window.__QUIZ_SUBJECT__=[{"id": "objective>Civic Education>2014>1", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "Who among the following could be described as the founding father of Nigerian nationalism?", "images": [], "options": {"A": "Nnamdi Azikwe", "B": "Herbert Macauley", "C": "Ahmadu Bello", "D": "Obafemi Awolowo"}, "answer": "B", "explanation": "Olayinka Herbert Samuel Macauley (14 November 1864 - 7 may 1946) was a Nigerian nationalist and musician and is considered by many Nigerians as the founder/father of Nigerian nationalism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>2", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW", "question": "Rule of law means", "images": [], "options": {"A": "Supremacy of the law", "B": "Absence of legal immunity", "C": "Peace, order and stability", "D": "Obedience to any authority"}, "answer": "A", "explanation": "Rule of law mean Supremacy of the law or constitution over and above everybody or citizens. It was propounded by A. V. Dicey in 1885.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>3", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : QUALITIES/CHARACTERISTICS OF CIVIL SOCIETY; I.E. ACCOUNTABILITY, FAIRNESS, JUSTICE, EQUITY ETC", "question": "A major characteristic of civil society is", "images": [], "options": {"A": "the desire to win election", "B": "corporate responsibility", "C": "social responsibility", "D": "political gerrymandering"}, "answer": "C", "explanation": "Social responsibility is an ethical framework and suggests that an entity, be it an organization or individual, has an obligation to act for the benefit of society at large.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>4", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Use the diagram below to answer this question      The marked pedestrian crossing shown in the diagram is", "images": ["Civic Education/imgs/2014/img1.png"], "options": {"A": "neon sign crossing", "B": "amber crossing", "C": "cobra crossing", "D": "zebra crossing"}, "answer": "D", "explanation": "The marked pedestrian crossing showing is zebra crossing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>5", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Use the diagram below to answer this question    In the above diagram, all vehicles stopped  mainly  because", "images": ["Civic Education/imgs/2014/img1.png"], "options": {"A": "it is emergency crossing line", "B": "the pedestrians have already stepped on the line", "C": "the traffic wardens have instructed them to stop", "D": "the traffic light has shown green"}, "answer": "B", "explanation": "Vehicle stopped mainly because the pedestrians have already stepped on the line as shown in the diagram.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>6", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "Citizenship status is acquired through", "images": [], "options": {"A": "birth, indigenization, colonization and referendum", "B": "association, convention, naturalization and incorporation", "C": "birth, naturalization, honorary and registration", "D": "registration, inter-relationship, integration and declaration"}, "answer": "C", "explanation": "Citizenship status can be acquired through several means, including birth, naturalization, honorary and registration. Birth refers to being born within a country's territory or to its citizens. Naturalization is the process by which a foreign citizen becomes a citizen of another country. Honorary citizenship is granted by a country to a foreign individual in recognition of their contributions or services. Registration can refer to the process of registering as a citizen, often applicable to those who have a claim to citizenship through descent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>7", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "Human Rights are basic natural rights which people enjoy primarily because they are", "images": [], "options": {"A": "members of a political party", "B": "international citizens", "C": "members of a community", "D": "human beings"}, "answer": "D", "explanation": "Human rights are basic natural right which people enjoy primarily because they are human beings. Human rights are rights exercised by human beings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>8", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS", "question": "Interpersonal relationship exists when", "images": [], "options": {"A": "citizens pay their taxes regularly to inland revenue service", "B": "citizens are politically conscious and participate in voting", "C": "there is interaction between persons in a social setting", "D": "group share social interest and communal aspiration"}, "answer": "C", "explanation": "Interpersonal relationship refers to a strong association among individuals working together in the same organization. Individuals working together are likely to develop interpersonal relationships. One of the most important interpersonal relationships is social interaction in a social setting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>9", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : MEANING AND ORIGIN OF CULTISM", "question": "Cultism can be described to be", "images": [], "options": {"A": "amiable", "B": "attractive", "C": "dangerous", "D": "harmless"}, "answer": "C", "explanation": "Cultism is a social vice that involves a group of people who share a common belief and are involved in secret practices. These practices are often harmful and dangerous to both members of the cult and non-members. Therefore, cultism can be described as dangerous.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>10", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Use the statements below to answer this question   NEWS:  'Rival cult Group Killed Ten on Campus'     STUDENT:  I will definitely need a bullet proof vest before I can go back to the Campus.    Based on the statement above, the decision of the student on having a bullet proof vest shows that cultism", "images": [], "options": {"A": "spreads fear and terror.", "B": "is a training ground for armed forces.", "C": "breed courageous graduates.", "D": "propagates self-defence."}, "answer": "A", "explanation": "The decision of the student on having a bullet proof vest shows that cultism spreads or create fear and terror on the campus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>11", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Use the statements below to answer this question   NEWS:  'Rival cult Group Killed Ten on Campus'     STUDENT:  I will definitely need a bullet proof vest before I can go back to the Campus.  It could be inferred from the statements above that cultism in schools could lead to", "images": [], "options": {"A": "sudden prosperity.", "B": "uninterrupted academic calender.", "C": "popularly on campus.", "D": "untimely death."}, "answer": "D", "explanation": "The statement 'Rival cult Group Killed Ten on Campus' implies that cultism in schools can lead to violence and death. The student's response further emphasizes the danger, as they feel they would need a bulletproof vest to return to campus. Therefore, the inference that can be drawn from these statements is that cultism in schools could lead to 'untimely death', which is option 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>12", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "Victims of human trafficking are usually compelled to engage in", "images": [], "options": {"A": "lucrative employment.", "B": "visiting tourist sites.", "C": "part-time studies.", "D": "forced labour."}, "answer": "D", "explanation": "Victims of human trafficking are usually compelled to engage in forced labour.  Human trafficking simply means the trade of humans for the purpose of forced labour, sexual slavery or commercial sexual exploitation for the trafficker or others.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>13", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "One habit which People Living With HIV/AIDS (PLWHAs) must avoid to remain healthy and productive is", "images": [], "options": {"A": "regular contact with healthy people", "B": "self-pity and self-medication", "C": "participation in profitable ventures", "D": "pursuit of academic studies"}, "answer": "B", "explanation": "People living with HIV/AIDS must avoid to remain healthy and productive, they should avoid self pity or self-medication.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>14", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "Youth empowerment is best described as the", "images": [], "options": {"A": "training given individuals for acquiring means of livelihood.", "B": "practice of engaging in prospective career.", "C": "provision of subsidized meals to the citizen by government.", "D": "mobilization of citizens for political rally."}, "answer": "A", "explanation": "Youth empowerment is described as the training given individuals for acquiring means of livelihood to earn a living.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>15", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "The National Assembly Presidency and Court which are inter-related and interdependent in our democracy constitute the", "images": [], "options": {"A": "tiers of government", "B": "types of democracy", "C": "forms of government", "D": "arms of government"}, "answer": "D", "explanation": "The National Assembly, Presidency, and Court are the three arms of government in a democratic system. The National Assembly (Legislature) makes the laws, the Presidency (Executive) implements the laws, and the Court (Judiciary) interprets the laws. They are inter-related and interdependent, each performing its functions to maintain checks and balances in the system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>16", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "A system of government that listens to public opinion and tolerates opposition is", "images": [], "options": {"A": "dictatorial regime", "B": "capitalist regime", "C": "democratic regime", "D": "socialist regime"}, "answer": "C", "explanation": "In democratic regime is a system of government that listens to the view or opinion of the people and tolerates opposition in the country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>17", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "A situation where most citizens fail to vote in elections coud be described as political", "images": [], "options": {"A": "socialization.", "B": "culture.", "C": "apathy.", "D": "legitimacy."}, "answer": "C", "explanation": "Political apathy is a situation where most citizens do not show interest in politics or fails to vote during the elections.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>18", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "The division of Nigeria into various constituencies with each electing a person to represent it in the National Assembly is a demonstration of", "images": [], "options": {"A": "checks and balances.", "B": "popular participation.", "C": "political rivalry among the constituents.", "D": "drive towards succession in the country."}, "answer": "B", "explanation": "The division of Nigeria into various constituencies with each electing a person to represent it in the National assembly is a demonstration of popular participation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>19", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : MEANING OF PUBLIC SERVICE", "question": "In Nigeria, public servants are expected to be", "images": [], "options": {"A": "non-partisan.", "B": "political.", "C": "ambitious.", "D": "apolitical."}, "answer": "A", "explanation": "In Nigeria, public servants are expected to be non-partisan. This means they should not show support for any political party or be involved in political activities. This is to ensure that they serve all citizens equally without any bias or favoritism. Being non-partisan is a key principle of public service, not just in Nigeria, but in many countries around the world.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>20", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "The principle that public servants cannot be held responsible for their official actions denotes", "images": [], "options": {"A": "impartiality", "B": "accountability", "C": "anonymity", "D": "neutrality"}, "answer": "C", "explanation": "Anonymity is a principle that states that public servants can not be held responsible for their official actions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>21", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)", "question": "Universal Declaration of Human Rights (UDHR) is based on the resolution of the", "images": [], "options": {"A": "Human Rights Watch", "B": "United Nations Organisation", "C": "Amnesty International", "D": "League of Nations"}, "answer": "B", "explanation": "Universal Declaration of Human Rights is based on the resolution of the United Nations Organisation (UNO).", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>22", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Use the story below to answer this question   Imoh lived with her parents in Kakuri. They were good citizens who detested all forms of immoral acts. Both at home and in school, Imoh had been taught the virtues and values of a good citizen. However, while in a bus on her way home from school, the conductor forgot to ask her fare. She knew that the right thing to do was to pay even when the conductor had forgotten to collect the fare. She also knew that there were other things she could do with the money if it was not paid, but she did what was expected by informing the conductor and paying the fare.    According to the story, Imoh's parents were", "images": [], "options": {"A": "wealthy couple.", "B": "prominent politicians.", "C": "honest and responsible.", "D": "religious fanatics."}, "answer": "C", "explanation": "From the story, it is clear that Imoh's parents have instilled in her the values of honesty and responsibility. They are described as good citizens who detest all forms of immoral acts. This suggests that they are honest and responsible individuals, not necessarily wealthy, prominent politicians, or religious fanatics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>23", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "Use the story below to answer this question   Imoh lived with her parents in Kakuri. They were good citizens who detested all forms of immoral acts. Both at home and in school, Imoh had been taught the virtues and values of a good citizen. However, while in a bus on her way home from school, the conductor forgot to ask her fare. She knew that the right thing to do was to pay even when the conductor had forgotten to collect the fare. She also knew that there were other things she could do with the money if it was not paid, but she did what was expected by informing the conductor and paying the fare.  What value did Imoh demonstrate?", "images": [], "options": {"A": "Tolerance.", "B": "Confidence.", "C": "Fair play.", "D": "Honesty."}, "answer": "D", "explanation": "Imoh demonstrated honesty. Honesty is a virtue that involves being truthful and sincere. In the story, Imoh was honest by informing the conductor about the unpaid fare and paying it, even though the conductor had forgotten to collect it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>24", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS", "question": "Conflicts are better resolved in the society through", "images": [], "options": {"A": "tribunal.", "B": "litigation.", "C": "dialogue.", "D": "the court."}, "answer": "C", "explanation": "Conflicts are better resolved in the society through dialogue. Dialogue is a method of conflict resolution that involves open, honest, and respectful communication between parties involved in a conflict. It allows for understanding, compromise, and peaceful resolution of conflicts. While tribunal, litigation, and court are also methods of conflict resolution, they are often more adversarial and may not lead to the best resolution for all parties involved.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>25", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "To prevent the spread of HIV/AIDS, people should be encouraged to", "images": [], "options": {"A": "avoid casual sexual activities.", "B": "marry very early in life.", "C": "engage in gainful employment.", "D": "pursue high education."}, "answer": "A", "explanation": "HIV/AIDS is primarily spread through unprotected sexual intercourse with an infected person. Therefore, avoiding casual sexual activities can significantly reduce the risk of contracting or spreading the virus. This does not necessarily mean that people should marry early in life, engage in gainful employment, or pursue higher education. These options may have other benefits, but they do not directly prevent the spread of HIV/AIDS.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>26", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "The nearest government to the people and an important means of promoting grassroots development is the", "images": [], "options": {"A": "state government", "B": "unitary government", "C": "local government", "D": "federal government"}, "answer": "C", "explanation": "Local government is the nearest government that is close to the grass root people and promote government at grass root.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>27", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "Democratic governance is usually characterized by", "images": [], "options": {"A": "free, fair and credible elections.", "B": "buoyant and competitive economy.", "C": "accessible employment opportunities.", "D": "youth participation in governance."}, "answer": "A", "explanation": "Democratic governance is characterized by free, fair, and credible elections. This is because democracy is a system of government where citizens exercise power by voting. In a democratic system, the citizens have the right to vote in order to choose their representatives in the government. The process of voting should be free, fair, and credible to ensure that the will of the people is accurately represented.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>28", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "Political apathy often leads to", "images": [], "options": {"A": "low level of participation.", "B": "good governance.", "C": "political stability.", "D": "low literacy level."}, "answer": "A", "explanation": "Political apathy is when the citizens of a country are not interested or involved in politics and this lead to low level of participation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>29", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : WAYS OF IMPROVING THE PUBLIC SERVICE", "question": "Which of the following is not necessary for public servants to perform effectively?", "images": [], "options": {"A": "Acceptance of foreign aid by the government.", "B": "Improvement in literacy level of the citizens.", "C": "Declaration of state of emergency by government.", "D": "Periodic review of the constitution by government."}, "answer": "A", "explanation": "The effectiveness of public servants is not directly influenced by the acceptance of foreign aid by the government. Public servants' performance is more related to their skills, training, resources, and the institutional framework within which they operate. Acceptance of foreign aid by the government is a policy decision that may indirectly affect public service by providing additional resources or imposing certain conditions, but it is not a necessary condition for public servants to perform effectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>30", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS", "question": "One of the conditions which can limit the enjoyment of Human Rights in Nigeria is the", "images": [], "options": {"A": "acceptance of foreign aid by the government.", "B": "improvement in literacy level of the citizens.", "C": "declaration of state of emergency by government.", "D": "periodic review of the constitution by government."}, "answer": "C", "explanation": "The declaration of a state of emergency by the government can limit the enjoyment of human rights. During a state of emergency, certain civil liberties can be suspended, such as freedom of assembly, freedom of movement, and the right to a fair trial. This is done to maintain order and security during a crisis. Therefore, the declaration of a state of emergency is a condition that can limit the enjoyment of human rights in Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>31", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS~~NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "The drunkard as depicted in the picture will not likely perform his parental role because", "images": ["Civic Education/imgs/2014/img2.png"], "options": {"A": "his action constitutes bad influence.", "B": "rehabilitation facilities are not available.", "C": "drinking problem is associated with the poor.", "D": "he has a large family to cater for."}, "answer": "A", "explanation": "The drunkard as depicted in the picture will not likely perform his parental role because his action constitutes bad influence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>32", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "The above picture portrays drunkenness mainly as", "images": ["Civic Education/imgs/2014/img2.png"], "options": {"A": "an individual habit in the society.", "B": "a potential health hazard.", "C": "a challenge to responsible parenting.", "D": "an environmental nuisance."}, "answer": "D", "explanation": "The picture portrays drunkenness mainly as an environmental nuisance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>33", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS", "question": "The implication of positive communal relationships is that it", "images": [], "options": {"A": "promotes solidarity and love.", "B": "ensures obedience to constituted authority.", "C": "encourages ethnic diversity.", "D": "promotes rural-urban drift."}, "answer": "A", "explanation": "Positive communal relationships promotes solidarity and love. It also promote diplomatic relationships among the people.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2014>34", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING", "question": "One major factor that attracts some Nigerians into human trafficking is", "images": [], "options": {"A": "over-population related issues.", "B": "influx of foreigners into the country.", "C": "insatiable quest for quick wealth.", "D": "influence of Western and social media."}, "answer": "C", "explanation": "The major factor that attracts some Nigerians into human trafficking is insatiable quest for quick wealth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>35", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "One of the reasons most HIV/AIDS patients are reluctant to disclose their status is because of", "images": [], "options": {"A": "the incurable nature of the ailment.", "B": "fear of social stigmatization.", "C": "lack of sufficient public awareness.", "D": "shortage of health counselors."}, "answer": "B", "explanation": "Fear of social stigmatization is one of the reasons most HIV/AIDS patients are reluctant to disclose their status.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>36", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW", "question": "Use the report below to answer this question.   The Bawali High Court has ordered the police in Area Z Command to produce Mr. Zeb, who is in police custody for an alleged offence. The court insists that Mr. Zeb cannot be punished until he is found guilty of breach of any law of the land by a court of competent jurisdiction.    The position of the court on this matter justifies the essence of the", "images": [], "options": {"A": "rule of law.", "B": "legislature.", "C": "police command.", "D": "separation of powers."}, "answer": "A", "explanation": "The position of the Court on this matter justifies the essence of the rule of law. A person or an accused person is presume innocent until it is found guilty by the court of law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>37", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : HOW LEADERS CAN PROTECT THE INTERESTS OF THEIR FOLLOWERS", "question": "Leaders can best protect the interest of their followers by", "images": [], "options": {"A": "embarking on periodic constitutional review.", "B": "creating socio-economic opportunities for foreigners.", "C": "creating conducive atmosphere for participation.", "D": "rewarding supports with contracts."}, "answer": "C", "explanation": "Creating Conducive atmosphere for participation is one of the way a leader can protect the interest of their followers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>38", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "The most popular means through which citizens of a country can participate in politics is by", "images": [], "options": {"A": "being members of political parties.", "B": "engaging in constructive criticisms.", "C": "engaging in political debates.", "D": "voting in elections."}, "answer": "D", "explanation": "Voting in elections is one of the ways a citizen of a country participate in politics. Citizens participate in politics by exercising his franchise right.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>39", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "Civil societies are vital for the promotion of popular participation because they are", "images": [], "options": {"A": "profit-oriented organizations.", "B": "engaged in developmental programmes.", "C": "involved in political education.", "D": "formidable oppositions to government."}, "answer": "C", "explanation": "Civil societies are non-profit organizations that are involved in promoting political education among the citizens. They are not profit-oriented organizations, they are not necessarily engaged in developmental programmes, and they are not formidable oppositions to government. They are involved in political education because they help to educate the citizens about their rights, responsibilities, and the workings of the government. This helps to promote popular participation in the political process as more informed citizens are more likely to participate actively in the political process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>40", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.    From this dialogue, it is very likely that Wanja will be exhibiting the following characters except", "images": [], "options": {"A": "disobedience to constituted authority.", "B": "truancy and perpetual lateness to school.", "C": "hospitable attitude towards people.", "D": "arrogance and unruly behavior."}, "answer": "C", "explanation": "From this dialogue, it is very likely that Wanja will not exhibit the character of hospitable attitude towards people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>41", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  Which of the following may result from Wanja's habit?", "images": [], "options": {"A": "Humility for elders.", "B": "Criminality in the society.", "C": "Advocacy for hard drugs by NGOs.", "D": "Excellent performance in school."}, "answer": "B", "explanation": "Criminality in the society may result from Wanja's habit smoking and alcohols result in bad friends and this lead to criminality in the society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>42", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : SYMPTOMS OF DRUG ABUSE", "question": "Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  From Ada's admonition, it could be deduced that taking hard drugs could", "images": [], "options": {"A": "make people respect the addicts.", "B": "lead to insanity of the addicts.", "C": "make people to adore the drug addicts.", "D": "ensure courteous behavior by the addicts."}, "answer": "B", "explanation": "From Ada's admonition, it could be deduced that taking hard drugs could lead to insanity of the addicts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>43", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE", "question": "Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  From the above dialogue, Wanja's behavior could be curtailed by", "images": [], "options": {"A": "Sending him abroad for further studies.", "B": "Financial inducement.", "C": "Re-orientation and rehabilitation.", "D": "Indulging him with expensive gifts."}, "answer": "C", "explanation": "From the dialogue, Wanja is involved in substance abuse and this behavior can be curtailed through re-orientation and rehabilitation. Re-orientation involves changing his perspective about substance abuse and its effects, while rehabilitation involves helping him overcome his addiction. Sending him abroad for further studies or indulging him with expensive gifts may not necessarily change his behavior. Financial inducement may even worsen the situation as he may use the money to buy more drugs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>44", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  Which of the following governmental agencies is the most capable of controlling the activities of Wanja and his group?", "images": [], "options": {"A": "National Agency for Food and Drug Administration and Control (NAFDAC)", "B": "National Orientation Agency (NOA)", "C": "National Emergency Management Agency (NEMA)", "D": "National Drug Law Enforcement Agency (NDLEA)"}, "answer": "D", "explanation": "National Drug Law Enforcement Agency (NDLEA) is governmental agencies that is capable of controlling the activities of Wanja and his group. NDLEA are charge with the responsibility of orientate the drug addicts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>45", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  One of the major barriers to national development is the", "images": [], "options": {"A": "low poverty level.", "B": "existence of multi-party system.", "C": "prevalence of corrupt practices.", "D": "persistent rural-urban migration."}, "answer": "C", "explanation": "The dialogue suggests that drug and alcohol abuse, which can be seen as a form of social corruption, is a major barrier to national development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>46", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  The quotation above shows that the speaker is concerned about", "images": [], "options": {"A": "nationalism.", "B": "revolution.", "C": "tourism.", "D": "welfarism."}, "answer": "D", "explanation": "The dialogue shows that Ada is concerned about Wanja's welfare, which is why she warns him about the dangers of drug and alcohol abuse and advises him to lead a good life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>47", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS", "question": "A major benefit of youth empowerment is", "images": [], "options": {"A": "dependence on foreign aid.", "B": "discouragement of patriotism.", "C": "reduction in crime rate.", "D": "negation to national prosperity."}, "answer": "C", "explanation": "Reduction in crime rate is a major benefit of Youth empowerment. It is believed that when youths are engaged the crime rate reduced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>48", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC", "question": "Use the story below to answer this question.   Chief Bilisi was prominent politician and honourable minister in Kantogo Republic. He had sponsored several candidates to power and made them to swear oath of aliegiance to him. In return, they awarded contracts and offered financial and material assistance to him at the expense of the public. This had resulted in the non-provision of social amenities. These were some of the grieviances the community had against him for which a mob gathered in front of his house shouting and hauling abusive words at him. They did not stop at that as they vandalized property and obstructed vehicular movement.    When leaders like Chief Bilisi place self interest above public goods, the result is that", "images": [], "options": {"A": "rebellion becomes inevitable.", "B": "cooperation of citizens is guaranteed.", "C": "international support for the regime is ensured.", "D": ".society becomes more peaceful and orderly."}, "answer": "A", "explanation": "When leaders like Chief Bilisi place self interest above public goods, the result is that rebellion becomes inevitable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>49", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER", "question": "Use the story below to answer this question.   Chief Bilisi was prominent politician and honourable minister in Kantogo Republic. He had sponsored several candidates to power and made them to swear oath of aliegiance to him. In return, they awarded contracts and offered financial and material assistance to him at the expense of the public. This had resulted in the non-provision of social amenities. These were some of the grieviances the community had against him for which a mob gathered in front of his house shouting and hauling abusive words at him. They did not stop at that as they vandalized property and obstructed vehicular movement.  The condition of disorderly behaviour exhibited by the mob in the story best describes the", "images": [], "options": {"A": "ineffectiveness of the police.", "B": "breakdown of law and order.", "C": "importance of ministerial position.", "D": "need for stiffer security measures."}, "answer": "B", "explanation": "The condition of disorderly behaviour exhibited by the mob in the story best describes the breakdown of law and order in the society or country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2014>50", "subject": "Civic Education", "year": "2014", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Use the story below to answer this question.   Chief Bilisi was prominent politician and honourable minister in Kantogo Republic. He had sponsored several candidates to power and made them to swear oath of aliegiance to him. In return, they awarded contracts and offered financial and material assistance to him at the expense of the public. This had resulted in the non-provision of social amenities. These were some of the grieviances the community had against him for which a mob gathered in front of his house shouting and hauling abusive words at him. They did not stop at that as they vandalized property and obstructed vehicular movement.  A major lesson Nigerians could learn from the story is that", "images": [], "options": {"A": "leaders can empower voters by giving them money.", "B": "security officials should use brutal force on citizens.", "C": "the underprivileged should not vie for elective positions.", "D": "greed and related vices can cause serious breach of the law."}, "answer": "D", "explanation": "A major lesson Nigerians could learn from the story is that greed and related vices can cause serious breach of the law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>1", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "From the above diagram, which major condition may have encouraged candidtates to engage in examination malpractice?", "images": ["Civic Education/imgs/2015/img1.png"], "options": {"A": "Public perception that it is normal to cheat", "B": "Inadequate preparation for the examination", "C": "The supervisors are negligent", "D": "School authorities encourage cheating"}, "answer": "B", "explanation": "Inadequate preparation for the examination is a major condition that may have encouraged candidates to engage in examination malpractice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>2", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Which of the following statements may be true about the behaviour of the candidates in the diagram?", "images": ["Civic Education/imgs/2015/img1.png"], "options": {"A": "The candidates are doing what is ethical", "B": "Candidates involved in malpractice should be banned for life", "C": "Their action can also affect innocent candidates", "D": "Their misconduct will guarantee a reliable certificate"}, "answer": "C", "explanation": "Their action can also affect innocent candidates. This is because innocent students may be caught between.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>3", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Based on the above diagram, the candidates would not have cheated if", "images": ["Civic Education/imgs/2015/img1.png"], "options": {"A": "They were well-spaced", "B": "There was an invigilator", "C": "They were hard working", "D": "There was no body to copy from"}, "answer": "C", "explanation": "The candidate would not have cheated if they were hardworking.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>4", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)", "question": "In which year did the United Nations General Assembly adopt the Universal Declaration of Human Rights?", "images": [], "options": {"A": "1945", "B": "1946", "C": "1947", "D": "1948"}, "answer": "D", "explanation": "The Universal Declaration of Human Rights was adopted by the United Nations General Assembly on December 10, 1948. This declaration is a milestone document in the history of human rights that sets out, for the first time, fundamental human rights to be universally protected.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>5", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Use the picture below to answer this question      The road signs in the picture above indicate", "images": ["Civic Education/imgs/2015/traffic.png"], "options": {"A": "Two ways traffic ahead", "B": "Dualised carrage way ahead", "C": "Two junctions ahead", "D": "Two exit routa ahead"}, "answer": "A", "explanation": "It indicates a two way traffic ahead. This is the most appropriate answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>6", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Two forms of road signs are regulatory and", "images": [], "options": {"A": "punitive", "B": "informative", "C": "persuasive", "D": "inhibitive"}, "answer": "B", "explanation": "Road signs are typically divided into several categories. Regulatory signs are one of them, which are designed to instruct road users on what they must or should do (or not do) under a given set of circumstances. The other type mentioned in the question is informative signs. These signs give information about destinations, distances, alternative routes, points of interest, or other geographical, historical, or cultural information.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>7", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS", "question": "Which of the following factors does not affect interpersonal relationship?", "images": [], "options": {"A": "Communication", "B": "Withdrawal", "C": "Compatibility", "D": "Forgiveness"}, "answer": "C", "explanation": "Interpersonal relationships are social associations, connections, or affiliations between two or more people. They vary in differing levels of intimacy and sharing, implying the discovery or establishment of common ground, and may be centered around something shared in common. The factors that affect interpersonal relationships include communication, withdrawal, and forgiveness. However, compatibility does not affect interpersonal relationships as it is a state, not a factor. It is the ability of two or more things to exist or work together without conflict.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>8", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : REASONS FOR CULTISM", "question": "The following cadre of students are the main target for campus cult membership except", "images": [], "options": {"A": "students from wealth homes", "B": "students from influential parents", "C": "bold and morally sound students", "D": "wayward and fun-loving students"}, "answer": "C", "explanation": "Campus cults often target students who are easily influenced or who seek a sense of belonging, which can often be found in students from wealthy homes, students from influential parents, and wayward and fun-loving students. However, bold and morally sound students are less likely to be targeted for campus cult membership because they are more likely to resist the pressure and manipulation tactics used by cults. They have a strong moral compass and are not easily swayed by peer pressure or the promise of power or popularity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>9", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "The National Agency for Food and Drug Administration and Control (NAFDAC) was established in", "images": [], "options": {"A": "1993", "B": "1996", "C": "1999", "D": "2001"}, "answer": "A", "explanation": "The National Agency for Food and Drug Administration and Control (NAFDAC) was established in 1993. NAFDAC is a Nigerian federal agency under the Federal Ministry of Health that is responsible for regulating and controlling the manufacture, importation, exportation, advertisement, distribution, sale and use of food, drugs, cosmetics, medical devices, chemicals and packaged water. Its goal is to ensure the health and safety of the Nigerian public.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>10", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "National Agency for the Prohibition of Traffic in Persons (NAPTIP) is an initiative of", "images": [], "options": {"A": "Federal Government of Nigeria", "B": "United States Agency for International Development", "C": "Women Trafficking and Child Labour Eradication Foundation", "D": "United States Office on Drugs and Crime"}, "answer": "A", "explanation": "The National Agency for the Prohibition of Traffic in Persons (NAPTIP) is an initiative of the Federal Government of Nigeria. It was established in 2003 in response to the high rate of human trafficking in the country. The agency is tasked with enforcing the law that prohibits trafficking in persons, coordinating and supervising all functions of other agencies and bodies in relation to traffic in persons, and adopting measures aimed at the elimination of traffic in persons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>11", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : MEANING OF HIV/AIDS", "question": "World AIDS day is observed on", "images": [], "options": {"A": "20th May", "B": "30th July", "C": "27th August", "D": "1st December"}, "answer": "D", "explanation": "World AIDS Day is observed on 1st December every year. It is dedicated to raising awareness of the AIDS pandemic caused by the spread of HIV infection and mourning those who have died of the disease.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>12", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "An enabling environment created to help an individual have effective control of his/her situation is known as", "images": [], "options": {"A": "reinforcement", "B": "empowerment", "C": "endownment", "D": "enhancement"}, "answer": "B", "explanation": "Empowerment refers to the process of becoming stronger and more confident, especially in controlling one's life and claiming one's rights. An enabling environment created to help an individual have effective control of his/her situation is known as empowerment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>13", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "In order to avoid undue interference in the process of governance, there should be", "images": [], "options": {"A": "clear cut separation of governmental powers.", "B": "proper fusion of governmental powers and functions.", "C": "more roles for traditional rulers in the governmental process.", "D": "additional responsibility for local government council."}, "answer": "A", "explanation": "The principle of separation of powers is a doctrine of constitutional law under which the three branches of government (executive, legislative, and judicial) are kept separate. This is to prevent abuse of power and to safeguard freedom for all. This principle is clearly stated in many democratic constitutions including the United States Constitution and the Constitution of the Federal Republic of Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>14", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "Red-tapism is one of the shortcomings of", "images": [], "options": {"A": "private enterprise", "B": "public service", "C": "non-governmental organization", "D": "pressure groups"}, "answer": "B", "explanation": "Red-tapism refers to excessive regulation or rigid conformity to formal rules that is considered redundant or bureaucratic and hinders or prevents action or decision-making. It is usually applied to governments, corporations, and other large organizations. Therefore, it is a shortcoming of the public service, not private enterprises, non-governmental organizations, or pressure groups.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>15", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM", "question": "An ideology that aims at promoting national consciousness and identity is", "images": [], "options": {"A": "nationalism", "B": "socialization", "C": "civic culture", "D": "progressivism"}, "answer": "A", "explanation": "Nationalism is an ideology that promotes national consciousness and identity. It emphasizes the interests of a particular nation (as in a group of people) especially with the aim of gaining and maintaining the nation's sovereignty (self-governance) over its homeland. Nationalism holds that each nation should govern itself, free from outside interference (self-determination), that a nation is a natural and ideal basis for a polity, and that the nation is the only rightful source of political power (popular sovereignty).", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>16", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CHARACTERISTICS OF HUMAN RIGHTS", "question": "Human rights are described as inviolable mainly because they are", "images": [], "options": {"A": "authoritative declaration", "B": "enforcable everywhere", "C": "not to be unnecessarily taken away", "D": "legal declaration instruments"}, "answer": "C", "explanation": "Human rights are described as inviolable mainly because they are not to be unnecessarily taken away. Human rights are the basic rights and freedoms to which all individuals are entitled, regardless of nationality, sex, national or ethnic origin, race, religion, language, or other status. These rights include the right to life and liberty, freedom from slavery and torture, freedom of opinion and expression, the right to work and education, and many more. They are protected and upheld by international and national laws and treaties.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>17", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Law and order can best be maintained in Nigeria through the", "images": [], "options": {"A": "prohibition of public protest", "B": "enforcement of rules and regulations", "C": "use of divide and rule policy", "D": "promotion of indigenization policy"}, "answer": "B", "explanation": "Law and order can best be maintained in any society through the enforcement of rules and regulations. This is because rules and regulations provide a guideline for acceptable behavior and actions in a society. When these rules and regulations are enforced, it ensures that individuals adhere to them, thereby maintaining law and order. Prohibition of public protest, use of divide and rule policy, and promotion of indigenization policy are not direct methods of maintaining law and order.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>18", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "A responsible parent is one who", "images": [], "options": {"A": "cares and provides for the children", "B": "indulges the children because of love", "C": "works in order to receive salary", "D": "employs house-helps to take care of the children"}, "answer": "A", "explanation": "A responsible parent is one who cares and provides for the children. This involves providing for their basic needs such as food, shelter, clothing, education, and also emotional needs like love, care, and support. Indulging children because of love can lead to spoiling them and is not a sign of responsible parenting. Working in order to receive salary is a general responsibility of every working adult, not specifically a parent. Employing house-helps to take care of the children does not necessarily mean the parent is responsible, as the primary care and responsibility still lies with the parent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>19", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "A major way of promoting responsible parenthood is through", "images": [], "options": {"A": "sex education", "B": "sound education", "C": "population control measures", "D": "tax reduction measures"}, "answer": "A", "explanation": "Responsible parenthood can be promoted through sex education. This is because sex education provides knowledge about sexual health, reproduction, and contraceptive methods. It also teaches about the responsibilities and consequences of sexual behavior, thereby promoting responsible parenthood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>20", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : TYPES OF INTERPERSONAL RELATIONSHIPS", "question": "Which of the following is not included in the stages of interpersonal relationships?", "images": [], "options": {"A": "Rejuvenation", "B": "Deterioration", "C": "Termination", "D": "Continuation"}, "answer": "A", "explanation": "The stages of interpersonal relationships typically include initiation, experimentation, intensifying, integration, bonding, and then either deterioration, termination, or continuation. Rejuvenation is not typically included as a stage in this process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>21", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : MEANING AND ORIGIN OF CULTISM", "question": "Cultism in tertiary institution in Nigeria was originally introduced to", "images": [], "options": {"A": "perpetuate the use of local gin and alcohol", "B": "harass opponents of university administrators", "C": "fight colonialism and oppressive rules", "D": "promote inter-communal marriages"}, "answer": "C", "explanation": "Cultism in tertiary institutions in Nigeria was originally introduced to fight colonialism and oppressive rules. The first known cult group, the Pyrates Confraternity (also known as National Association of Sea Dogs), was formed in the University of Ibadan in 1952 by Nobel laureate Wole Soyinka and his friends. It was formed to advocate for the rights of the students and fight against the oppressive rules of the colonial masters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>22", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "Which of the following is not a function of the National Drug Law Enforcement Agency (NDLEA)?", "images": [], "options": {"A": "Applying and implementing all drug laws", "B": "Arresting, investigating and prosecuting drug traffickers", "C": "Undertaking the registration of companies dealing in drugs", "D": "Carrying out enlightenment campaigns on drug trafficking"}, "answer": "C", "explanation": "The National Drug Law Enforcement Agency (NDLEA) is a Federal agency in Nigeria charged with eliminating the growing, processing, manufacturing, selling, exporting, and trafficking of hard drugs. The agency does not undertake the registration of companies dealing in drugs. This is typically the responsibility of the National Agency for Food and Drug Administration and Control (NAFDAC).", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>23", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "An individual who finds it difficult to control in-take of drug is known as drug", "images": [], "options": {"A": "baron", "B": "trafficker", "C": "mogul", "D": "addict"}, "answer": "D", "explanation": "An individual who finds it difficult to control in-take of drug is known as a drug addict. A drug addict is a person who is unable to stop using a drug, despite the negative effects it has on their life. This is different from a drug baron, trafficker, or mogul, who are involved in the production, distribution, or sale of drugs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>24", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "The NDLEA personnel are not usually found in", "images": [], "options": {"A": "international airports", "B": "seaports", "C": "border crossings", "D": "foreign embassies"}, "answer": "D", "explanation": "The NDLEA (National Drug Law Enforcement Agency) personnel are not usually found in foreign embassies. The NDLEA is a Nigerian federal agency tasked with preventing the production, importation, possession, distribution and use of drugs. They are typically found in places where drug trafficking is likely to occur, such as international airports, seaports, and border crossings. However, they do not typically operate in foreign embassies, as these are considered the sovereign territory of the foreign country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>25", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "Which of the following statements best describes Human Trafficking?", "images": [], "options": {"A": "Recruitment of youths as casual workers", "B": "Desperate desire by youths to travel abroad", "C": "Buying and selling of humans for selfish purposes", "D": "Transportation of goods and services through human portage"}, "answer": "C", "explanation": "Human trafficking is a crime that involves the exploitation of a person through force, fraud, or coercion. This exploitation often involves forced labor, sexual exploitation, or other forms of abuse. Therefore, the option 'Buying and selling of humans for selfish purposes' best describes human trafficking. The other options do not accurately describe the nature of human trafficking.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>26", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "Use the write-up below to answer this question   One major trend in Kantoga Republi today, especially during elections, is the engagement of youths by some politicians for political thuggery, rigging, stuffing of ballot boxes and other related electoral offences. Most of the youths who are engaged in these crimes have no means of livelihood or are school drop-outs. These youths are Kantoguans who ought to benefit from the enormous wealth and resources of the nation. Unfortunately, this is not the case at the moment. Indeed, it is the duty of government, especially at the centre, to provide entrepreneurial skill acquisition programme and start-up funds for small scale businesses to empower the youths. This will reduce the chances of engaging youth in wrong purposes.    From the above write-up, what category of Kantoguan youths deserves to be effectively empowered?", "images": [], "options": {"A": "Children of the ruling political class", "B": "Unemployed youths and school drop-outs", "C": "University undergraduates", "D": "Youths wing of religious organisations"}, "answer": "B", "explanation": "From the write-up, it is clear that the category of Kantoguan youths that deserves to be effectively empowered are the 'Unemployed youths and school drop-outs'. These are the youths who are being engaged in crimes such as political thuggery, rigging, stuffing of ballot boxes and other related electoral offences because they have no means of livelihood. Empowering them through entrepreneurial skill acquisition programs and start-up funds for small scale businesses would reduce their chances of being engaged in such activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>27", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "Use the write-up below to answer this question   One major trend in Kantoga Republi today, especially during elections, is the engagement of youths by some politicians for political thuggery, rigging, stuffing of ballot boxes and other related electoral offences. Most of the youths who are engaged in these crimes have no means of livelihood or are school drop-outs. These youths are Kantoguans who ought to benefit from the enormous wealth and resources of the nation. Unfortunately, this is not the case at the moment. Indeed, it is the duty of government, especially at the centre, to provide entrepreneurial skill acquisition programme and start-up funds for small scale businesses to empower the youths. This will reduce the chances of engaging youth in wrong purposes.  The responsibility of empowering the youths rests mostly with", "images": [], "options": {"A": "the political class", "B": "religious organisations", "C": "university administrators", "D": "national government"}, "answer": "D", "explanation": "From the passage, it is clear that the responsibility of empowering the youths rests mostly with the national government. The passage mentions that it is the duty of the government, especially at the centre, to provide entrepreneurial skill acquisition programme and start-up funds for small scale businesses to empower the youths. This implies that the national government has the primary responsibility to empower the youths.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>28", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "Use the write-up below to answer this question   One major trend in Kantoga Republi today, especially during elections, is the engagement of youths by some politicians for political thuggery, rigging, stuffing of ballot boxes and other related electoral offences. Most of the youths who are engaged in these crimes have no means of livelihood or are school drop-outs. These youths are Kantoguans who ought to benefit from the enormous wealth and resources of the nation. Unfortunately, this is not the case at the moment. Indeed, it is the duty of government, especially at the centre, to provide entrepreneurial skill acquisition programme and start-up funds for small scale businesses to empower the youths. This will reduce the chances of engaging youth in wrong purposes.  Based on the write-up, what immediate measures can those in authority take to empower the youths?", "images": [], "options": {"A": "Build more youth orientation camps in the country", "B": "Enhance religious and moral education in schools and colleges", "C": "Provide entrepreneurial training with adequate fund", "D": "Provide free meal for the teeming unemployed youths"}, "answer": "C", "explanation": "The passage suggests that the immediate measures those in authority can take to empower the youths include providing entrepreneurial skill acquisition programme and start-up funds for small scale businesses. This aligns with option 3, which suggests providing entrepreneurial training with adequate fund. The other options do not directly address the issue of empowering the youths as suggested in the passage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>29", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "A very important segment of the society which is distinct from government, business and home is the", "images": [], "options": {"A": "civil society", "B": "public service", "C": "mass media", "D": "traditional institution"}, "answer": "A", "explanation": "The civil society is a very important segment of the society which is distinct from government, business and home. Civil society includes non-governmental organizations and institutions that manifest interests and will of citizens. They include organizations such as community groups, non-profit organizations, and independent foundations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>30", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : MEANING OF HIV/AIDS", "question": "HIV/AIDS is generally described as terminal in nature because it is", "images": [], "options": {"A": "preventable", "B": "transmittable", "C": "avertable", "D": "incurable"}, "answer": "D", "explanation": "HIV/AIDS is generally described as terminal in nature because it is incurable. While there are treatments that can slow the course of the disease, there is currently no known cure for HIV/AIDS. This makes the disease terminal, as it eventually leads to death.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>31", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL RELATIONSHIPS", "question": "Inter-communal relationship is best described as", "images": [], "options": {"A": "the interaction between individuals, groups or organisation with common aspirations.", "B": "the interaction among individuals and professionals in a society.", "C": "loyalty to community leaders so as to achieve rapid communal development.", "D": "respect for collective national symbols in order to foster nationalistic feeling."}, "answer": "A", "explanation": "Inter-communal relationship refers to the interaction between different communities. This interaction can be between individuals, groups, or organizations that share common aspirations. It involves mutual understanding, cooperation, and respect among different communities. Therefore, the first option is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>32", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : QUALITIES/CHARACTERISTICS OF CIVIL SOCIETY; I.E. ACCOUNTABILITY, FAIRNESS, JUSTICE, EQUITY ETC", "question": "A situation whereby someone is obliged to inform a superior about his actions and decisions for the purpose of control is", "images": [], "options": {"A": "probity", "B": "self-discipline", "C": "accountability", "D": "fair play"}, "answer": "C", "explanation": "The situation described in the question is known as accountability. Accountability is a concept in ethics and governance with several meanings. It is often used synonymously with such concepts as responsibility, answerability, blameworthiness, liability, and other terms associated with the expectation of account-giving. In governance, accountability is the acknowledgment and assumption of responsibility for actions, decisions, and policies including the administration, governance, and implementation within the scope of the role or employment position and encompassing the obligation to report, explain and be answerable for resulting consequences.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>33", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "\"All human beings are born free and equal in dignity and rights. They are endowed with reason and conscience and should act towards one another in a spirit of brotherhood\".   The above quotation summarizes the", "images": [], "options": {"A": "Universal Declaration of Human Rights.", "B": "African charter on Human Rights.", "C": "Geneva Conventions and protocols.", "D": "United Nations Organization Charter."}, "answer": "A", "explanation": "The quote is from the Universal Declaration of Human Rights. The Universal Declaration of Human Rights (UDHR) is a historic document that was adopted by the United Nations General Assembly at its third session on 10 December 1948 as Resolution 217 at the Palais de Chaillot in Paris, France. It consists of 30 articles which have been elaborated in subsequent international treaties, regional human rights instruments, national constitutions, and other laws. The quote is the first article of the UDHR.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>34", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD", "question": "Effective and responsible parenthood is primarily", "images": [], "options": {"A": "a national duty", "B": "a military duty", "C": "a political duty", "D": "an economic duty"}, "answer": "A", "explanation": "None of the options is correct. Effective and responsible parenthood is primarily a personal duty. It is the responsibility of parents to provide for the physical, emotional, and social well-being of their children. This includes providing food, shelter, clothing, education, and healthcare, as well as nurturing, guidance, and love. While the state and society have roles to play in supporting parents, the primary responsibility lies with the parents themselves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>35", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTERPERSONAL RELATIONSHIPS", "question": "Association and affiliation between two or more people is called", "images": [], "options": {"A": "multilateral relations", "B": "bilateral relations", "C": "inter-communal relations", "D": "inter-personal relations"}, "answer": "D", "explanation": "The term 'inter-personal relations' refers to the social association, connection, or affiliation between two or more people. It varies in differing levels of intimacy and sharing, involving the discovery or establishment of common ground, and may be centered around something shared in common. The other options do not accurately describe the association and affiliation between two or more people.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>36", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "A bill passed by the National Assembly requires the assent of the president before it becomes law. The law can be declared null and void by the court of law. The process above emphasizes the", "images": [], "options": {"A": "supremacy of judiciary over other arms of government", "B": "relationship among the arms of government", "C": "importance of law makers in a democracy", "D": "fundamentals of the rule of law"}, "answer": "B", "explanation": "The process described in the question emphasizes the relationship among the arms of government. In a democratic system, the three arms of government (the Executive, Legislature, and Judiciary) work together to make, implement, and interpret laws. The process of a bill becoming law involves the Legislature (National Assembly) passing the bill, the Executive (President) assenting to the bill, and the Judiciary (Court of Law) having the power to declare the law null and void if it contravenes the constitution. This shows the relationship and interdependence among the three arms of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>37", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW", "question": "The idea that \"Law should be impartial with the people who break it\" implies", "images": [], "options": {"A": "principle of fair hearing", "B": "right to legal representation", "C": "equality before the law", "D": "prerogative writ of habeas corpus"}, "answer": "C", "explanation": "The statement 'Law should be impartial with the people who break it' implies that everyone is equal before the law. This is a fundamental principle in legal systems where each person is subject to the law and no one is above it. It ensures that everyone is treated equally irrespective of their social status, wealth, or power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>38", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF NATIONAL DEVELOPMENT", "question": "The foreign policy objectives of Nigeria as enshrined in the 1999 Constitution exclude the promotion of", "images": [], "options": {"A": "national interest", "B": "African integration", "C": "support for donor agencies", "D": "just world economic order"}, "answer": "C", "explanation": "The foreign policy objectives of Nigeria as enshrined in the 1999 Constitution include the promotion of national interest, African integration, and a just world economic order. However, support for donor agencies is not explicitly stated as a foreign policy objective in the constitution. Therefore, the promotion of support for donor agencies is excluded from the foreign policy objectives of Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>39", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY", "question": "Democracy can promote national development if there is", "images": [], "options": {"A": "good governance", "B": "promotion of culture", "C": "immunity for leaders", "D": "registration of parties"}, "answer": "A", "explanation": "Democracy can promote national development if there is good governance. Good governance refers to the management of resources in a manner that is transparent, accountable, equitable and responsive to the needs of the people. It ensures that the government is effective and efficient in its operations, respects the rule of law, and promotes the participation of citizens in decision-making processes. This leads to national development as resources are used optimally, corruption is minimized, and the needs and interests of the people are prioritized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>40", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "A major civil society group which campaigned against military rule prior to the advent of the Four Republic in Nigeria is the", "images": [], "options": {"A": "Campaign for Democracy", "B": "Save Nigeria Group", "C": "Civil Liberties Organization", "D": "National Democracy Coalition"}, "answer": "A", "explanation": "The Campaign for Democracy (CD) was a major civil society group that campaigned against military rule prior to the advent of the Fourth Republic in Nigeria. The group was instrumental in mobilizing public opinion and pressure against the military regime, advocating for a return to democratic governance. The other options listed, while they are recognized civil society groups in Nigeria, they did not play as significant a role as the CD in the campaign against military rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>41", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "Which of the following functions is not performed by the Public Service Commission?", "images": [], "options": {"A": "Evaluating the performance of ministries and departments", "B": "Advising government on technical matters", "C": "Preparing the annual budget and assenting to it", "D": "Organising enlightenment programme and training"}, "answer": "C", "explanation": "The Public Service Commission does not prepare the annual budget and assent to it. This function is performed by the executive arm of government, specifically the Ministry of Finance and the President or Governor. The Public Service Commission is responsible for the recruitment, promotion, and discipline of civil servants. It also advises the government on civil service matters, evaluates the performance of ministries and departments, and organizes training programs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>42", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC", "question": "Which of the following is a major challenge to civil society in Nigeria?", "images": [], "options": {"A": "Value disorientation", "B": "Diverse political interests", "C": "Inadequate funding", "D": "Unstable political system"}, "answer": "C", "explanation": "Inadequate funding is a major challenge to civil society in Nigeria. Civil society organizations rely on funding to carry out their activities, and without adequate funding, their operations can be severely hampered. Value disorientation, diverse political interests, and an unstable political system can also pose challenges, but these are not unique to civil society and can affect many other sectors as well.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>43", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF DEMOCRACY", "question": "Democracy is yet to take firm root in Africa because", "images": [], "options": {"A": "It retards African development", "B": "African leaders are not experienced enough", "C": "Most African leaders detest the will of the people.", "D": "It is an expensive system of government"}, "answer": "C", "explanation": "Democracy is yet to take firm root in Africa mainly because most African leaders detest the will of the people. This is evident in the numerous cases of electoral malpractices, corruption, and disregard for the rule of law. Democracy is a system of government where the citizens exercise power directly or elect representatives from among themselves to form a governing body. If the leaders disregard the will of the people, then it's not a true democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>44", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "Nationalism ensures the following except", "images": [], "options": {"A": "national consciousness", "B": "secession in a country", "C": "national integration", "D": "courageously necessary"}, "answer": "B", "explanation": "Nationalism is a political ideology that involves a strong identification of a group of individuals with a nation. It is a collective state of mind or consciousness in which people believe their nation is superior to all others. It does not encourage secession in a country, rather it promotes national unity and integration. Therefore, the statement that nationalism ensures secession in a country is incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>45", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Justice demands that people should always do what is", "images": [], "options": {"A": "persistently convenient.", "B": "consistently right.", "C": "individually acceptable.", "D": "courageously necessary."}, "answer": "B", "explanation": "Justice is a concept of moral rightness based on ethics, rationality, law, natural law, religion, or equity. It demands that people should always do what is consistently right. Doing what is consistently right means acting in accordance with moral or legal principles all the time. This is the essence of justice, to ensure fairness and equity in all situations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2015>46", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Orderliness in the society is good mainly because it", "images": [], "options": {"A": "discourages poverty", "B": "promotes peace and stability", "C": "guarantees employment for youths", "D": "ensures maximum rewards from leaders"}, "answer": "B", "explanation": "Orderliness in the society is good mainly because it promotes peace and stability. When there is orderliness, there is a system or pattern that guides the actions and behaviors of individuals in the society. This reduces chaos, conflicts and misunderstandings, thereby promoting peace and stability. While orderliness may indirectly contribute to discouraging poverty, guaranteeing employment for youths, and ensuring maximum rewards from leaders, its primary benefit is the promotion of peace and stability in the society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>47", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Which of the following is necessary for the effective application of the rule of law?", "images": [], "options": {"A": "Political will to ensure that laws are obeyed", "B": "Employment opportunities for all citizens", "C": "The fusion of the three arms of government", "D": "Extension of the retirement age of judges"}, "answer": "A", "explanation": "The rule of law refers to the principle that everyone is subject to the law and equal before the law. It requires that laws are obeyed by all, including government officials, and that laws are enforced fairly and efficiently. Therefore, political will to ensure that laws are obeyed is necessary for the effective application of the rule of law. The other options do not directly relate to the rule of law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>48", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "Use the dialogue below to answer this question   Zubair: Today is the day for gubernatorial elections. Ade, what are you waiting for? Let us go and cast our votes for candidates of our choice.    Ade: I have no interest in an election which would not yield any dividend of democracy. Our political elite are only concerned about their interest when they get to the position of authority. For crying out loud, I have made up my mind that I will not vote again.    Zubair: Haba! Ade, don't you remember Abraham Lincoln's words that 'all men are not just, all men are not true. But . . . for every scoundrel there is a hero, that for every selfish politician, there is a dedicated leader!' Come on, go and cast your vote so that we can choose the right person for the position and change the political, economic and social directions of our great state.    Ade's action as shown in the dialogue is a demonstration of political", "images": [], "options": {"A": "wisdom.", "B": "apathy.", "C": "lawlessness.", "D": "participation."}, "answer": "B", "explanation": "In the dialogue, Ade expresses a lack of interest in participating in the election, indicating a sense of disillusionment with the political process. This is a demonstration of political apathy, which refers to indifference or a lack of interest in political activities such as voting or engaging in political debate. The other options do not accurately describe Ade's attitude.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>49", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY", "question": "Use the dialogue below to answer this question   Zubair: Today is the day for gubernatorial elections. Ade, what are you waiting for? Let us go and cast our votes for candidates of our choice.    Ade: I have no interest in an election which would not yield any dividend of democracy. Our political elite are only concerned about their interest when they get to the position of authority. For crying out loud, I have made up my mind that I will not vote again.    Zubair: Haba! Ade, don't you remember Abraham Lincoln's words that 'all men are not just, all men are not true. But . . . for every scoundrel there is a hero, that for every selfish politician, there is a dedicated leader!' Come on, go and cast your vote so that we can choose the right person for the position and change the political, economic and social directions of our great state.  It could be inferred from the dialogue that failure to vote in an election would", "images": [], "options": {"A": "guarantee citizens' right.", "B": "encourage the emergence of a responsive government.", "C": "promote accountability in governance.", "D": "perpetuate irresponsible leadership."}, "answer": "D", "explanation": "From the dialogue, it can be inferred that failure to vote in an election would perpetuate irresponsible leadership. This is because, as Zubair points out, voting is a way to choose the right person for the position and change the political, economic, and social directions of the state. If citizens like Ade choose not to vote, they are indirectly allowing the continuation of irresponsible leadership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2015>50", "subject": "Civic Education", "year": "2015", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : HOW LEADERS CAN PROTECT THE INTERESTS OF THEIR FOLLOWERS", "question": "Use the dialogue below to answer this question   Zubair: Today is the day for gubernatorial elections. Ade, what are you waiting for? Let us go and cast our votes for candidates of our choice.    Ade: I have no interest in an election which would not yield any dividend of democracy. Our political elite are only concerned about their interest when they get to the position of authority. For crying out loud, I have made up my mind that I will not vote again.    Zubair: Haba! Ade, don't you remember Abraham Lincoln's words that 'all men are not just, all men are not true. But . . . for every scoundrel there is a hero, that for every selfish politician, there is a dedicated leader!' Come on, go and cast your vote so that we can choose the right person for the position and change the political, economic and social directions of our great state.  From the above dialogue, political leaders can encourage citizens to perform their civic duties by", "images": [], "options": {"A": "fulfilling their electoral promises", "B": "travelling overseas to seek for foreign investors.", "C": "engaging in religious activities.", "D": "visiting all the local governments in the country."}, "answer": "A", "explanation": "From the dialogue, it can be inferred that political leaders can encourage citizens to perform their civic duties by fulfilling their electoral promises. Ade's reluctance to vote stems from his belief that the political elite are only concerned about their own interests when they get to the position of authority. If political leaders were to fulfill their electoral promises, it would show citizens like Ade that they are indeed concerned about the welfare of the people, thereby encouraging them to participate in the electoral process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>1", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "Orderliness can be defined as", "images": [], "options": {"A": "being punctual to work", "B": "studying diligently in school", "C": "doing things in a proper way", "D": "learning the Western way of life"}, "answer": "C", "explanation": "Orderliness refers to the quality of doing things in a systematic, organized, and disciplined manner. It does not necessarily relate to punctuality, diligence in studies, or adopting a particular way of life. Therefore, the correct answer is 'doing things in a proper way'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>2", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Use the sign below to answer this question     The road sign above means", "images": ["Civic Education/imgs/2016/img1.png"], "options": {"A": "No entry", "B": "Maximum speed limit", "C": "No stopping", "D": "No parking"}, "answer": "A", "explanation": "The road sign means No Entry or Road. This is the most appropriate answer", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>3", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "The Traffic in Persons Prohibition and Administration Act was passed in Nigeria in", "images": [], "options": {"A": "December 2001", "B": "October 2002", "C": "August 2003", "D": "April 2004"}, "answer": "C", "explanation": "The Traffic in Persons (Prohibition) Enforcement and Administration Act was passed in Nigeria in August 2003. The Act was established to prohibit trafficking in persons, provide for an effective and comprehensive legal and institutional framework for the prohibition, prevention, detection, prosecution and punishment of human trafficking and related offenses in Nigeria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>4", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "The process of enabling someone to perform an action which adds values to his/her life is known as", "images": [], "options": {"A": "employment", "B": "recruitment", "C": "socialization", "D": "empowerment"}, "answer": "D", "explanation": "Empowerment is the process of enabling someone to perform an action which adds values to his/her life. It involves giving someone the resources, skills, or authority to do something. This can be in the form of education, training, or mentorship. The other options, employment, recruitment, and socialization, do not fit the definition of the process described in the question.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>5", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "Rates are collected in Nigeria by", "images": [], "options": {"A": "Federal Inland Revenue Service", "B": "State Ministry of Finance", "C": "Local Government Council", "D": "Council of Traditional Rulers"}, "answer": "C", "explanation": "In Nigeria, rates such as property tax, market fees, and other local levies are collected by the Local Government Council. The Federal Inland Revenue Service is responsible for collecting federal taxes like income tax and VAT, while the State Ministry of Finance handles state-level taxes. The Council of Traditional Rulers does not have a role in tax collection.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>6", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "The fourth schedule of the 1999 constitution of Nigeria outlines the functions of", "images": [], "options": {"A": "federal government", "B": "local government", "C": "national government", "D": "state government"}, "answer": "B", "explanation": "The fourth schedule of the 1999 constitution of Nigeria outlines the functions of the local government. The local government is the third tier of government in Nigeria and it is the closest to the people. It is responsible for the administration of areas within its jurisdiction, including the implementation of certain federal and state policies, economic planning, and development, as well as the provision of public services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>7", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "Lack of interest in the country is referred to as political", "images": [], "options": {"A": "ignorance", "B": "apathy", "C": "participation", "D": "socialization"}, "answer": "B", "explanation": "Lack of interest in the country is referred to as political apathy. Political apathy is a feeling of disinterest in the sense of politics or apathy towards politics. It can consist of interest apathy, voter apathy, and civic apathy. It means that an individual has an lack of concern for, or interest in, political matters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>8", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "Which of the following instrument is not used by a civil society group?", "images": [], "options": {"A": "Propaganda", "B": "Boycott", "C": "Protest", "D": "Violence"}, "answer": "D", "explanation": "Civil society groups are non-governmental organizations that are involved in the public sphere, expressing the interests and will of citizens. They use various instruments to achieve their goals, such as propaganda, boycotts, and protests. However, violence is not an instrument used by civil society groups. It is against the principles of civil society groups which are based on peaceful advocacy and respect for law and order.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>9", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "The administrative class in the public service is to", "images": [], "options": {"A": "implement policies", "B": "formulate policies", "C": "veto policies", "D": "oversee policies"}, "answer": "A", "explanation": "The administrative class in the public service is responsible for implementing policies. They are the ones who carry out the decisions made by the policy makers. They do not formulate, veto, or oversee policies. These roles are typically performed by the legislative and executive branches of government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>10", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "\"We the people of the Federal Republic of Nigeria\" is usually the opening phrase of the preamble to", "images": [], "options": {"A": "coup announcement", "B": "government gazettes", "C": "constitution", "D": "hansard"}, "answer": "C", "explanation": "The phrase \"We the people of the Federal Republic of Nigeria\" is the opening phrase of the preamble to the constitution of Nigeria. A preamble is an introductory statement in a document that explains the document's philosophy, purposes, or objectives. In the case of constitutions, it presents the general principles which the constitution seeks to establish.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>11", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS", "question": "One of the responsibilities of a good citizen is to", "images": [], "options": {"A": "possess an international passport", "B": "enjoy all amenities provided by the government", "C": "serve the country when required", "D": "develop his potentialities to the fullest"}, "answer": "C", "explanation": "One of the responsibilities of a good citizen is to serve the country when required. This can be in the form of obeying laws, paying taxes, participating in civic duties like voting, and even serving in the military or other public services when called upon. It is part of the social contract that citizens have with their country, where they agree to abide by the rules and work for the betterment of the society in return for protection and rights granted by the state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>12", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "Naturalized citizens cannot be denied their legal status as members of a country unless if they", "images": [], "options": {"A": "are jailed for one year within seven years of acquiring citizenship", "B": "are found guilty to be spies or secret agents for another country", "C": "refuse to represent the country in an international sporting event", "D": "give adequate information to the host country"}, "answer": "B", "explanation": "Naturalized citizens can lose their citizenship if they are found guilty of being spies or secret agents for another country. This is because such actions are considered a betrayal of the country's trust and a violation of the loyalty expected from its citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>13", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION", "question": "Citizenship education influences an individual to be", "images": [], "options": {"A": "patriotic", "B": "educated", "C": "complacent", "D": "competent"}, "answer": "A", "explanation": "Citizenship education is designed to help individuals understand their rights and responsibilities as citizens, and to encourage them to be active, informed, and responsible members of their community. This includes fostering a sense of patriotism, or love and devotion to one's country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>14", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Which of the following is not an example of orderliness?", "images": [], "options": {"A": "Listening skill", "B": "Driving skill", "C": "Decorum", "D": "Deviance"}, "answer": "A", "explanation": "Orderliness refers to the quality of being well-organized or following a systematic and established procedure. Listening skill, while important, does not directly relate to the concept of orderliness. Driving skill, decorum, and deviance (which is a lack of orderliness) are more directly related to the concept of orderliness.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>15", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Which of the following statements is not correct?", "images": [], "options": {"A": "Valid driver's license must be obtained before attempting to drive", "B": "Flowing garment can be worm on a motorcycle or bicycle", "C": "Headlight should be used during unfavourable weather", "D": "Drivers must not engage in distractive activities while driving"}, "answer": "B", "explanation": "The statement 'Flowing garment can be worn on a motorcycle or bicycle' is not correct. This is because wearing flowing garments while riding a motorcycle or bicycle can be dangerous as the garment can get caught in the wheels or chain of the vehicle, leading to accidents. The other options are correct as they all relate to safe and responsible driving practices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>16", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL CONFLICTS", "question": "Use the dialogue below to answer this question       Which of the following is a consequence of lack of understanding between the Iwuya and Ipaja?", "images": ["Civic Education/imgs/2016/2016civivq1618.png"], "options": {"A": "Intra-communal conflict", "B": "Economic dislocation", "C": "Inter-communal feud", "D": "Interpersonal violence"}, "answer": "A", "explanation": "Lack of understanding between the Iwuya and Ipaja is Intra-Communal conflict.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>17", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS", "question": "Use the dialogue below to answer this question     The remarks of Ayo in the above dialogue portray the importance of", "images": ["Civic Education/imgs/2016/2016civivq1618.png"], "options": {"A": "struggle against British imperialists", "B": "museum for keeping old weapons of war", "C": "modern methods of conflict resolution", "D": "peace for societal progress and development"}, "answer": "D", "explanation": "The remarks of Ayo in the above dialogue portray the importance of peace for societal progress and development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>18", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS", "question": "Use the dialogue below to answer this question     From the above dialogue, the Headmaster could be described as a", "images": ["Civic Education/imgs/2016/2016civivq1618.png"], "options": {"A": "conciliator that delights in the peace of the communities", "B": "dogged fighter with sound martial skills", "C": "good samaritan who values peace", "D": "fellow who prefers social unrest to harmonious co-existence"}, "answer": "D", "explanation": "The headmaster is described as a fellow who prefers social unrest to harmonious co-existence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>19", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Cultism can best be discouraged through", "images": [], "options": {"A": "mentoring of cultists by the rich", "B": "provision of jobs for cultists", "C": "sensitization on the dangers of cultism", "D": "establishment of cultists support groups"}, "answer": "C", "explanation": "Cultism can best be discouraged through sensitization on the dangers of cultism. Sensitization involves creating awareness and educating people about the negative impacts of cultism. This can be done through various mediums such as seminars, workshops, media campaigns, etc. The aim is to enlighten individuals, especially the youth, about the dangers and consequences of cultism, thereby discouraging their involvement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>20", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : SYMPTOMS OF DRUG ABUSE", "question": "Which of the following is a consequence of drug abuse?", "images": [], "options": {"A": "Depression", "B": "Victimization", "C": "Inefficiency", "D": "Cowardice"}, "answer": "A", "explanation": "Depression is a consequence of drug abuse. Drug abuse can lead to a variety of physical and mental health problems. One of these is depression, a mood disorder that causes a persistent feeling of sadness and loss of interest. Drug abuse can lead to depression by altering the levels of neurotransmitters in the brain, which are responsible for mood regulation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>21", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "The effect of human trafficking on the victims is", "images": [], "options": {"A": "illiteracy", "B": "affluence", "C": "exposure", "D": "exploitation"}, "answer": "D", "explanation": "Human trafficking is a form of modern-day slavery where people profit from the control and exploitation of others. The victims of human trafficking are often exploited for purposes such as forced labor, sexual exploitation, and organ trafficking. Therefore, the correct answer is 'exploitation'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>22", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "The general attitude of government and society towards cultism is that of", "images": [], "options": {"A": "affection", "B": "sympathy", "C": "abhorrence", "D": "support"}, "answer": "C", "explanation": "Cultism is a social vice that is generally frowned upon by both the government and society at large due to its negative impacts such as violence, crime, and disruption of academic activities in schools. Therefore, the general attitude of government and society towards cultism is that of 'abhorrence'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>23", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE", "question": "Drug abuse can be prevented by", "images": [], "options": {"A": "fighting drug addicts", "B": "poverty reduction", "C": "reducing drugs in circulation", "D": "legal sanction"}, "answer": "C", "explanation": "Drug abuse can be prevented by reducing drugs in circulation. This is because the availability of drugs is a major factor that contributes to drug abuse. If drugs are not readily available, it would be difficult for individuals to abuse them. The other options do not directly address the prevention of drug abuse. Fighting drug addicts does not prevent drug abuse but rather punishes those who are already addicted. Poverty reduction and legal sanctions may indirectly affect drug abuse, but they are not direct methods of prevention.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>24", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING", "question": "A major responsible for human trafficking is", "images": [], "options": {"A": "hunger", "B": "illiteracy", "C": "greed", "D": "joblessness"}, "answer": "C", "explanation": "A major responsible for human trafficking is greed. Human trafficking is a crime driven by the potential for profit. Traffickers exploit vulnerable individuals with the promise of financial gain. While factors like hunger, illiteracy, and joblessness can make individuals more vulnerable to trafficking, the root cause is the greed of the traffickers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>25", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "People living with HIV/AIDS (PLWHA) can be supported by", "images": [], "options": {"A": "billing them for antiretroviral therapy", "B": "providing drugs for them at subsidized rates", "C": "providing special attires for them", "D": "providing accommodation for them in designated locations"}, "answer": "B", "explanation": "People living with HIV/AIDS (PLWHA) can be supported by providing drugs for them at subsidized rates. This is because antiretroviral therapy is a critical part of managing HIV/AIDS, and making these drugs more affordable can significantly improve the quality of life for PLWHA.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>26", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Cult members are particularly hostile to", "images": [], "options": {"A": "lecturers", "B": "perceived enemies", "C": "their group", "D": "all students"}, "answer": "B", "explanation": "Cult members are particularly hostile to perceived enemies. This is because cults often create an 'us versus them' mentality, where anyone outside of the group is seen as a potential threat or enemy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>27", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "Drug law enforcement agencies in Nigeria are not empowered to", "images": [], "options": {"A": "execute drug suspects", "B": "arrest drug barons", "C": "prosecute drug traffickers", "D": "rehabilitate drug addicts"}, "answer": "A", "explanation": "The National Drug Law Enforcement Agency (NDLEA) in Nigeria is empowered to arrest, prosecute drug traffickers and rehabilitate drug addicts. However, they are not empowered to execute drug suspects. Execution is a capital punishment that is only carried out after a court judgement. It is not within the jurisdiction of the NDLEA to execute drug suspects.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>28", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "Which of the following is not a means of reducing the incidence of HIV/AIDS in our society?", "images": [], "options": {"A": "Education and enlightenment programme", "B": "The use of specially designed cutlery by victims", "C": "Avoiding pre-marital and extra-marital sex", "D": "Upholding the value of chastity"}, "answer": "B", "explanation": "The use of specially designed cutlery by victims is not a means of reducing the incidence of HIV/AIDS in our society. HIV/AIDS is not transmitted through sharing of cutlery. It is transmitted through unprotected sex, sharing of sharp objects like needles and from an infected mother to her child during childbirth or breastfeeding. Education and enlightenment programmes, avoiding pre-marital and extra-marital sex, and upholding the value of chastity are all effective means of reducing the incidence of HIV/AIDS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>29", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS", "question": "Youth empowerment promotes", "images": [], "options": {"A": "self-reliance", "B": "youthful exuberance", "C": "pursuit of higher education", "D": "foreign scholarship"}, "answer": "A", "explanation": "Youth empowerment is a process where young people are encouraged to take charge of their lives. They do this by addressing their situation and then take action in order to improve their access to resources and transform their consciousness through their beliefs, values, and attitudes. Youth empowerment aims to improve quality of life. Youth empowerment is often addressed as a gateway to intergenerational equity, civic engagement and democracy building. The most common way in which youth empowerment occurs is through youth-led organizations in which young people's interests are represented and their voices are heard. Therefore, the correct answer is 'self-reliance'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>30", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW", "question": "The supreme court of Nigeria helps in law", "images": [], "options": {"A": "drafting", "B": "application", "C": "interpretation", "D": "enforcement"}, "answer": "C", "explanation": "The Supreme Court of Nigeria is the highest court in Nigeria, and its decisions are final. The primary role of the Supreme Court is to interpret the law. This means that the Supreme Court takes the lead in defining the meaning of laws, how they are applied, and whether they violate the constitution. Therefore, the correct answer is 'interpretation'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>31", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY", "question": "Democracy thrives most where there is", "images": [], "options": {"A": "non partisan judiciary", "B": "freedom of speech and association", "C": "absence of universal suffrage", "D": "one-party system"}, "answer": "B", "explanation": "Democracy thrives most where there is freedom of speech and association. This is because democracy is a system of government where citizens are allowed to participate in decision making. Freedom of speech and association allows citizens to express their views and form or join groups that share their interests or beliefs. This promotes diversity of opinions and ideas, which is a key feature of a thriving democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>32", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF RULE OF LAW", "question": "Rule of law is limited by the following except", "images": [], "options": {"A": "state of emergency", "B": "habeas corpus", "C": "illiteracy", "D": "immunity"}, "answer": "C", "explanation": "The rule of law is not limited by illiteracy. The rule of law is a principle that all people and institutions are subject to and accountable to law that is fairly applied and enforced. Illiteracy, or the inability to read or write, does not limit the application or enforcement of the law. However, state of emergency, habeas corpus, and immunity can limit the rule of law. A state of emergency can suspend certain legal protections, habeas corpus (a legal action through which a person can seek relief from unlawful detention) can be suspended in certain situations, and immunity can protect certain individuals from legal action.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>33", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "Preventive measures of HIV/AIDS do not include", "images": [], "options": {"A": "abstinence", "B": "screening of blood before transfusion", "C": "use of barrier methods", "D": "stigmatization of victims"}, "answer": "D", "explanation": "Stigmatization of victims is not a preventive measure of HIV/AIDS. Stigmatization refers to the act of discriminating or treating someone unfairly due to their condition or status. In the context of HIV/AIDS, stigmatization can actually hinder prevention efforts as it may discourage individuals from getting tested or seeking treatment due to fear of discrimination. The other options listed such as abstinence, screening of blood before transfusion, and use of barrier methods are all recognized preventive measures of HIV/AIDS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>34", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : WHY LEADERS FAIL TO PROTECT THE INTERESTS OF THEIR FOLLOWERS", "question": "One of the reasons leaders fail to protect the interest of the followers is", "images": [], "options": {"A": "selfishness", "B": "inadequate finance", "C": "ignorance", "D": "rigid policies"}, "answer": "A", "explanation": "Selfishness is one of the reasons leaders fail to protect the interest of the followers. When leaders are selfish, they prioritize their own interests over the interests of their followers. This can lead to decisions and actions that are detrimental to the followers. The other options listed such as inadequate finance, ignorance, and rigid policies can also contribute to leaders failing to protect the interest of their followers, but they are not the primary reason.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>35", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : TYPES OF POPULAR PARTICIPATION", "question": "Which of the following is not a form of political participation?", "images": [], "options": {"A": "Taking part in voters' registration exercise", "B": "Voting during election", "C": "Joining political party", "D": "Ballot box stuffing during election"}, "answer": "D", "explanation": "Political participation refers to the activities by which citizens attempt to influence the selection of political leaders and the policies they pursue. This includes activities like voting, joining political parties, and participating in voters' registration exercises. Ballot box stuffing, however, is an illegal activity that involves tampering with the election process and is not considered a legitimate form of political participation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>36", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "Civil society groups perform the following roles during general elections except", "images": [], "options": {"A": "educating the voters", "B": "serving as watchdog", "C": "counting votes", "D": "stimulating participation"}, "answer": "C", "explanation": "Civil society groups play a crucial role in the electoral process. They educate voters about their rights and responsibilities, serve as watchdogs to ensure the election is free and fair, and stimulate participation by encouraging citizens to vote. However, counting votes is not a role of civil society groups. This is typically the responsibility of the electoral commission or other designated election officials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>37", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Which of the following is not an example of civil society groups?", "images": [], "options": {"A": "United Action for Democracy", "B": "United Nations Organization", "C": "Transition Monitoring Group", "D": "Amnesty International"}, "answer": "B", "explanation": "A civil society group is a non-governmental organization that operates in the interest of the citizens but outside of the government. The United Nations Organization is not a civil society group. It is an international organization established by sovereign states to promote international cooperation and to create and maintain international order.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>38", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "One of the major complains against public service is", "images": [], "options": {"A": "inefficiency", "B": "understaffing", "C": "victimization", "D": "discrimination"}, "answer": "A", "explanation": "Inefficiency is one of the major complaints against public service. This refers to the inability of the public service to deliver services in a timely, cost-effective, and quality manner. This could be due to various factors such as bureaucracy, lack of resources, corruption, and lack of accountability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>39", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : WAYS OF IMPROVING THE PUBLIC SERVICE", "question": "Which of the following is not a way of improving public service?", "images": [], "options": {"A": "Politicization", "B": "Refresher courses", "C": "The use of Code of Conduct Bureau", "D": "Reformation"}, "answer": "A", "explanation": "Politicization is not a way of improving public service. It often leads to bias and corruption, which can degrade the quality of public service. On the other hand, refresher courses, the use of Code of Conduct Bureau, and reformation are all strategies that can improve the quality of public service. Refresher courses can update the knowledge and skills of public servants, the Code of Conduct Bureau can enforce ethical standards, and reformation can change outdated systems and processes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>40", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "Children that are not cared for are mostly prone to", "images": [], "options": {"A": "criminal attitudes", "B": "terminal diseases", "C": "examination failure", "D": "forced migration"}, "answer": "A", "explanation": "Children that are not cared for are mostly prone to criminal attitudes. Lack of care and guidance can lead to behavioral problems and criminal attitudes in children. While it's possible for such children to experience terminal diseases, examination failure, or forced migration, these are not as directly linked to the lack of care as criminal attitudes are.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>41", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM~~EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Use the monologue below to answer this question   Oh Motherland, you were a precious country, a beacon of hope and aspiration as well as toga of pride of your citizens at independence. However, today you are bedeviled with evil, engulfed in the darkness and to say the obvious, at the edge of total moral collapse. Corruption, fraud, deception and dishonesty are prevalent; drug peddlers are having a field day. In schools and colleges, radicalism, prostitution, cultism, examination malpractice among other social vices are order of the day.    The motherland in the monologue could best be described as", "images": [], "options": {"A": "a nation in transition", "B": "a morally upgrading country", "C": "a socially viable nation", "D": "an ethically bankrupt country"}, "answer": "D", "explanation": "The monologue describes a country that was once a beacon of hope and pride but is now riddled with corruption, fraud, deception, dishonesty, and various social vices. This description aligns with the concept of ethical bankruptcy, which refers to a state where moral principles and values are severely lacking or completely absent. Therefore, the motherland in the monologue can best be described as 'an ethically bankrupt country'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>42", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM~~EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Use the monologue below to answer this question   Oh Motherland, you were a precious country, a beacon of hope and aspiration as well as toga of pride of your citizens at independence. However, today you are bedeviled with evil, engulfed in the darkness and to say the obvious, at the edge of total moral collapse. Corruption, fraud, deception and dishonesty are prevalent; drug peddlers are having a field day. In schools and colleges, radicalism, prostitution, cultism, examination malpractice among other social vices are order of the day.  In spite of the state of affairs reflected in the above monologue, the citizens can make the country better by being committed to", "images": [], "options": {"A": "promoting inter-communal relations", "B": "strengthening capacity building", "C": "championing moral values", "D": "encouraging interpersonal relations"}, "answer": "C", "explanation": "The monologue describes a country in a state of moral decay. To improve such a situation, the citizens need to uphold and promote moral values. This includes honesty, integrity, and respect for others, among other virtues. By championing moral values, citizens can help to reduce corruption, fraud, and other social vices, thereby making the country better. Therefore, the citizens can make the country better by being committed to 'championing moral values'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>43", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM~~EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Use the monologue below to answer this question   Oh Motherland, you were a precious country, a beacon of hope and aspiration as well as toga of pride of your citizens at independence. However, today you are bedeviled with evil, engulfed in the darkness and to say the obvious, at the edge of total moral collapse. Corruption, fraud, deception and dishonesty are prevalent; drug peddlers are having a field day. In schools and colleges, radicalism, prostitution, cultism, examination malpractice among other social vices are order of the day.  Based on the monologue above, the best approach to curb decadence in the motherland by", "images": [], "options": {"A": "value re-orientation", "B": "introducing war against corruption", "C": "legalizing capital punishment", "D": "sending corrupt officials on exile"}, "answer": "A", "explanation": "The monologue describes a variety of social issues, including corruption, fraud, drug peddling, radicalism, prostitution, cultism, and examination malpractice. These issues are not just about corruption, but also about moral and ethical decay. Therefore, the best approach to curb this decadence is through 'value re-orientation'. This means changing the mindset and attitudes of the citizens towards positive values and ethics. This is a more comprehensive approach than just introducing war against corruption or legalizing capital punishment, which only address specific issues and not the overall moral decay. Sending corrupt officials on exile does not solve the root cause of the problem, which is the lack of proper values and ethics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>44", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "The most important contribution of responsible parenthood to national development is that it", "images": [], "options": {"A": "increases youthful population", "B": "fosters national integration", "C": "augments the nation workforce", "D": "breeds dependable citizenry"}, "answer": "D", "explanation": "Responsible parenthood contributes to national development by breeding dependable citizenry. This is because responsible parents raise children who are likely to become responsible, law-abiding, and productive citizens. These citizens contribute to the development of the nation in various ways, such as by participating in the workforce, paying taxes, and upholding the law. While responsible parenthood may also increase the youthful population, foster national integration, and augment the nation's workforce, these are not the most important contributions. The most important contribution is the creation of a dependable citizenry, as this underpins all other aspects of national development.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>45", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : DRUGS THAT CAN BE ABUSED", "question": "Which of the following can not be easily abused?", "images": [], "options": {"A": "cosmetics", "B": "stimulant", "C": "tobacco", "D": "narcotics"}, "answer": "A", "explanation": "The question asks for the item that cannot be easily abused. Among the options, cosmetics are the least likely to be abused. Stimulants, tobacco, and narcotics are all substances that can be and often are abused, leading to addiction and health problems. Cosmetics, on the other hand, are generally used for enhancing or altering one's appearance and are not typically associated with abuse.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>46", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS", "question": "Use the story below to answer this question   Dr. Fajir was the Minister of Works and Urban Development in the Ganiba Republic. As such, he was entrusted with the public fund so that his ministry could construct new roads and rehabilitate the existing ones. Unfortunately, Dr. Fajir embezzled the money entrusted in his care and siphoned same to his foreign accounts. This led to the deplorable conditions of roads in the Republic. The Crime Commission arrested and prosecuted him accordingly. Subsequently, he was given the opportunity to be defended by lawyers of his choice in a Court of Law. However, he was found guilty and sentenced to 15 years imprisonment with hard labour without the option of a fine. In addition, he forfeited all his ill-gotten wealth to the Republic.    Dr. Fajir cannot exercise some basic rights because he", "images": [], "options": {"A": "was a suspect in a criminal case", "B": "was found guilty of a criminal case", "C": "failed to comply with court order", "D": "embezzled public fund"}, "answer": "B", "explanation": "The question is about why Dr. Fajir cannot exercise some basic rights. The story clearly states that he was found guilty of a criminal case, which is why he cannot exercise some basic rights. Being a suspect in a criminal case or failing to comply with a court order does not necessarily result in the loss of basic rights. Embezzling public funds is the crime he committed, but it's the conviction (being found guilty) that results in the loss of rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>47", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "Use the story below to answer this question   Dr. Fajir was the Minister of Works and Urban Development in the Ganiba Republic. As such, he was entrusted with the public fund so that his ministry could construct new roads and rehabilitate the existing ones. Unfortunately, Dr. Fajir embezzled the money entrusted in his care and siphoned same to his foreign accounts. This led to the deplorable conditions of roads in the Republic. The Crime Commission arrested and prosecuted him accordingly. Subsequently, he was given the opportunity to be defended by lawyers of his choice in a Court of Law. However, he was found guilty and sentenced to 15 years imprisonment with hard labour without the option of a fine. In addition, he forfeited all his ill-gotten wealth to the Republic.  According to the above story, the open trial of Dr. Fajir and his representation by lawyers of his choice in a court of competent jurisdiction is an indication of", "images": [], "options": {"A": "respect for habeas corpus", "B": "freedom of expression", "C": "respect for human rights", "D": "freedom of legal representation"}, "answer": "C", "explanation": "The open trial of Dr. Fajir and his representation by lawyers of his choice in a court of competent jurisdiction is an indication of respect for human rights. This is because the right to a fair trial and the right to legal representation are fundamental human rights. The right to a fair trial ensures that individuals are not unjustly treated or punished without being given an opportunity to defend themselves. The right to legal representation ensures that individuals have the opportunity to be defended by a legal practitioner in court proceedings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>48", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS", "question": "Use the story below to answer this question   Dr. Fajir was the Minister of Works and Urban Development in the Ganiba Republic. As such, he was entrusted with the public fund so that his ministry could construct new roads and rehabilitate the existing ones. Unfortunately, Dr. Fajir embezzled the money entrusted in his care and siphoned same to his foreign accounts. This led to the deplorable conditions of roads in the Republic. The Crime Commission arrested and prosecuted him accordingly. Subsequently, he was given the opportunity to be defended by lawyers of his choice in a Court of Law. However, he was found guilty and sentenced to 15 years imprisonment with hard labour without the option of a fine. In addition, he forfeited all his ill-gotten wealth to the Republic.  Based on the above story, which of the following would Dr. Fajir not be allowed to do while in prison?", "images": [], "options": {"A": "Voting during election", "B": "Engaging in hard labour", "C": "Participating in prison fellowship", "D": "Writing examination"}, "answer": "A", "explanation": "While in prison, Dr. Fajir would not be allowed to vote during elections. This is because in many jurisdictions, including the Ganiba Republic as implied in the story, prisoners are often disenfranchised and do not have the right to vote. This is often justified on the grounds that those who have committed serious crimes against society should not have a say in how society is governed. The other options such as engaging in hard labour, participating in prison fellowship, and writing examination are activities that prisoners are typically allowed to engage in as part of their rehabilitation process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2016>49", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "The most important place for building good values is the", "images": [], "options": {"A": "social welfare centre", "B": "workplace", "C": "family", "D": "media houses"}, "answer": "C", "explanation": "The family is the first social institution any individual interacts with. It is in the family that a child learns the basic values, norms, and social behavior. The family lays the foundation for the child's personality development. Therefore, the family is the most important place for building good values.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2016>50", "subject": "Civic Education", "year": "2016", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "Citizen's compliance with tenets of the Nigerian National Pledge will enable the country to", "images": [], "options": {"A": "receive reciprocal assistance", "B": "witness value clarification", "C": "get international aid", "D": "experience development"}, "answer": "D", "explanation": "The Nigerian National Pledge is a pledge to be faithful, loyal and honest, to serve Nigeria with all strength, to defend her unity, uphold her honor and glory, and to obey Nigeria's laws. Compliance with these tenets will lead to a harmonious and peaceful society, which is a prerequisite for development. Therefore, citizen's compliance with the tenets of the Nigerian National Pledge will enable the country to experience development.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>1", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "The standards that are considered ethical by an individual or the society are known as", "images": [], "options": {"A": "dignity", "B": "rights", "C": "values", "D": "materialism"}, "answer": "C", "explanation": "The standards that are considered ethical by an individual or the society are known as values. Values are the beliefs and principles that guide our decisions and behavior. They are the standards by which we judge right and wrong, important and unimportant, worthwhile and worthless. They are not tangible items like dignity, rights or materialism, but rather intangible standards that guide our actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>2", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "One significance of value in society is that it", "images": [], "options": {"A": "brings about peaceful co-existence of people", "B": "makes one to acquire more properties", "C": "enhances an individual's access to education", "D": "promotes influx of aliens to community"}, "answer": "A", "explanation": "One significance of value in society is that it brings about peaceful co-existence of people. Values are the shared beliefs and attitudes that bind people together in society. They provide a common understanding of what is right and wrong, and this shared understanding helps to promote peace and harmony among people. The other options do not accurately represent the significance of values in society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>3", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "'If I should forsake you,  Banwuya motherland, Africa fatherland,  Let my two hands  Forget their cunnings\".   @ Femi Ademiluyi: The New Man.  All rights reserved.    The quotation shows that the speaker is", "images": [], "options": {"A": "nationalistic", "B": "opportunistic", "C": "subservient", "D": "reoriented"}, "answer": "A", "explanation": "The speaker in the poem is expressing a deep sense of loyalty and commitment to his motherland, Africa. This is a characteristic of nationalism, which is a political ideology that involves a strong identification of a group of individuals with a nation. Therefore, the speaker is nationalistic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>4", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "The status of being a legal member of a country is referred to as", "images": [], "options": {"A": "alien", "B": "asylum", "C": "citizenship", "D": "migrant"}, "answer": "C", "explanation": "The status of being a legal member of a country is referred to as citizenship. Citizenship is the status of a person recognized under the custom or law of a sovereign state or local jurisdiction. It involves rights, duties and privileges.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>5", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : IDENTIFICATION OF LOCAL AND WORLD CIVIC PROBLEMS", "question": "Rendering services to humanity across boundaries is an indication of providing solution to", "images": [], "options": {"A": "political crisis", "B": "social dilemmas", "C": "natural disasters", "D": "civic problems"}, "answer": "C", "explanation": "Rendering services to humanity across boundaries is often in response to natural disasters. This is because natural disasters such as earthquakes, hurricanes, and floods often require international aid and assistance. This is not necessarily related to political crisis, social dilemmas, or civic problems, which are more localized and specific issues.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>6", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : ROLES OF INDIVIDUALS, GROUPS AND GOVERNMENT IN UDHR", "question": "Human rights can be best promoted if", "images": [], "options": {"A": "jungle justice is discouraged", "B": "relevant knowledge and information are acquired", "C": "political elite exercises discretionary powers", "D": "there is existing constitution"}, "answer": "B", "explanation": "Human rights can be best promoted if relevant knowledge and information are acquired. This is because understanding the concept of human rights, the laws that protect these rights, and the mechanisms to enforce these rights is crucial for their promotion. While discouraging jungle justice, exercising discretionary powers by political elites, and having an existing constitution can contribute to the promotion of human rights, they are not as fundamental as having the relevant knowledge and information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>7", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS", "question": "The rights of citizens can be guaranteed through", "images": [], "options": {"A": "gerrymandering", "B": "the writ of habeas corpus", "C": "prerogative of mercy", "D": "political immunity"}, "answer": "B", "explanation": "The writ of habeas corpus is a legal action or writ by means of which detainees can seek relief from unlawful imprisonment. It is a way to report an illegal detention or imprisonment to a court and request that the court order the custodian of the person, usually a prison official, to bring the prisoner to court, to determine whether the detention is lawful. This is how it guarantees the rights of citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>8", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS", "question": "The inalienable rights of citizens of a state can best be protected through", "images": [], "options": {"A": "an unwritten constitution", "B": "parliamentary system of government", "C": "unitary system of government", "D": "an independent judiciary"}, "answer": "D", "explanation": "An independent judiciary is the best way to protect the inalienable rights of citizens of a state. This is because an independent judiciary can make decisions free from pressure and influences other than the law. It can uphold the rule of law, protect rights and liberties, and check abuses of power. An independent judiciary ensures that everyone, including citizens, institutions, and the government itself, are subject to the law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>9", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "The society can be much more peaceful if individuals learn to", "images": [], "options": {"A": "respect and obey the laws of the land", "B": "gather knowledge about politics", "C": "understand the human rights commission", "D": "seek redress in the court of law"}, "answer": "A", "explanation": "A peaceful society is one where law and order are maintained. This can be achieved if individuals respect and obey the laws of the land. This is because laws are designed to regulate human behavior and maintain order in society. When people obey the laws, conflicts and crimes are minimized, leading to a peaceful society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>10", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER", "question": "The exhibition of queuing culture in a society is a good example of", "images": [], "options": {"A": "participation", "B": "empowerment", "C": "nationalism", "D": "orderliness"}, "answer": "D", "explanation": "Queuing culture is a practice where people line up in an orderly manner while waiting for services or goods. This practice is a good example of orderliness because it shows respect for others and prevents chaos and confusion. It is not directly related to participation, empowerment, or nationalism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>11", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : MEANING OF CONSTITUTED AUTHORITY", "question": "Constituted authority is necessary in the society because it", "images": [], "options": {"A": "promotes international relations", "B": "ensures security of lives and properties", "C": "serves as agent of socialization", "D": "provides scholarship for higher education"}, "answer": "B", "explanation": "Constituted authority refers to the powers and mechanisms established by a constitution, which govern a society or organization. It is necessary in society because it ensures the security of lives and properties. This is achieved by enforcing laws and regulations, maintaining order, and protecting citizens from harm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>12", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "Responsible parenthood is important because it", "images": [], "options": {"A": "promotes procreation", "B": "fosters orderliness", "C": "grooms disciplined children", "D": "provides solution to all societal problems"}, "answer": "C", "explanation": "Responsible parenthood refers to the responsibility of parents to guide, nurture, and instill good values in their children. It is important because it grooms disciplined children. Disciplined children are more likely to grow into responsible adults who contribute positively to society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>13", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "Which of the following should not be encouraged by responsible parents?", "images": [], "options": {"A": "Moral development", "B": "Religious fundamentalism", "C": "Spiritual development", "D": "Respect for elders"}, "answer": "B", "explanation": "Responsible parents should encourage moral development, spiritual development, and respect for elders in their children. However, religious fundamentalism, which refers to a belief in the absolute authority of a religious text or leaders, is often associated with intolerance and extremism. Therefore, it should not be encouraged.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>14", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Road signs primarily serve as", "images": [], "options": {"A": "symbols to correct road users", "B": "signs to aid Federal Road Safety officials to apprehend defaulters", "C": "devices to guide traffic division of Police Command", "D": "precautionary devices to guide road users"}, "answer": "D", "explanation": "Road signs are primarily used as precautionary devices to guide road users. They provide information about the road conditions ahead, provide directions and destinations, and enforce traffic laws. They are not primarily symbols to correct road users, signs to aid Federal Road Safety officials to apprehend defaulters, or devices to guide the traffic division of Police Command.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>15", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "In obeying traffic rules, pedestrians are to walk on the left side of the road so as to", "images": [], "options": {"A": "buy things at the roadside", "B": "see oncoming vehicles", "C": "cross at anytime", "D": "walk across junctions"}, "answer": "B", "explanation": "Pedestrians are advised to walk on the left side of the road to see oncoming vehicles. This is a safety measure that allows pedestrians to see approaching vehicles and take necessary actions to avoid accidents. It has nothing to do with buying things at the roadside, crossing at anytime or walking across junctions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>16", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Use the diagram below to answer this question      From the diagram above, activities of deviants in the society can be curtailed by", "images": ["Civic Education/imgs/2017/img1.png"], "options": {"A": "establishment of more prison", "B": "ostracizing the deviants from the society", "C": "indulging the deviants with financial incentive", "D": "strengthening reformative institutions"}, "answer": "D", "explanation": "From the diagram above, activities of deviants in the society can be curtailed by strengthening reformative institution.", "marks": "1", "difficulty": "3"}, {"id": "objective>Civic Education>2017>17", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS", "question": "Use the diagram below to answer this question    The act of the deviants in the picture above contradicts the skills of", "images": ["Civic Education/imgs/2017/img1.png"], "options": {"A": "interpersonal relationships", "B": "entrepreneurship", "C": "inter-communal relationships", "D": "resolution"}, "answer": "A", "explanation": "The act of the deviants in the picture above contradicts the skills of Inter personal relationships.", "marks": "1", "difficulty": "3"}, {"id": "objective>Civic Education>2017>18", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS", "question": "One of the skills that can be used in resolving intercommunal conflicts is", "images": [], "options": {"A": "coercion", "B": "mediation", "C": "suppression", "D": "harassment"}, "answer": "B", "explanation": "Mediation is a conflict resolution skill that can be used in resolving intercommunal conflicts. Mediation involves a neutral third party who helps the conflicting parties to reach a mutually satisfactory agreement. Coercion, suppression, and harassment are not effective conflict resolution skills as they may lead to further escalation of the conflict.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>19", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Use the dialogue below to this question   Johnson: Danladi, when are you leaving for school?  Danladi: School?  Johnson: Are you on break?  Danladi: No, but the school has been closed down due to clash between rival cult groups.  Johnson: What a terrible situation! I don't know when you are going to finish your programme. You have already spent six years in school for a four-year programme due to frequent closure and compulsory breaks. So what will you be doing at home while the closure lasted?  Danladi: Roaming the street, visiting friends and attending social functions of course.  Johnson: You better engage yourself in a productive venture such as learning a new language, entrepreneurial skills, volunteer services and so on.    From the above dialogue, it is evident that cultism disrupts activities in the", "images": [], "options": {"A": "family", "B": "school", "C": "society", "D": "club"}, "answer": "B", "explanation": "From the dialogue, it is clear that the activities being disrupted by cultism are those of the school. Danladi mentions that the school has been closed down due to clashes between rival cult groups, which has extended his four-year programme to six years. Therefore, the correct answer is 'school'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>20", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Use the dialogue below to this question   Johnson: Danladi, when are you leaving for school?  Danladi: School?  Johnson: Are you on break?  Danladi: No, but the school has been closed down due to clash between rival cult groups.  Johnson: What a terrible situation! I don't know when you are going to finish your programme. You have already spent six years in school for a four-year programme due to frequent closure and compulsory breaks. So what will you be doing at home while the closure lasted?  Danladi: Roaming the street, visiting friends and attending social functions of course.  Johnson: You better engage yourself in a productive venture such as learning a new language, entrepreneurial skills, volunteer services and so on.  From the above dialogue, which of the following is likely to happen if cultism is eradicated from our campuses?", "images": [], "options": {"A": "Uninterrupted school programme", "B": "Increase in the remuneration of staff of higher institutions", "C": "Provision of scholarships for brilliant students", "D": "Amicable resolution of disputes on campuses"}, "answer": "A", "explanation": "The dialogue suggests that the eradication of cultism would lead to an uninterrupted school programme. This is evident from Johnson's concern about Danladi's extended stay in school due to frequent closures and compulsory breaks, which are a result of the cult activities. Therefore, the correct answer is 'Uninterrupted school programme'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>21", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : REASONS FOR CULTISM", "question": "Which of the following is not responsible for cult activities in schools and colleges?", "images": [], "options": {"A": "Perceived injustice", "B": "Satisfaction of membership aspiration", "C": "Personal protection", "D": "Preservation of cultural heritage"}, "answer": "D", "explanation": "Cult activities in schools and colleges are often driven by factors such as perceived injustice, satisfaction of membership aspiration, and personal protection. However, preservation of cultural heritage is not a common reason for cult activities. Cults are often associated with negative behaviors and practices that are contrary to cultural heritage preservation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>22", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : SYMPTOMS OF DRUG ABUSE", "question": "Drug abuse often leads to", "images": [], "options": {"A": "sexually transmitted disease", "B": "cancerous illness", "C": "psychiatric disorder", "D": "incurable ailment"}, "answer": "C", "explanation": "Drug abuse can lead to a variety of health problems, including psychiatric disorders. The use of drugs can alter the brain's structure and function, leading to changes in mood, behavior, and cognitive processes. This can result in psychiatric disorders such as depression, anxiety, and psychosis. While drug abuse can also lead to sexually transmitted diseases, cancerous illnesses, and incurable ailments, these are not direct consequences of drug abuse but rather potential indirect consequences.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>23", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE", "question": "Use of hard drugs could best be curtailed through", "images": [], "options": {"A": "compensation", "B": "rehabilitation", "C": "enlightenment", "D": "compromise"}, "answer": "C", "explanation": "The use of hard drugs can best be curtailed through enlightenment. This involves educating people about the dangers and negative effects of hard drugs on their health and society at large. This is more effective than compensation or compromise, which may not address the root cause of the problem. Rehabilitation is also important, but it comes after the person has already started using drugs. Enlightenment, on the other hand, can prevent the person from starting to use drugs in the first place.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>24", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "If an individual persists in the use of hard drugs, such individual is likely to exhibit", "images": [], "options": {"A": "hostile attitude towards religious organizations", "B": "unfriendly disposition towards foreigners", "C": "oppressive behaviour", "D": "emotional illness and aggression"}, "answer": "D", "explanation": "Persistent use of hard drugs often leads to emotional illness and aggression. This is because drugs can alter the brain's structure and function, leading to changes in mood, behavior, and cognition. This can manifest as emotional instability, irritability, and aggressive behavior. The other options, such as hostile attitude towards religious organizations, unfriendly disposition towards foreigners, and oppressive behavior, are not directly linked to drug use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>25", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE", "question": "Drug abuse can best be prevented in the society by", "images": [], "options": {"A": "arresting and prosecuting drug vendors", "B": "engaging in public enlightenment", "C": "canvassing capital punishment for drug peddlers", "D": "prohibiting the sales of drugs at the motor park"}, "answer": "B", "explanation": "Public enlightenment is the best way to prevent drug abuse in society. This is because it involves educating the public about the dangers and consequences of drug abuse. It helps to change people's attitudes and behaviors towards drug use. Arresting and prosecuting drug vendors or canvassing capital punishment for drug peddlers may deter some people, but it does not address the root cause of the problem. Prohibiting the sales of drugs at the motor park is also not a comprehensive solution as drugs can be sold elsewhere.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>26", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "Which of the following people suffer most in human trafficking?", "images": [], "options": {"A": "Girls", "B": "Boys", "C": "Children", "D": "Adults"}, "answer": "C", "explanation": "Children suffer most in human trafficking. This is because they are often the most vulnerable and easy to manipulate. They are often forced into labor, sexual exploitation, and other forms of abuse. While girls, boys, and adults can also be victims of human trafficking, children are often the most affected due to their vulnerability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>27", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "Which of the following people suffer most in human trafficking?", "images": [], "options": {"A": "Girls", "B": "Boy", "C": "Children", "D": "Adults"}, "answer": "C", "explanation": "Human trafficking affects all demographics, but children are often the most vulnerable. This is due to their lack of understanding, inability to protect themselves, and the fact that they are often targeted by traffickers due to their vulnerability. Therefore, the answer is 'Children'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>28", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING", "question": "Which of the following cannot motivate human trafficking?", "images": [], "options": {"A": "Poverty", "B": "Greed", "C": "Low self-esteem", "D": "Education"}, "answer": "D", "explanation": "Education is a tool that empowers individuals and provides them with the knowledge and skills to protect themselves. It is not a motivator for human trafficking. On the contrary, it is often a deterrent. The other options, such as poverty, greed, and low self-esteem, can all contribute to the conditions that make individuals vulnerable to trafficking.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>29", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : CAUSES OF HIV/AIDS", "question": "One way of being infected with HIV/AIDS is through", "images": [], "options": {"A": "the use of unsterilized sharp objects", "B": "sitting close to HIV/AIDS infected persons", "C": "sharing clothes with AIDS/HIV infected persons", "D": "having handshake with people living with HIV/AIDS"}, "answer": "A", "explanation": "HIV/AIDS can be transmitted through the use of unsterilized sharp objects. This is because the virus can survive in the blood on these objects and infect a person if they come into contact with their bloodstream. It cannot be transmitted through casual contact such as sitting close to, sharing clothes with, or shaking hands with a person living with HIV/AIDS.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>30", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "One of the preventive measures against the infection of HIV/AIDS is", "images": [], "options": {"A": "membership of Red Cross Society", "B": "faithfulness to a partner", "C": "becoming a medical staff", "D": "membership of campaign against AIDS"}, "answer": "B", "explanation": "One of the most effective preventive measures against the infection of HIV/AIDS is being faithful to a partner. This reduces the risk of exposure to the virus through sexual contact. Membership of organizations like the Red Cross Society or a campaign against AIDS, or becoming a medical staff, while potentially beneficial in the fight against HIV/AIDS, are not direct preventive measures against the infection.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>31", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Which of the following is not a skill for practical living?", "images": [], "options": {"A": "Life coping skill", "B": "Manipulative skill", "C": "Artistic skill", "D": "Cyber crime skill"}, "answer": "D", "explanation": "Practical living skills are those skills that are essential for living independently. These include life coping skills, manipulative skills, and artistic skills. Life coping skills help individuals to handle issues and problems commonly encountered in daily life. Manipulative skills are those that require movement and coordination of the hands and fingers, and artistic skills involve creativity and the ability to create art. Cyber crime skill, however, is not a skill for practical living. It involves illegal activities using the internet and is not a skill that promotes independent and responsible living.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>32", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS", "question": "Which of the following is not a reason for self-reliance?", "images": [], "options": {"A": "Creation of employment opportunities", "B": "Innovation and creativity", "C": "Diversification of the economy", "D": "Quest for white collar jobs"}, "answer": "D", "explanation": "Self-reliance is the ability to depend on oneself for the things one needs. The reasons for self-reliance include the creation of employment opportunities, innovation and creativity, and diversification of the economy. These all contribute to personal growth and economic development. However, the quest for white collar jobs is not a reason for self-reliance. In fact, it can be seen as a reliance on others or on a particular sector of the economy, which is contrary to the concept of self-reliance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>33", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "In the constitution, the areas where both the federal and state governments exercise joint authority are on the", "images": [], "options": {"A": "residual list", "B": "concurrent list", "C": "exclusive list", "D": "reserved list"}, "answer": "B", "explanation": "In a federal system of government, the concurrent list refers to the areas where both the federal and state governments can exercise authority. This includes areas like education, agriculture, health, etc. The residual list is for the state government, the exclusive list is for the federal government, and there is no such thing as a reserved list in the constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>34", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "Government is saddled with all the following responsibilities except", "images": [], "options": {"A": "prevention of internal disturbances", "B": "protection of lives and properties", "C": "promotion of industrial development", "D": "provision of all needs of the citizens"}, "answer": "D", "explanation": "While the government is responsible for the prevention of internal disturbances, protection of lives and properties, and promotion of industrial development, it is not responsible for the provision of all needs of the citizens. This is because in a democratic society, citizens also have personal responsibilities and the government cannot cater to every individual need.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>35", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW", "question": "A major feature of representative democracy is", "images": [], "options": {"A": "free and fair election", "B": "absolute application of law", "C": "civil liberty groups", "D": "enlightened electorates"}, "answer": "A", "explanation": "A major feature of representative democracy is free and fair election. In a representative democracy, citizens elect representatives to make decisions and pass laws on behalf of all the people instead of the people deciding on laws themselves. Free and fair elections are a fundamental part of this process, ensuring that the representatives truly reflect the will of the people.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2017>36", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "A feature that distinguishes the 1979 Nigerian constitution from that of 1963 was the introduction of", "images": [], "options": {"A": "unitary system of government", "B": "republicanism", "C": "presidential system of government", "D": "westminster system"}, "answer": "C", "explanation": "The 1979 Nigerian constitution introduced the presidential system of government, which was a departure from the parliamentary system of government that was in place under the 1963 constitution. In a presidential system, the president is both the head of state and the head of government, and is separate from the legislature. This is different from a parliamentary system, where the head of state is usually a monarch or president, but the head of government is the prime minister or premier, and is a member of the legislature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>37", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "In a democracy, official opposition is allowed to", "images": [], "options": {"A": "bring down the government", "B": "pave way for military intervention", "C": "make government accountable", "D": "encourage crisis in a state"}, "answer": "C", "explanation": "In a democracy, the role of the official opposition is to hold the government accountable for its actions. They do this by scrutinizing the government's policies and actions, and by offering alternative policies. They do not have the power to bring down the government, pave way for military intervention, or encourage crisis in a state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>38", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY", "question": "The beauty of democratic system of government is that", "images": [], "options": {"A": "the President has supreme power", "B": "political power resides in the people", "C": "there is absence of exploitation", "D": "political participation is limited"}, "answer": "B", "explanation": "The beauty of a democratic system of government is that political power resides in the people. This is because in a democracy, the people are the ultimate source of political power. They exercise this power directly or through their elected representatives. The other options are not correct because in a democracy, the President does not have supreme power, there is not necessarily an absence of exploitation, and political participation is not limited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>39", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW", "question": "Use the passage below to answer this question   One morning, Mr. Ojuri was on his way to a bank in his neighbourhood to make enquiries. He was arrested for wandering and subsequently detained for seven days by the police without trial or access to his relatives.    From the above passage, it could be said that in a society where this incident happened, there is absence of", "images": [], "options": {"A": "court of law", "B": "rule of law", "C": "lawyers and solicitors", "D": "the press"}, "answer": "B", "explanation": "The rule of law is a principle that ensures that all individuals and institutions are subject to and accountable to laws that are fairly applied and enforced. In the scenario described, Mr. Ojuri was arrested and detained without trial or access to his relatives, which is a violation of his rights. This indicates an absence of the rule of law, as his rights were not protected by the law. Therefore, the correct answer is 'rule of law'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Civic Education>2017>40", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "The following can be classified as forms of political apathy except", "images": [], "options": {"A": "refusal to register and vote", "B": "lack of interest in politics", "C": "refusal to rig in an election", "D": "nonchalant attitude towards politicians"}, "answer": "C", "explanation": "Political apathy refers to a lack of interest, enthusiasm, or concern about political matters. This can manifest in various ways, such as refusal to register and vote, lack of interest in politics, or a nonchalant attitude towards politicians. However, 'refusal to rig in an election' is not a form of political apathy. Rather, it is an act of political integrity and adherence to democratic principles. Therefore, the correct answer is 'refusal to rig in an election'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>41", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "The notion of perceiving the involvement of people in politics as devilish connotes political", "images": [], "options": {"A": "demonization", "B": "apathy", "C": "degeneration", "D": "discontent"}, "answer": "A", "explanation": "The notion of perceiving the involvement of people in politics as devilish connotes political 'demonization'. Demonization in this context refers to the act of portraying something as wicked or threatening, in this case, the involvement in politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>42", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "The active involvement of people in the decision-making process in a state indicates political", "images": [], "options": {"A": "indoctrination", "B": "participation", "C": "struggle", "D": "apathy"}, "answer": "B", "explanation": "The active involvement of people in the decision-making process in a state indicates political 'participation'. Political participation refers to the actions of private citizens by which they seek to influence or support government and politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>43", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "A non-governmental organisation that allows independent initiative of citizens is known as", "images": [], "options": {"A": "civil society", "B": "pressure group", "C": "religious group", "D": "professional society"}, "answer": "A", "explanation": "A civil society is a term often used to describe the wide array of non-governmental and not-for-profit organizations that have a presence in public life, expressing the interests and values of their members or others, based on ethical, cultural, political, scientific, religious or philanthropic considerations. Civil societies are often populated by organizations such as registered charities, development non-governmental organizations, community groups, women's organizations, faith-based organizations, professional associations, trade unions, self-help groups, social movements, business associations, coalitions and advocacy groups.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>44", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "The effective way by which government can ascertain public support and reaction is through", "images": [], "options": {"A": "opinion leaders", "B": "party members", "C": "campaigns", "D": "elections"}, "answer": "D", "explanation": "Elections are the most effective way by which government can ascertain public support and reaction. Elections are a formal group decision-making process by which a population chooses an individual or multiple individuals to hold public office. They are the mechanism by which a country gauges the general public's opinion on governmental policies and actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>45", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY", "question": "The following are effects of political apathy except that it", "images": [], "options": {"A": "affects the quality of lives", "B": "leads to the enthronement of irresponsible leaders", "C": "promotes free and fair elections", "D": "ensures non-availability of dividends of democracy"}, "answer": "C", "explanation": "Political apathy refers to indifference in the attitude of citizens towards political activities. It often leads to low voter turnout and lack of political control by the people. This can result in irresponsible leaders and a lack of dividends of democracy, affecting the quality of lives. However, it does not promote free and fair elections. Instead, it can lead to unrepresentative outcomes in elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>46", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "Which of the following is the best way through which citizens can participate in the politics of their country?", "images": [], "options": {"A": "Acquisition of higher degree in political science", "B": "Standing for elective positions", "C": "Learning the arts and science of political sagacity", "D": "Undergoing mentorship under prominent political leaders"}, "answer": "B", "explanation": "Citizens can participate in the politics of their country in various ways, such as voting, standing for elective positions, joining political parties, and engaging in political discussions. Among the options provided, standing for elective positions is the most direct way of participating in politics. It allows citizens to influence political decisions and policies directly. The other options, while they can contribute to political knowledge and skills, do not necessarily involve direct participation in politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>47", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "The public service is important for ensuring", "images": [], "options": {"A": "continuity in governance", "B": "gender equality", "C": "professional equality", "D": "superiority of the pressure groups"}, "answer": "A", "explanation": "The public service is a sector of the government that ensures continuity in governance. It is the machinery of the government responsible for the implementation of laws and policies, and it continues to function regardless of changes in government. Therefore, the public service ensures continuity in governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>48", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "Political neutrality of civil servants means that they", "images": [], "options": {"A": "do not engage in partisan politics", "B": "should not be seen or heard", "C": "should not work with politicians", "D": "do not receive praises nor blames for their actions"}, "answer": "A", "explanation": "Political neutrality of civil servants means that they do not engage in partisan politics. Civil servants are expected to serve the government of the day, regardless of its political affiliation, and to implement its policies impartially. Therefore, they should not engage in partisan politics to maintain their impartiality and integrity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>49", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "The category of public service that has the closest contact with the political class is the", "images": [], "options": {"A": "manipulative class", "B": "administrative class", "C": "clerical class", "D": "technical class"}, "answer": "B", "explanation": "The administrative class in the public service has the closest contact with the political class. This is because the administrative class is responsible for implementing the policies and decisions made by the political class. They are the bridge between the political class and the rest of the public service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2017>50", "subject": "Civic Education", "year": "2017", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "In the public service, another name for red-tapism is", "images": [], "options": {"A": "theocracy", "B": "bureaucracy", "C": "autocracy", "D": "democracy"}, "answer": "B", "explanation": "In the public service, another name for red-tapism is bureaucracy. Red-tapism refers to the excessive regulation or rigid conformity to formal rules that is considered redundant or bureaucratic and hinders or prevents action or decision-making. It is usually applied to governments, corporations, and other large organizations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>1", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Members of a society are expected to adhere to societal values for the following reasons except", "images": [], "options": {"A": "Enhancement of development", "B": "Improvement of self dignity", "C": "Reduction of social vices", "D": "Relegation of morality"}, "answer": "D", "explanation": "Adhering to societal values is not expected to lead to the relegation of morality. On the contrary, societal values are often designed to uphold and promote morality. Therefore, the option 'Relegation of morality' is not a correct reason for members of a society to adhere to societal values.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>2", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "An attribute of honesty is", "images": [], "options": {"A": "Tolerance", "B": "Justice", "C": "Compromise", "D": "Liberty"}, "answer": "B", "explanation": "Honesty is closely related to justice. When a person is honest, they are fair and just in their actions and dealings with others. They do not cheat, lie, or steal, which are all actions that are considered unjust. Therefore, 'Justice' is an attribute of honesty.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>3", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "Discipline is describe as the", "images": [], "options": {"A": "ability to show hospitality", "B": "State or quality of being brave", "C": "Tendency to fight", "D": "ability to behave in a controlled manner"}, "answer": "D", "explanation": "Discipline is generally defined as the practice of training people to obey rules or a code of behavior, using punishment to correct disobedience. In other words, it is the ability to behave in a controlled manner. Therefore, the correct answer is option 4.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>4", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS", "question": "The saying, \"ask for what you can do for your country and not what your country can do for you\" denotes that", "images": [], "options": {"A": "The country owes you no obligation as a citizen", "B": "Citizens have both constitutional rights and obligations", "C": "Fundamental rights are to be safeguarded by citizens", "D": "Service and reward do not go together"}, "answer": "B", "explanation": "The saying, \"ask for what you can do for your country and not what your country can do for you\" implies that as citizens, we have both rights and obligations. It means that citizens should not only expect to receive benefits from their country but should also be ready to contribute to the betterment of the country. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>5", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "In the contemporary society, youths can display nationalistic role by showing the following attitudes except", "images": [], "options": {"A": "Discouraging corrupt practices", "B": "Exploiting the environment for the betterment of the people", "C": "Contributing to the development of the society", "D": "Showing indifference to national issues"}, "answer": "B", "explanation": "Exploiting the environment for the betterment of the people is not a nationalistic role. Nationalistic roles involve actions that promote the unity, development, and well-being of a nation. Exploiting the environment often leads to environmental degradation, which is harmful to the nation's people and its future. Therefore, this option is not a way for youths to display nationalistic roles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>6", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "The defence of the territorial integrity of a country by her citizens is part of", "images": [], "options": {"A": "Political participation", "B": "Self determination", "C": "Political culture", "D": "Duties and Obligations"}, "answer": "D", "explanation": "The defence of the territorial integrity of a country by her citizens is part of their duties and obligations. Every citizen has a responsibility to protect their country's territorial integrity, whether through military service, reporting threats, or supporting the country's defense efforts. This is a duty and obligation of citizenship, not necessarily a part of political participation, self-determination, or political culture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>7", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : ROLES OF INDIVIDUALS, GROUPS AND GOVERNMENT IN UDHR", "question": "An agency established by Federal Government of Nigeria to protect rights of citizens is", "images": [], "options": {"A": "Centre for Human Rights and Development", "B": "Human Right Watch", "C": "Legal Aid Council", "D": "Human Rights Monitor"}, "answer": "C", "explanation": "The Legal Aid Council is a parastatal of the Federal Ministry of Justice established by the Legal Aid Act 1976 to provide free legal services to Nigerian citizens who cannot afford the cost of private legal services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>8", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)", "question": "The Universal Declaration of Human Rights (UDHR) is related to", "images": [], "options": {"A": "Economic Community of West African States (ECOWAS)", "B": "United Nations Organisations (UNO)", "C": "African Union (AU)", "D": "European Union (EU)"}, "answer": "B", "explanation": "The Universal Declaration of Human Rights (UDHR) is a milestone document in the history of human rights that was proclaimed by the United Nations General Assembly in Paris on 10 December 1948.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>9", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR", "question": "The best means through which individual rights can be safeguarded is", "images": [], "options": {"A": "Knowledge acquisition", "B": "Judicial independence", "C": "Press censorship", "D": "Improved standard of living"}, "answer": "B", "explanation": "The best means through which individual rights can be safeguarded is through judicial independence. Judicial independence refers to the concept that the judiciary should be independent from the other branches of government. That is, courts should not be subject to improper influence from the other branches of government or from private or partisan interests. Judicial independence is vital and important to the idea of separation of powers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>10", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "The effect of queuing up in public places is", "images": [], "options": {"A": "Orderliness", "B": "Transparency", "C": "Honesty", "D": "Humility"}, "answer": "A", "explanation": "The effect of queuing up in public places is orderliness. Queuing up helps to maintain order and fairness in public places. It ensures that services are provided on a first-come, first-served basis, thereby preventing chaos and disorder.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>11", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "A father that effectively discharges his duty towards his children could be described as a", "images": [], "options": {"A": "Philanthropist", "B": "Celebrity", "C": "Responsible parent", "D": "Permissive father"}, "answer": "C", "explanation": "A father that effectively discharges his duty towards his children is described as a responsible parent. A responsible parent is one who takes care of the needs of his children, provides for them, and ensures their well-being. A philanthropist is someone who seeks to promote the welfare of others, typically through the donation of money. A celebrity is a famous person. A permissive father is one who allows his children to do whatever they want without setting boundaries or enforcing rules.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>12", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "A programme established to foster common ties among Nigerians is", "images": [], "options": {"A": "Subsidy Re-investment Programme (SURE-P)", "B": "Universal Basic Education (UBE)", "C": "Education Trust Fund (ETF)", "D": "National Youth Service Corps (NYSC)"}, "answer": "D", "explanation": "The National Youth Service Corps (NYSC) is a program established to foster common ties among Nigerians. It is a one-year mandatory service for all Nigerians who have graduated from tertiary institutions at home or abroad. The program aims to promote national unity and integration by posting corps members to states other than their states of origin. The Subsidy Re-investment Programme (SURE-P), Universal Basic Education (UBE), and Education Trust Fund (ETF) are all programs aimed at improving various aspects of the Nigerian society, but they do not specifically aim to foster common ties among Nigerians.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>13", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Use the dialogue below to answer this question   Ade: Uche, are you not going to work today?  Uche: I will go, but by public transport.  Ade: Why?  Uche: One of the side mirrors of my car is broken and also, the car emits excessive smoke.    Uche's action, based on the dialogue above, can help in", "images": [], "options": {"A": "Reducing road accidents.", "B": "Increasing air pollution.", "C": "Encouraging public transportation.", "D": "Ensuring vehicle's functionality."}, "answer": "A", "explanation": "From the dialogue, Uche decided not to use his car because it has a broken side mirror and it emits excessive smoke. This decision can help in reducing road accidents because a broken side mirror can limit the driver's view of the road, which can lead to accidents. Also, excessive smoke from a car can impair visibility for other road users, leading to accidents. Therefore, by not using his car, Uche is helping to reduce the possibility of road accidents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>14", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Use the dialogue below to answer this question   Ade: Uche, are you not going to work today?  Uche: I will go, but by public transport.  Ade: Why?  Uche: One of the side mirrors of my car is broken and also, the car emits excessive smoke.  An implication of Uche's action from the above dialogue is that he is", "images": [], "options": {"A": "Afraid of Federal Road Safety Corps.", "B": "Considerate of other road users.", "C": "Afraid of Civil Defence Corps.", "D": "Environmentally friendly"}, "answer": "D", "explanation": "Uche's decision to use public transport instead of his car that emits excessive smoke shows that he is environmentally friendly. Excessive smoke from vehicles contributes to air pollution, which is harmful to the environment. By choosing not to use his car until it is fixed, Uche is preventing further air pollution, thus showing consideration for the environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>15", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Use the dialogue below to answer this question   Ade: Uche, are you not going to work today?  Uche: I will go, but by public transport.  Ade: Why?  Uche: One of the side mirrors of my car is broken and also, the car emits excessive smoke.  From the above dialogue, it could be implied that Uche is mindful of", "images": [], "options": {"A": "Driving school code.", "B": "When to use public transport.", "C": "Traffic regulations.", "D": "His obligation as a citizen."}, "answer": "D", "explanation": "From the dialogue, Uche is mindful of his obligation as a citizen. This is evident from his decision to not drive his car because it has a broken side mirror and emits excessive smoke. This shows his concern for safety and environmental pollution, which are part of a citizen's obligations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>16", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS", "question": "Which of the following is not a skill for settling intercommunal conflict?", "images": [], "options": {"A": "War", "B": "Dialogue", "C": "Mediation", "D": "Arbitration"}, "answer": "A", "explanation": "War is not a skill for settling intercommunal conflict. It is rather a result of failed conflict resolution. The other options - Dialogue, Mediation, and Arbitration - are all peaceful means of resolving conflicts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>17", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS", "question": "One of the advantages of inter-communal relationship is that it ensures the", "images": [], "options": {"A": "Existence of totalitarianism", "B": "Domination of the minority by the majority", "C": "Domination of the majority by the minority", "D": "Enhancement of security"}, "answer": "D", "explanation": "Inter-communal relationships refer to the relationships between different communities. These relationships can be beneficial in many ways, one of which is the enhancement of security. When communities have good relationships with each other, they can work together to ensure the safety and security of their members. This is because they can share information and resources, and support each other in times of need. Therefore, the correct answer is 'Enhancement of security'. The other options do not accurately represent the advantages of inter-communal relationships.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>18", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS", "question": "Which of the following skills negates the promotion of interpersonal relationship?", "images": [], "options": {"A": "Tolerance", "B": "Selfishness", "C": "Caring", "D": "Kindness"}, "answer": "B", "explanation": "Interpersonal relationships are relationships between individuals. These relationships can be enhanced by positive traits such as tolerance, caring, and kindness. However, selfishness is a trait that can negatively affect interpersonal relationships. When a person is selfish, they prioritize their own needs and wants over those of others. This can lead to conflict and tension in relationships. Therefore, the correct answer is 'Selfishness'. The other options are traits that would promote, not negate, interpersonal relationships.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>19", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Use the cartoon below to answer questions       The cartoon is an evidence that cultism is", "images": ["Civic Education/imgs/2018/img1.png"], "options": {"A": "violent in nature.", "B": "terrorist in nature.", "C": "martial in nature.", "D": "Militant in nature."}, "answer": "A", "explanation": "Cultism is Violent in nature. This is the most appropriate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>20", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Use the cartoon below to answer questions     What does the boy need the bullet proof vest for?", "images": ["Civic Education/imgs/2018/img1.png"], "options": {"A": "Demonstration", "B": "Protection", "C": "Battle", "D": "Vengeance"}, "answer": "B", "explanation": "Bullet proof vest is needed for protection. This is the most appropriate answer", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>21", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Use the cartoon below to answer questions     It could be inferred from the cartoon that the activities of cult groups on campus may not be reduced by", "images": ["Civic Education/imgs/2018/img1.png"], "options": {"A": "Religious Instruction", "B": "Campaign against cultism", "C": "Relevant legislation", "D": "Bullet proof vest"}, "answer": "D", "explanation": "Bullet proof vest can not reduced the activities of cult group on campus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>22", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : HOW DRUGS ARE ABUSED", "question": "Which of the following is not a common way by which people abuse drugs?", "images": [], "options": {"A": "Ingestion", "B": "Intrusion", "C": "Inhalation", "D": "Injection"}, "answer": "B", "explanation": "Drug abuse refers to the misuse of substances, especially drugs or alcohol, for purposes such as achieving calming or euphoric effects, to the detriment of one's health. The common ways by which people abuse drugs include ingestion (taking by mouth), inhalation (breathing in), and injection (directly into the bloodstream). Intrusion is not a recognized method of drug abuse.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>23", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "The establishment of the National Drug Law Enforcement Agency (NDLEA)", "images": [], "options": {"A": "Make drugs available to the masses", "B": "prevent drug abuse", "C": "encourage the use of drug by the masses", "D": "Support importation of drugs"}, "answer": "B", "explanation": "The National Drug Law Enforcement Agency (NDLEA) is a Federal agency in Nigeria charged with eliminating the growing, processing, manufacturing, selling, exporting, and trafficking of hard drugs. The agency was established by Decree Number 48 of 1989. The NDLEA is present in international airports, seaports and border crossing. It tries to eradicate cannabis by destroying plantings. The NDLEA also targets the leaders of narcotics and money laundering organizations. Its aim is to prevent drug abuse, not to make drugs available to the masses, encourage the use of drugs by the masses, or support the importation of drugs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>24", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : SYMPTOMS OF DRUG ABUSE", "question": "A common repercussion for drug abuse is", "images": [], "options": {"A": "Medication", "B": "Rehabilitation", "C": "Brain drain", "D": "Memory loss"}, "answer": "D", "explanation": "Drug abuse often leads to various health issues, including memory loss. This is because drugs can alter important brain areas that are necessary for life-sustaining functions and can drive the compulsive drug abuse that marks addiction. Brain changes that occur over time with drug use challenge an addicted person's self-control and interfere with their ability to resist intense impulses to take drugs. Hence, memory loss is a common repercussion for drug abuse.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>25", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE", "question": "Which of the following is a way of preventing drug trafficking?", "images": [], "options": {"A": "Foreign scholarship", "B": "Employment", "C": "Motivation", "D": "Indulging offenders"}, "answer": "B", "explanation": "Employment can be a way of preventing drug trafficking. When people are gainfully employed, they are less likely to engage in illegal activities such as drug trafficking. Employment provides a means of livelihood and reduces the economic incentive to engage in drug trafficking. None of the other options provided (Foreign scholarship, Motivation, Indulging offenders) directly prevent drug trafficking.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>26", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "A major consequence of human trafficking is", "images": [], "options": {"A": "Promotion of rural-urban drift.", "B": "Decline in literacy rate.", "C": "Increased rate of youth employment.", "D": "Increased exploitation of the ignorant."}, "answer": "D", "explanation": "Human trafficking often leads to the exploitation of the ignorant. Victims are often deceived or coerced into situations where they are exploited for labor, sexual purposes, or other forms of servitude. This exploitation is a major consequence of human trafficking. The other options do not directly relate to the consequences of human trafficking.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>27", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "Human trafficking results into all the following except", "images": [], "options": {"A": "Prostitution", "B": "Migration", "C": "Criminality", "D": "Welfarism"}, "answer": "D", "explanation": "Welfarism is not a result of human trafficking. Welfarism refers to the system in which the welfare of the citizens is the responsibility of the state. Human trafficking, on the other hand, is a criminal activity that involves the illegal trade of people for exploitation or commercial gain. The other options, prostitution, migration, and criminality, can be results of human trafficking.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>28", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "The group of individuals in the society that is mostly prone to human trafficking are", "images": [], "options": {"A": "Women and children", "B": "Youths, women and men", "C": "Men and vulnerable children", "D": "Old and weak individuals"}, "answer": "A", "explanation": "Human trafficking is a serious crime and a grave violation of human rights. Every year, thousands of men, women and children fall into the hands of traffickers, in their own countries and abroad. However, women and children are the most vulnerable and are often the primary targets of human trafficking due to their perceived lack of power and their marginalized status in many societies. This makes them more susceptible to manipulation and coercion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>29", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "An enlightenment and awareness campaign on HIV/AIDS could", "images": [], "options": {"A": "lead to discrimination", "B": "Create job opportunities", "C": "cause conflict", "D": "Provide people with genuine information"}, "answer": "D", "explanation": "An enlightenment and awareness campaign on HIV/AIDS is designed to provide people with genuine information about the disease, its causes, prevention methods, and treatment options. This helps to dispel myths and misconceptions about the disease, reduce stigma and discrimination, and promote safe practices. It does not lead to discrimination or cause conflict, and while it may create job opportunities in the health and social work sectors, this is not its primary purpose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>30", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "Which of these is not a form of stigmatization?", "images": [], "options": {"A": "Refusal to interact with family of an HIV patient", "B": "Physical and verbal abuse of HIV/AIDS patient", "C": "Ostracising HIV patient", "D": "Enlighening people living with HIV/AIDS"}, "answer": "D", "explanation": "Stigmatization refers to the act of discriminating or treating someone unfairly due to their condition or status. Enlightening people living with HIV/AIDS is not a form of stigmatization, but rather a positive action aimed at providing them with necessary information and support.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>31", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "Testing of blood before transfusion will greatly help to", "images": [], "options": {"A": "Spread HIV", "B": "Control HIV", "C": "Eradicate HIV", "D": "Prevent HIV"}, "answer": "D", "explanation": "Testing of blood before transfusion is a preventive measure to ensure that the blood to be transfused is not infected with HIV. This helps to prevent the spread of HIV.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>32", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS", "question": "From the above report, which of the following is the major consequence of the intervention programme?", "images": [], "options": {"A": "Increase in self-reliance skills", "B": "Promotion of intercommunal relation", "C": "Provision of infrastructural facilities", "D": "Acceleration of national development"}, "answer": "D", "explanation": "The question refers to a report that is not provided, making it impossible to determine the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>33", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING", "question": "From the above report, a probable reason for the initial high crime rate in in Aikara community was", "images": [], "options": {"A": "Poor upbringing", "B": "Corruption", "C": "Abject poverty", "D": "Greed"}, "answer": "C", "explanation": "The question refers to a report that is not provided, making it impossible to determine the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>34", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "One of the functions of local government is", "images": [], "options": {"A": "Settlement of intra-party crisis", "B": "Making of bye-laws", "C": "Formulation of monetary policies", "D": "Delimitation of constituencies"}, "answer": "B", "explanation": "The function of local government includes making of bye-laws. Bye-laws are laws that are made by a local authority and apply only within its particular area. They are used to deal with issues that are of local concern, such as regulating businesses, controlling land use, or managing public health and safety.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>35", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "A body established and entrusted with power and authority to direct the affairs of a state is called", "images": [], "options": {"A": "Federal Executive Council", "B": "State Legislative Council", "C": "Trusteeship", "D": "Government"}, "answer": "D", "explanation": "A body established and entrusted with power and authority to direct the affairs of a state is called a Government. The government is the governing body of a nation, state, or community. It is responsible for the creation of laws, the enforcement of laws, and the protection of the state and its citizens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>36", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW", "question": "Which of the following concepts can guarantee adherence to the rule of law?", "images": [], "options": {"A": "Political immunity", "B": "Political gerrymandering", "C": "National development", "D": "Representative democracy"}, "answer": "D", "explanation": "The concept that can guarantee adherence to the rule of law is 'Representative democracy'. In a representative democracy, citizens elect representatives to make laws and decisions on their behalf, ensuring that the rule of law is upheld. Political immunity and political gerrymandering do not guarantee adherence to the rule of law. National development is a broad concept that includes adherence to the rule of law, but it is not a concept that can guarantee it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>37", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "According to the 1999 constitution sovereignty resides in the", "images": [], "options": {"A": "Commander-in-Chief of the Armed Forces.", "B": "People who confer legitimacy on elected leaders.", "C": "National Assembly which has power to make laws and amend the constitution.", "D": "Military which can declare any law null, void and of no effect."}, "answer": "B", "explanation": "According to the 1999 constitution, sovereignty resides in the 'People who confer legitimacy on elected leaders'. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In a democratic society, the people are the source of sovereignty. They confer legitimacy on elected leaders through the process of voting. The other options do not correctly represent where sovereignty resides according to the constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>38", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "In a democratic government, franchise is given to all", "images": [], "options": {"A": "Party members.", "B": "Resident adults.", "C": "Adult citizens.", "D": "Opinion leaders."}, "answer": "C", "explanation": "In a democratic government, franchise, which is the right to vote, is given to all adult citizens. This is because democracy is a system of government where citizens exercise power by voting. Therefore, all adult citizens are given the right to vote irrespective of their party affiliation, residency status, or influence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>39", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW", "question": "A Significant companion of the rule of law is the", "images": [], "options": {"A": "Fusion of legislative and executive functions", "B": "Supremacy of the ordinary law", "C": "Adoption of one party system", "D": "Enforcement of law by the legislature"}, "answer": "B", "explanation": "A significant companion of the rule of law is the supremacy of the ordinary law. The rule of law is a principle that all people and institutions are subject to and accountable to law that is fairly applied and enforced. Therefore, the supremacy of the ordinary law means that no individual or government is above the law, and all are subject to the same laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>40", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF RULE OF LAW", "question": "Operation of the rule of law could be undermined by the", "images": [], "options": {"A": "Existence of civil society groups.", "B": "Existence of free press.", "C": "Establishment of administrative tribunals.", "D": "Encouragement of effective opposition."}, "answer": "C", "explanation": "The rule of law is a principle that ensures that all individuals and institutions are subject to and accountable to laws that are fairly applied and enforced. The establishment of administrative tribunals can undermine the operation of the rule of law because they can make decisions without the same level of scrutiny and accountability as a court of law. This can lead to arbitrary or unfair decisions. The other options, such as the existence of civil society groups and free press, and the encouragement of effective opposition, are generally seen as supporting the rule of law, not undermining it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>41", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Use the dialogue below to answer this question   Ini: The recent Constitution Conference organized by federal government gulped a lot of money.  Emem: That type of conference can only happen where there is a democratic governance which permits respect for all shades of opinion.  Ini: So, the federal government cannot solely take decisions and ratify them?  Emem: No, that will negate the fundamental principles of democracy.    The above dialogue shows that democracy could result into", "images": [], "options": {"A": "Inefficiency", "B": "Corruption", "C": "Absolute liberty", "D": "High cost of governance"}, "answer": "D", "explanation": "The dialogue between Ini and Emem discusses the cost of a Constitution Conference organized by the federal government. Emem explains that such a conference, which allows for a variety of opinions to be heard, is a characteristic of democratic governance. However, this can lead to a high cost of governance, as it requires resources to facilitate such processes. Therefore, the dialogue suggests that democracy could result in a high cost of governance. The other options, such as inefficiency, corruption, and absolute liberty, are not directly suggested by the dialogue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>42", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Use the dialogue below to answer this question   Ini: The recent Constitution Conference organized by federal government gulped a lot of money.  Emem: That type of conference can only happen where there is a democratic governance which permits respect for all shades of opinion.  Ini: So, the federal government cannot solely take decisions and ratify them?  Emem: No, that will negate the fundamental principles of democracy.  It could be inferred from the dialogue above that democracy encourages", "images": [], "options": {"A": "Tolerance", "B": "Development", "C": "Job creation", "D": "Delegated legislation"}, "answer": "A", "explanation": "From the dialogue, it can be inferred that democracy encourages 'Tolerance'. This is because Emem mentions that a democratic governance permits respect for all shades of opinion, which is a form of tolerance. Tolerance in this context refers to the acceptance of differing views and opinions, which is a fundamental principle of democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>43", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "The most suitable form of democracy for a small village or community is", "images": [], "options": {"A": "Constitution democracy", "B": "Indirect democracy", "C": "Communal democracy", "D": "Direct democracy"}, "answer": "D", "explanation": "The most suitable form of democracy for a small village or community is 'Direct democracy'. In a direct democracy, all members of the community have the right to participate in decision-making processes. This is more feasible in smaller communities where it is easier to gather all members for discussions and decisions. In contrast, indirect or representative democracy is more suitable for larger societies where it is impractical for everyone to participate directly in decision-making.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>44", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY", "question": "Which of the following is not a major reason for political apathy?", "images": [], "options": {"A": "Political violence", "B": "Unfulfilled political promises", "C": "Bad governance", "D": "Cross carpeting phenomenon"}, "answer": "D", "explanation": "Political apathy refers to the indifference in attitude of the citizens towards political activities. It's often caused by factors such as political violence, unfulfilled political promises, and bad governance. However, cross carpeting phenomenon, which refers to the act of switching from one political party to another, is not a major reason for political apathy. It's more of a political strategy used by politicians rather than a cause for citizens' indifference towards politics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>45", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "The Chapter IV of the 1999 constitution of Nigeria is about", "images": [], "options": {"A": "Composition of the National Assembly", "B": "Fundamental human rights", "C": "Procedures for the impeachment of the president", "D": "Formation of quorum in the Senate"}, "answer": "B", "explanation": "The Chapter IV of the 1999 constitution of Nigeria is about Fundamental Human Rights. These rights are guaranteed to all citizens and they include rights such as the right to life, right to dignity of human person, right to personal liberty, right to fair hearing, right to private and family life, right to freedom of thought, conscience and religion, right to freedom of expression and the press, etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>46", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY", "question": "Which of the following may prevent a citizen from voting in a general election?", "images": [], "options": {"A": "Lack of stable income", "B": "High cost of living", "C": "Non-registration", "D": "Political neutrality"}, "answer": "C", "explanation": "A citizen may be prevented from voting in a general election if they have not registered to vote. Registration is a prerequisite for voting in many countries. It is the process where eligible citizens of a country indicate their intention to vote in an election by having their names, and often other identifying information, entered in a register (also known as electoral roll). This ensures that only eligible citizens vote in an election. Therefore, non-registration can prevent a citizen from voting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>47", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "An organised group that is independent of the state could be described as", "images": [], "options": {"A": "Civil defence", "B": "Pressure group", "C": "Community group", "D": "Civil society"}, "answer": "D", "explanation": "A civil society is an organized group that is independent of the state. It refers to the space for collective action around shared interests, purposes and values, generally distinct from government and commercial for-profit actors. Civil society includes charities, development NGOs, community groups, women's organizations, faith-based organizations, professional associations, trade unions, social movements, coalitions and advocacy groups.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>48", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "The smooth operation of the Public Service in Nigeria is being hampered by", "images": [], "options": {"A": "Debt burden", "B": "Adequate training", "C": "Privatization policy", "D": "Bribery and corruption"}, "answer": "D", "explanation": "The smooth operation of the Public Service in Nigeria is being hampered by bribery and corruption. This is because corruption leads to inefficiency, misappropriation of public funds, and a lack of accountability, which hampers the smooth operation of the public service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2018>49", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "The Public Service can perform all these functions except", "images": [], "options": {"A": "Advise government on policy formulation", "B": "keeping of government records", "C": "Provision of social services", "D": "budget approval for implementation"}, "answer": "D", "explanation": "The Public Service can perform all these functions except budget approval for implementation. The approval of the budget for implementation is the responsibility of the legislative arm of government, not the public service. The public service can advise on policy formulation, keep government records, and provide social services, but it does not have the power to approve budgets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2018>50", "subject": "Civic Education", "year": "2018", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : MEANING OF PUBLIC SERVICE", "question": "The highest class in the Public Service in Nigeria is the", "images": [], "options": {"A": "Clerical", "B": "Manipulative", "C": "Technical", "D": "Administrative"}, "answer": "D", "explanation": "The highest class in the Public Service in Nigeria is the Administrative class. The Public Service is a hierarchical system and the Administrative class is at the top of this hierarchy. They are responsible for making key decisions and implementing policies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>1", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "Fundamental rights are literally the rights that one can enjoy because one is", "images": [], "options": {"A": "an individual.", "B": "a human being.", "C": "a citizen,", "D": "an educated elite."}, "answer": "B", "explanation": "Fundamental rights are the basic human rights that every individual is entitled to because they are a human being. These rights are inherent and not dependent on factors such as citizenship or education.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>2", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY", "question": "Which of the following nationalists is associated with democratic socialism?", "images": [], "options": {"A": "Ahmadu Bello", "B": "Tafawa Balewa", "C": "Anthony Enahoro", "D": "Obafemi Awolowo"}, "answer": "D", "explanation": "Obafemi Awolowo is associated with democratic socialism. He was a Nigerian nationalist and statesman who played a key role in Nigeria's independence movement, the First and Second Republics and the Civil War. He was the first premier of the Western Region and later federal commissioner for finance, and he was thrice a major contender for his country's highest office. Awolowo was one of the principal participants in the country's formative political and constitutional development. He was the leader of the Action Group party that implemented free primary education in the Western Region and established the first television service in Africa in 1959.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>3", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "When a person is being fair, impartial and reasonable in dealing with others, such person is said to be", "images": [], "options": {"A": "responsible.", "B": "tolerant.", "C": "honest.", "D": "humble."}, "answer": "B", "explanation": "When a person is being fair, impartial and reasonable in dealing with others, such person is said to be tolerant. Tolerance is the ability or willingness to tolerate the existence of opinions or behavior that one dislikes or disagrees with. It involves respecting the rights and beliefs of others, even if they are different from our own. It is a key aspect of good citizenship and a peaceful society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>4", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS", "question": "A limitation to the exercise of human right is", "images": [], "options": {"A": "war", "B": "deportation", "C": "migration", "D": "HIV/AIDS"}, "answer": "A", "explanation": "A limitation to the exercise of human rights can be war. During war, certain rights such as the right to movement, right to assembly, and even right to life can be infringed upon. This is because during war, the primary focus is usually on survival and victory, rather than the protection of individual rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>5", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : MEANING OF CONSTITUTED AUTHORITY", "question": "Which of the following is not among the sources of authority?", "images": [], "options": {"A": "Societal", "B": "Traditional", "C": "Rational Legal", "D": "Charismatic"}, "answer": "C", "explanation": "Rational Legal is not a source of authority. The sources of authority are typically Traditional, Charismatic, and Legal-rational. Traditional authority is based on established belief in the sanctity of immemorial traditions and the legitimacy of the status of those exercising authority under them. Charismatic authority is power legitimized by the level of devotion of the followers for the leader. Legal-rational authority is power legitimized by legally enacted rules and regulations such as governments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>6", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Orderliness can be exhibited in the following ways except", "images": [], "options": {"A": "observing the traffic lights.", "B": "queuing culture.", "C": "decorum behaviour.", "D": "interrupting an individual."}, "answer": "D", "explanation": "Orderliness is about maintaining a sense of organization and discipline in one's activities or behavior. It involves following rules, regulations, and societal norms. Options 1, 2, and 3 are all examples of orderliness as they involve following rules or norms (traffic lights, queuing, and decorum behavior). However, option 4, 'interrupting an individual', is not an example of orderliness. It is generally considered rude and disruptive to interrupt someone, which goes against the concept of orderliness.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>7", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "Which of the following is a way of achieving responsible parenthood?", "images": [], "options": {"A": "Commitment", "B": "Patriotism", "C": "Favouritism", "D": "Goodness"}, "answer": "A", "explanation": "Responsible parenthood involves various aspects, including providing for the physical, emotional, and social needs of children. This requires a high level of commitment from parents. Therefore, option 1, 'Commitment', is the correct answer. The other options, 'Patriotism', 'Favouritism', and 'Goodness', while they may be desirable qualities, are not directly related to the concept of responsible parenthood.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>8", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "A citizen is someone who", "images": [], "options": {"A": "holds a chieftaincy title in the country.", "B": "is a legal member of the country.", "C": "has lived in the country for a long time.", "D": "is a staunch supporter of the country's development."}, "answer": "B", "explanation": "A citizen is a person who is legally recognized as a member of a state or country. The person has the rights and protection of that state or country. The person can also be a native or naturalized member of a state, nation, or country, who owes allegiance to its government and is entitled to its protection.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>9", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Incidences of broken home and irresponsible parenthood are the major causes of the following except", "images": [], "options": {"A": "unhealthy growth.", "B": "armed robbery.", "C": "migration.", "D": "cultism."}, "answer": "C", "explanation": "Broken homes and irresponsible parenthood can lead to a variety of social problems, including unhealthy growth, armed robbery, and cultism. However, migration is not directly caused by broken homes or irresponsible parenthood. Migration can be caused by a variety of factors, including economic opportunities, political instability, and environmental factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>10", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION", "question": "Citizenship education will not help to achieve which of the following?", "images": [], "options": {"A": "National unity", "B": "Education of the youth", "C": "Moral decadence", "D": "Promoting democracy"}, "answer": "C", "explanation": "Citizenship education is a type of education that teaches individuals about their rights, responsibilities, and duties as citizens. It also promotes values such as national unity, democracy, and the importance of education. However, it does not directly address moral decadence. Moral decadence refers to the decline in moral standards, which is a societal issue that needs to be addressed through various means, not just through citizenship education.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>11", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Use the story to answer this question  One fateful morning, Imasuen was going to school. A few distance away from the school gate, he saw an accident victim writhing in severe pain by the road side. The accident victim was hit by a motorcycle rider and left half-dead. Although Imasuen was already late for school, he decided to convey the victim to a nearby hospital before reporting the matter to a nearby police station.    From the story above, it could be said that Imasuen have demonstrated", "images": [], "options": {"A": "honesty", "B": "fair play", "C": "tolerance", "D": "selflessness"}, "answer": "D", "explanation": "From the story, Imasuen demonstrated selflessness. Selflessness is the quality of caring more about other people than about oneself. Despite being late for school, Imasuen decided to help the accident victim, showing that he cared more about the victim's wellbeing than his own convenience. This act of putting others before oneself is a clear demonstration of selflessness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>12", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Use the story to answer this question  One fateful morning, Imasuen was going to school. A few distance away from the school gate, he saw an accident victim writhing in severe pain by the road side. The accident victim was hit by a motorcycle rider and left half-dead. Although Imasuen was already late for school, he decided to convey the victim to a nearby hospital before reporting the matter to a nearby police station.  The behaviour of the motorcycle rider in the above story depicts", "images": [], "options": {"A": "arrogance.", "B": "unruly attitude.", "C": "cruelty.", "D": "aggressive behaviour."}, "answer": "C", "explanation": "The behavior of the motorcycle rider in the story depicts 'cruelty'. This is because the rider hit a person and left them half-dead without offering any help or reporting the incident. This act of indifference and lack of empathy towards the victim's suffering is a clear indication of cruelty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>13", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Use the story to answer this question  One fateful morning, Imasuen was going to school. A few distance away from the school gate, he saw an accident victim writhing in severe pain by the road side. The accident victim was hit by a motorcycle rider and left half-dead. Although Imasuen was already late for school, he decided to convey the victim to a nearby hospital before reporting the matter to a nearby police station.  The behaviour of Imasuen in the story above can help promote all the following except", "images": [], "options": {"A": "orderliness.", "B": "peaceful coexistence.", "C": "punctuality.", "D": "stability."}, "answer": "C", "explanation": "The behavior of Imasuen in the story promotes orderliness, peaceful coexistence, and stability as he showed empathy, responsibility, and care for the victim. However, it does not promote punctuality. In the story, Imasuen was already late for school and he decided to help the victim instead of going to school on time. Therefore, his actions, while commendable, did not promote punctuality.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>14", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM", "question": "Nationalism is a product of all the following features except", "images": [], "options": {"A": "cultural similarity", "B": "social complexity", "C": "shared interest", "D": "historical association."}, "answer": "B", "explanation": "Nationalism is a political ideology that involves a strong identification of a group of individuals with a political entity defined in national terms, i.e. a nation. It is often associated with the belief that a particular nation should be autonomous, and its people should have a shared interest, cultural similarity, and historical association. However, social complexity, which refers to the differentiation in social roles, status, and access to resources among members of a society, is not a product of nationalism. In fact, it can sometimes challenge the unity and homogeneity that nationalism seeks to promote.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>15", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "Trafficked individuals are likely to have been", "images": [], "options": {"A": "corrupt and greedy.", "B": "traumatized and stigmatized.", "C": "dangerous and heartless.", "D": "hardworking and courageous."}, "answer": "B", "explanation": "Human trafficking is a serious crime and a grave violation of human rights. Every year, thousands of men, women and children fall into the hands of traffickers, in their own countries and abroad. Trafficked individuals are often subjected to physical and emotional abuse, which can lead to trauma and stigmatization. The other options do not accurately describe the likely state of trafficked individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>16", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : DRUGS THAT CAN BE ABUSED", "question": "The drug usually referred to as marijuana is", "images": [], "options": {"A": "cannabis.", "B": "cocaine,", "C": "caffeine.", "D": "heroin."}, "answer": "A", "explanation": "Marijuana is a common name for cannabis, a psychoactive drug from the Cannabis plant. It is used for medical or recreational purposes. The other options listed, cocaine, caffeine, and heroin, are different substances and not referred to as marijuana.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>17", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "The process of acquisition of necessary skills by young people for national development is known as", "images": [], "options": {"A": "sponsorship.", "B": "encouragement.", "C": "motivation.", "D": "empowerment."}, "answer": "D", "explanation": "The process of acquisition of necessary skills by young people for national development is known as empowerment. Empowerment refers to the process of becoming stronger and more confident, especially in controlling one's life and claiming one's rights. It often involves the empowered developing confidence in their own capacities. The other options, sponsorship, encouragement, and motivation, are not processes of acquiring skills.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>18", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "The Federal Road Safety Corps (FRSC) carries out all these functions except", "images": [], "options": {"A": "construction of motorable roads.", "B": "effective patrol operation.", "C": "inspection of vehicles.", "D": "prompt rescue mission."}, "answer": "A", "explanation": "The Federal Road Safety Corps (FRSC) is a Para-military organization and the lead agency in Nigeria on road safety administration and management. The statutory functions include: Making the highways safe for motorists and other road users as well as checking road worthiness of vehicles, educating motorists and members of the public on the importance of road discipline on the highways, and providing prompt rescue services on the highways. However, the construction of motorable roads is not part of their duties. This is typically the responsibility of government agencies like the Federal Ministry of Works or state Public Works Departments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>19", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "The inalienable entitlement of an individual in a society are known as", "images": [], "options": {"A": "basic necessities.", "B": "natural justice.", "C": "fundamental freedom.", "D": "human rights."}, "answer": "D", "explanation": "The inalienable entitlements of an individual in a society are known as human rights. Human rights are rights inherent to all human beings, regardless of race, sex, nationality, ethnicity, language, religion, or any other status. They include the right to life and liberty, freedom from slavery and torture, freedom of opinion and expression, the right to work and education, and many more. Everyone is entitled to these rights, without discrimination.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>20", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : MEANING AND ORIGIN OF CULTISM", "question": "Membership of an organization that is characterized by secrecy of operations is associated with", "images": [], "options": {"A": "activism.", "B": "cultism.", "C": "radicalism.", "D": "spiritism."}, "answer": "B", "explanation": "Cultism is often characterized by secrecy of operations. Cults usually operate in a clandestine manner, with their activities hidden from non-members. This is to maintain the exclusivity of the group and to avoid detection by law enforcement agencies. Activism, radicalism, and spiritism do not necessarily involve secrecy of operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>21", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY", "question": "The inability of citizens of a country to freely elect their leaders is a threat to", "images": [], "options": {"A": "federalism.", "B": "totalitarianism.", "C": "oligarchy.", "D": "democracy."}, "answer": "D", "explanation": "The inability of citizens to freely elect their leaders is a threat to democracy. Democracy is a system of government where citizens have the power to elect their leaders in free and fair elections. If citizens are unable to do this, it undermines the democratic process. Federalism, totalitarianism, and oligarchy are different forms of government and are not directly threatened by the inability of citizens to elect their leaders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>22", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "Being faithful in marriage can greatly assist to prevent", "images": [], "options": {"A": "unhealthy growth.", "B": "extravagancy.", "C": "hatred.", "D": "HIV infection."}, "answer": "D", "explanation": "Being faithful in marriage can greatly assist to prevent HIV infection. This is because HIV can be transmitted through sexual intercourse with an infected person. Therefore, being faithful to one's partner reduces the risk of exposure to the virus.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>23", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Which of the following is a punitive measure against cultism?", "images": [], "options": {"A": "Counselling and enlightenment in school", "B": "A true and sincere religious inculcation", "C": "Arrest and prosecution of suspects", "D": "Good parental responsibility and care"}, "answer": "C", "explanation": "A punitive measure is a form of punishment imposed for breaking a law or rule. In the context of cultism, the most direct punitive measure would be the arrest and prosecution of suspects. This is because it directly punishes those involved in cultism and serves as a deterrent for others. Counselling, religious inculcation, and good parental responsibility are preventive measures, not punitive measures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>24", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Use the image in Figure 1 to answer this question      The road sign in Figure 1 indicates", "images": ["Civic Education/imgs/2019/img1.png"], "options": {"A": "move ahead", "B": "stop ahead", "C": "speed limit", "D": "wait a bit"}, "answer": "A", "explanation": "The road sign in figure I indicates move ahead. This is the most appropriate answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>25", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Authorized road users include the following except", "images": [], "options": {"A": "pedestrians.", "B": "bicycle riders.", "C": "roller skaters.", "D": "tricycle riders."}, "answer": "C", "explanation": "Authorized road users are those who are legally allowed to use the road. This includes pedestrians, bicycle riders, and tricycle riders. Roller skaters are not typically considered authorized road users because they can pose a safety risk to themselves and others on the road. Therefore, the correct answer is 'roller skaters'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>26", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "Which of the following is not a function of the judicial arm of government?", "images": [], "options": {"A": "Implementation of the law", "B": "Pronouncement of punishment", "C": "Adjudication of cases", "D": "Interpretation of the law"}, "answer": "A", "explanation": "The judicial arm of government is responsible for the interpretation of the law, adjudication of cases, and pronouncement of punishment. It does not implement the law. That is the function of the executive arm of government. Therefore, the correct answer is 'Implementation of the law'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>27", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "Trafficked children are likely to experience all the following except", "images": [], "options": {"A": "empowerment.", "B": "prostitution.", "C": "forced labour.", "D": "unwanted pregnancy."}, "answer": "A", "explanation": "Child trafficking is a form of child abuse where children are recruited, moved or transported and then exploited, forced to work or sold. The experiences of trafficked children are often of severe abuse, exploitation, and violence. Empowerment, which is the process of becoming stronger and more confident, especially in controlling one's life and claiming one's rights, is not a likely experience for trafficked children. Therefore, the correct answer is 'empowerment'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>28", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "Which of the following is not a way of promoting national consciousness?", "images": [], "options": {"A": "Inter-school debate", "B": "Multicultural education", "C": "Sporting festivals", "D": "Compensatory mechanism"}, "answer": "D", "explanation": "National consciousness is a form of collective consciousness that is directed towards the nation. It involves a strong identification with the nation and a shared understanding of the nation's history, present, and future. Ways of promoting national consciousness include inter-school debates, multicultural education, and sporting festivals, which all foster a sense of unity, shared identity, and understanding. However, a compensatory mechanism, which is a psychological strategy whereby a person makes up for a deficiency in one area by excelling or overachieving in another, does not directly contribute to promoting national consciousness. Therefore, the correct answer is 'Compensatory mechanism'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>29", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The totality of legislative, executive and judicial powers constitutes", "images": [], "options": {"A": "sovereignty.", "B": "authority.", "C": "state.", "D": "government."}, "answer": "A", "explanation": "The totality of legislative, executive and judicial powers constitutes sovereignty. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. It is a basic principle underlying the dominant Westphalian model of state foundation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>30", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL RELATIONSHIPS", "question": "Use the passage below to answer this question  Ate and Ube are two towns that have lived peacefully in the past years. Last year, they met and decided to build a hospital and raised fund towards the project. Everyone played his/her part to see that the completion of the project becomes a reality. The project was completed within six months.    What existed between Ate and Ube towns can best be termed", "images": [], "options": {"A": "boldness.", "B": "commitment.", "C": "courage.", "D": "co-operation."}, "answer": "D", "explanation": "The relationship between Ate and Ube towns can best be termed as co-operation. This is because they worked together in harmony to achieve a common goal, which was the completion of the hospital project. Co-operation refers to the process of groups of organisms working or acting together for common, mutual, or some underlying benefit, as opposed to working in competition for selfish benefit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>31", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS", "question": "Use the passage below to answer this question  Ate and Ube are two towns that have lived peacefully in the past years. Last year, they met and decided to build a hospital and raised fund towards the project. Everyone played his/her part to see that the completion of the project becomes a reality. The project was completed within six months.  The relationship that existed between Ate and Ube towns will lead to all the following except", "images": [], "options": {"A": "promotion of harmony", "B": "unification", "C": "stunted development", "D": "achievement of goals"}, "answer": "C", "explanation": "The relationship between Ate and Ube towns is described as peaceful and cooperative, with both towns working together to build a hospital. This kind of relationship would likely promote harmony and unification, and help them achieve their goals. However, there is no reason to believe it would lead to stunted development. In fact, the successful completion of the hospital project suggests the opposite.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>32", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : REASONS FOR CULTISM", "question": "Which of the following categories of students will not likely be a major target of campus cult membership recruitment?", "images": [], "options": {"A": "Proud children from wealthy homes", "B": "Students with influential parents", "C": "Bold and morally upright children", "D": "Wayward and fun-loving students."}, "answer": "C", "explanation": "Campus cults often target individuals who are likely to be influenced or manipulated easily. This includes proud children from wealthy homes, students with influential parents, and wayward and fun-loving students. Bold and morally upright children, on the other hand, are less likely to be targeted for recruitment by campus cults because they are more likely to resist such influences and stand up for what is right.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>33", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "What do human traffickers use to instil fear into their victims?", "images": [], "options": {"A": "Confrontation", "B": "Intimidation", "C": "Elimination", "D": "Exploitation"}, "answer": "B", "explanation": "Human traffickers often use intimidation to instil fear into their victims. This can involve threats of violence, manipulation, and other forms of psychological control. Intimidation is a tactic used to control and exploit victims, making them more compliant and less likely to seek help.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>34", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "The origin of democracy is traced to the", "images": [], "options": {"A": "Romans", "B": "Greeks", "C": "Egyptians", "D": "British"}, "answer": "B", "explanation": "The origin of democracy is traced back to the ancient Greeks in the city-state of Athens around 5th century BC. The term 'democracy' itself is derived from the Greek words 'demos' (people) and 'kratos' (power), meaning 'power to the people'. The Greeks are credited with pioneering the concept of 'rule by the people', which is the fundamental principle of democracy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>35", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Which of the following skills is needed for youth empowerment?", "images": [], "options": {"A": "Cross-curricula skills", "B": "Non-cognitive skills", "C": "Manipulative skills", "D": "Transversal skills"}, "answer": "D", "explanation": "Transversal skills are needed for youth empowerment. These skills are those that can be applied in various situations and contexts, such as problem-solving, critical thinking, and teamwork. They are essential for youth empowerment as they help young people to adapt to different situations, make informed decisions, and effectively interact with others.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>36", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW", "question": "Which of the following is not a feature of federal constitution?", "images": [], "options": {"A": "Division of power", "B": "Supremacy of the constitution", "C": "Flexibility of the constitution", "D": "Written constitution"}, "answer": "C", "explanation": "Flexibility of the constitution is not a feature of a federal constitution. A federal constitution is characterized by a division of power between the central government and the constituent units, supremacy of the constitution, and a written constitution. However, it is not necessarily flexible. In fact, federal constitutions are often rigid to protect the rights and powers of the constituent units.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>37", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "Which of the following is not a consequence of human trafficking?", "images": [], "options": {"A": "Relative deprivation", "B": "Violation of rights", "C": "Discontentment of individuals", "D": "Family bonding and reunion"}, "answer": "D", "explanation": "Human trafficking is a serious crime and a grave violation of human rights. It involves the use of force, fraud, or coercion to obtain some type of labor or commercial sex act. The consequences of human trafficking include violation of rights, relative deprivation, and discontentment of individuals. However, family bonding and reunion is not a consequence of human trafficking. In fact, it often results in the opposite - separation of families and loss of familial ties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>38", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF RULE OF LAW", "question": "The principle of rule of law is upheld in the society in order to", "images": [], "options": {"A": "protect the citizens from arbitrary rule.", "B": "accord immunity to the president.", "C": "preserve customs and tradition of the society.", "D": "encourage mass literacy and prosperity."}, "answer": "A", "explanation": "The principle of rule of law is a legal maxim that suggests that no one is above the law and everyone must answer to it. This principle is upheld in society to protect citizens from arbitrary rule, ensuring that laws are fairly applied and enforced. It does not primarily aim to accord immunity to the president, preserve customs and tradition of the society, or encourage mass literacy and prosperity. These may be secondary effects or entirely unrelated to the rule of law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>39", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "Constitutional democracy is also known as", "images": [], "options": {"A": "communalism", "B": "limited government", "C": "communism", "D": "autocratic government"}, "answer": "B", "explanation": "Constitutional democracy is also known as limited government. In a constitutional democracy, the power of the government is limited by the constitution, and the rights and freedoms of the citizens are protected.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>40", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "Human rights are the cornerstones of", "images": [], "options": {"A": "democracy.", "B": "plutocracy", "C": "aristocracy.", "D": "theocracy."}, "answer": "A", "explanation": "Human rights are the cornerstones of democracy. In a democratic society, the rights and freedoms of all individuals are respected and protected. This includes the right to freedom of speech, the right to freedom of religion, the right to a fair trial, and many others.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>41", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "In order to guarantee transparency and accountability in governance, leaders should ensure that", "images": [], "options": {"A": "constitutionalism thrives.", "B": "the judiciary is supervised.", "C": "immunity covers government officials.", "D": "trials should be held in secret."}, "answer": "A", "explanation": "Transparency and accountability in governance are best guaranteed when constitutionalism thrives. Constitutionalism is the adherence to a system of constitutional government, which means that all actions and policies of the government are in accordance with the constitution. This ensures that the government is accountable to the people and operates transparently within the confines of the law. The other options do not directly guarantee transparency and accountability in governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>42", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : DIFFERENT CULT GROUPS IN NIGERIA AND THEIR SYMBOLS", "question": "Use the diagram in Figure 2 to answer this question    The diagram in Figure 2 symbolizes", "images": ["Civic Education/imgs/2019/img2.png"], "options": {"A": "strength", "B": "authority", "C": "status", "D": "power"}, "answer": "B", "explanation": "The diagram in figure above symbolizes authority. This is the most appropriate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>43", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : WAYS OF DISCOURAGING POLITICAL APATHY", "question": "Political apathy can be discouraged through", "images": [], "options": {"A": "voter's registration.", "B": "registration of more political parties.", "C": "support of government policies.", "D": "free and fair elections."}, "answer": "D", "explanation": "Political apathy, which is a lack of interest or concern in politics, can be discouraged through free and fair elections. When elections are free and fair, citizens are more likely to participate in the political process because they believe their votes count and can make a difference. The other options do not directly address the issue of political apathy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>44", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : THE NEED FOR POPULAR PARTICIPATION IN THE SOCIETY", "question": "Use the write-up below to answer this question  Seven months ago, the people of Okiti town were seen in large numbers staging a peaceful protest against the nonchalant attitude of the provincial government concerning the provision of social amenities in the area.  Some government officials came around and listened to their grievances. Today, things have changed for the better in Okiti town. There is a great improvement in infrastructural development and the people of the area now feel the presence of government in their town.    Which of the following is the consequence of government initial attitude towards Okiti community?", "images": [], "options": {"A": "Underdevelopment", "B": "Corruption", "C": "Ignorance", "D": "Illiteracy"}, "answer": "A", "explanation": "The consequence of the government's initial attitude towards the Okiti community was underdevelopment. This is evident from the context of the question where it is stated that the people of Okiti town were protesting against the lack of social amenities in their area. This implies that the area was underdeveloped due to the government's nonchalant attitude. Underdevelopment refers to the state of an area being deprived of infrastructure and basic amenities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>45", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : THE NEED FOR POPULAR PARTICIPATION IN THE SOCIETY", "question": "Use the write-up below to answer this question  Seven months ago, the people of Okiti town were seen in large numbers staging a peaceful protest against the nonchalant attitude of the provincial government concerning the provision of social amenities in the area.  Some government officials came around and listened to their grievances. Today, things have changed for the better in Okiti town. There is a great improvement in infrastructural development and the people of the area now feel the presence of government in their town.  Which of the following is not portrayed in the write-up above?", "images": [], "options": {"A": "The importance of decentralization", "B": "Government responsiveness", "C": "Intra-governmental relations", "D": "Freedom of expression"}, "answer": "A", "explanation": "The importance of decentralization is not portrayed in the write-up. Decentralization refers to the distribution or delegation of functions and powers from a central authority to regional and local authorities. The write-up does not mention anything about the distribution of powers or functions. It only talks about the government's response to the grievances of the people of Okiti town and the subsequent improvement in infrastructural development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>46", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Use the write-up below to answer this question  Seven months ago, the people of Okiti town were seen in large numbers staging a peaceful protest against the nonchalant attitude of the provincial government concerning the provision of social amenities in the area.  Some government officials came around and listened to their grievances. Today, things have changed for the better in Okiti town. There is a great improvement in infrastructural development and the people of the area now feel the presence of government in their town.  From the above write-up, the action of Okiti people received prompt government attention because of the", "images": [], "options": {"A": "existence of democratic governance.", "B": "need to support minority groups.", "C": "need to reward patriotic citizens.", "D": "election that was fast approaching."}, "answer": "A", "explanation": "The action of Okiti people received prompt government attention because of the existence of democratic governance. In a democratic system of governance, the government is accountable to the people and is expected to respond to their needs and grievances. The fact that government officials came around, listened to their grievances, and made improvements indicates that there is a democratic system in place.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2019>47", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "Democracy could be described as a form of government in which people", "images": [], "options": {"A": "develop interest in good governance.", "B": "produce sound political manifesto for national development.", "C": "participate in the decision making process.", "D": "contribute to political liberation."}, "answer": "C", "explanation": "Democracy is a form of government in which people participate in the decision-making process. This is the fundamental principle of democracy, where the power is vested in the people and they have the right to express their views, opinions, and make decisions that affect their lives. The other options, while they may be aspects of a democratic society, do not define democracy itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>48", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "Which of the following is a focus of the activities of civil society?", "images": [], "options": {"A": "Anonymity", "B": "Equity", "C": "Position seeking", "D": "Policy Implementation"}, "answer": "B", "explanation": "The focus of the activities of civil society is to promote equity. Civil society organizations work to ensure that all individuals and groups in society have equal opportunities and are not discriminated against. They do this by advocating for policies and practices that promote fairness and justice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>49", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : MEANING OF PUBLIC SERVICE", "question": "Which of the following principles prohibits public servants from being seen or heard in the public?", "images": [], "options": {"A": "Permanence", "B": "Impartiality", "C": "Meritocracy", "D": "Anonymity"}, "answer": "D", "explanation": "The principle of anonymity in public service prohibits public servants from being seen or heard in the public. This principle ensures that public servants carry out their duties without seeking personal recognition or publicity. It allows them to remain neutral and impartial, focusing on serving the public interest rather than their own.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2019>50", "subject": "Civic Education", "year": "2019", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY", "question": "Which of the following is a consequence of political apathy?", "images": [], "options": {"A": "Unrest and secession in the country", "B": "Emergence of incompetent leaders", "C": "Lack of foreign direct investment", "D": "Frequent military intervention"}, "answer": "B", "explanation": "Political apathy refers to the indifference on the part of any citizen of any country with regard to their attitude towards political activities. It often leads to the emergence of incompetent leaders because when citizens are apathetic, they do not participate in the political process, including voting, and therefore do not contribute to the selection of competent leaders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>1", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM", "question": "Nationalism in Nigeria eventually led to", "images": [], "options": {"A": "national renaissance", "B": "creattion of states", "C": "decolonization", "D": "the end of the military rule"}, "answer": "C", "explanation": "Nationalism is a political ideology that involves a strong identification of a group of individuals with a nation. In the context of Nigeria, nationalism was a significant force for the struggle for independence from British rule. Therefore, nationalism in Nigeria eventually led to decolonization, not the end of military rule, national renaissance, or creation of states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>2", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "Which of the following conditions gives rise to the denial of right to life?", "images": [], "options": {"A": "Homicide", "B": "Forgery", "C": "Protest", "D": "Burglary"}, "answer": "A", "explanation": "The right to life is a fundamental human right that is protected by law. Homicide, which is the act of one human killing another, directly violates this right. Therefore, it is a condition that gives rise to the denial of the right to life. The other options, Forgery, Protest, and Burglary, while they are crimes, do not directly result in the denial of the right to life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>3", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Activities that act to clog the wheel of societal progress can be described as", "images": [], "options": {"A": "family issues", "B": "cultural vices", "C": "religious issue", "D": "social vices"}, "answer": "D", "explanation": "Social vices are activities that are considered harmful or undesirable in society. They act to clog the wheel of societal progress because they disrupt social order, cause harm to individuals and communities, and hinder development. Examples of social vices include corruption, crime, and discrimination. The other options, family issues, cultural vices, and religious issues, while they can have negative impacts, are not necessarily activities that clog the wheel of societal progress.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>4", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The four most prominent national leaders of Nigeria at independence were", "images": [], "options": {"A": "J.S Tarka, S.L Akintola, Aminu Kano and Ernest Ikoli", "B": "Nnamdi Azikwe, K.O Mbadiwe, Arthur Richards and Aminu Kano", "C": "Tafawa Balewa, Obafemi Awolowo, Nnamdi Azikwe and Ahmadu Bello", "D": "Adesoji Aderemi, Shehu Shagari, Obafemi Awolowo and Nnamdi Azikwe"}, "answer": "C", "explanation": "The four most prominent national leaders of Nigeria at independence were Tafawa Balewa, Obafemi Awolowo, Nnamdi Azikwe and Ahmadu Bello. These leaders played significant roles in the struggle for Nigeria's independence. Tafawa Balewa was the first Prime Minister of Nigeria, Obafemi Awolowo was the leader of the Action Group and first Premier of the Western Region, Nnamdi Azikwe was the first President of Nigeria and Ahmadu Bello was the first Premier of the Northern Nigeria Region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>5", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD", "question": "Responsible parenthood can complement the activities of government in several ways except by raising", "images": [], "options": {"A": "responsible citizens", "B": "citizens who oppose the government", "C": "responsible future leaders", "D": "entrepreneurs in the society"}, "answer": "B", "explanation": "Responsible parenthood does not involve raising citizens who oppose the government. Responsible parenthood involves raising responsible citizens, future leaders, and entrepreneurs who can contribute positively to the society and the economy. Opposing the government does not necessarily mean being responsible or contributing positively to the society. It could lead to unrest, instability and other negative consequences.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>6", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY", "question": "One importance of constituted authority is that it leads to", "images": [], "options": {"A": "maintenance of law and order", "B": "concentration of power", "C": "immunity of elected leaders", "D": "arbitrary use of power"}, "answer": "A", "explanation": "Constituted authority refers to the powers and mechanisms established by a constitution, which govern a state or organization. One of the primary roles of constituted authority is to maintain law and order in the society. It does this by enforcing laws and regulations, and by providing a system for resolving disputes. This helps to ensure that society functions smoothly and that people's rights are protected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>7", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Teaching children to be satisfied with what they have is a way of encouraging", "images": [], "options": {"A": "self--reliance", "B": "orderliness", "C": "contentment", "D": "selflessness"}, "answer": "C", "explanation": "Teaching children to be satisfied with what they have is a way of encouraging contentment. Contentment refers to a state of happiness and satisfaction. When children are taught to be satisfied with what they have, they learn to appreciate their possessions and circumstances, and this leads to a sense of contentment. This does not mean they should not aspire for more, but they should not be overly concerned or unhappy if they do not have everything they want.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>8", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Law and order can best be maintained in Nigeria through the", "images": [], "options": {"A": "making of decree by the various security agencies", "B": "constitutional law enforcement and citizens' common welfare", "C": "prohibition of public protest, terrorism and militancy", "D": "use of modern security gadgets and directorate of state security service"}, "answer": "B", "explanation": "Law and order can best be maintained in Nigeria through constitutional law enforcement and citizens' common welfare. This is because the constitution is the supreme law of the land and it provides guidelines for maintaining law and order. It also ensures the common welfare of citizens by protecting their rights and freedoms. The other options do not provide a comprehensive approach to maintaining law and order.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>9", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)", "question": "The Universal Declaration of Human Rights(UDHR) was adopted by the", "images": [], "options": {"A": "United Nations General Assembly", "B": "United National Security Council", "C": "United Nations San- Francisco Conference", "D": "United Nations Trusteeship Council"}, "answer": "A", "explanation": "The Universal Declaration of Human Rights (UDHR) was adopted by the United Nations General Assembly. The UDHR is a milestone document in the history of human rights that was proclaimed by the United Nations General Assembly in Paris on 10 December 1948. The other options are incorrect because they are not the bodies that adopted the UDHR.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>10", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD", "question": "Responsible parenting is the ability of parents to", "images": [], "options": {"A": "provide qualitative education for their children", "B": "establish profitable business for the fanily", "C": "meet the basic and social needs of their children", "D": "ensure that rights of their chidren are safeguarded"}, "answer": "C", "explanation": "Responsible parenting involves meeting both the basic and social needs of children. Basic needs include food, shelter, and clothing, while social needs involve emotional support, love, and guidance. Providing qualitative education or establishing a profitable business for the family are part of the ways to meet these needs but they are not the definition of responsible parenting. Ensuring the rights of children are safeguarded is also part of responsible parenting but it does not encompass all that responsible parenting entails.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>11", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF RULE OF LAW", "question": "Use the story below to answer question below:  Amaka stole a chicken from a poultry farm.The workers on the farm caught Amaka and gave him the beatings of his life.    Assuming the offence committed by Amaka in the above story happened in a democratic society,the poultry farm workers would be", "images": [], "options": {"A": "honoured for executing instant justice", "B": "punished for taking laws into their own hands", "C": "converted to security personnel", "D": "promoted for safeguarding the poultry farm"}, "answer": "B", "explanation": "In a democratic society, everyone is subject to the law and no one is allowed to take the law into their own hands. Therefore, the workers would be punished for taking laws into their own hands. Executing instant justice, converting to security personnel, or promoting for safeguarding the poultry farm are not actions that would be taken in a democratic society in response to the workers' actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>12", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF RULE OF LAW", "question": "Use the story below to answer question below:  Amaka stole a chicken from a poultry farm.The workers on the farm caught Amaka and gave him the beatings of his life.  Against the background of democratic society, the farm workers in the story above are expected to", "images": [], "options": {"A": "hand Amaka over to the police", "B": "deny Amaka his right to fair hearing", "C": "judge Amaka after giving him a fair hearing", "D": "discharge him of the offence committed"}, "answer": "A", "explanation": "In a democratic society, the rule of law is paramount. This means that when a crime is committed, the offender should be handed over to the police who are the law enforcement agents. The police will then carry out investigations and if found guilty, the offender will be prosecuted in a court of law. The farm workers do not have the right to take the law into their own hands by beating Amaka. They should have handed him over to the police.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>13", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS", "question": "A community which does not associate with neighbouring communities would likely experience", "images": [], "options": {"A": "limited access to modern facilities", "B": "corruption among elected officials", "C": "retarded economic development", "D": "disregard for constitutional rights"}, "answer": "C", "explanation": "A community that does not associate with neighbouring communities would likely experience retarded economic development. This is because interaction with other communities often leads to exchange of ideas, trade and other forms of cooperation that can lead to economic growth. Isolation can limit access to new ideas, technologies and opportunities for trade, thereby slowing down economic development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>14", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Which of the following agencies carries out inspection of vehicles for road worthiness in Nigeria?", "images": [], "options": {"A": "Nigeria Security and Civil Defence Corps", "B": "The Nigeria Police", "C": "Vehicle Inspection Office", "D": "Nigeria Customs Services"}, "answer": "C", "explanation": "The Vehicle Inspection Office (VIO) is the agency responsible for carrying out inspection of vehicles for road worthiness in Nigeria. The VIO ensures that all vehicles on the road are safe and meet the necessary safety standards.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>15", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "The role of a responsible mother is to", "images": [], "options": {"A": "ensure good neighbourliness", "B": "report the husband when necessary", "C": "help the motherless children and orphans", "D": "support the father in meeting family needs"}, "answer": "D", "explanation": "A responsible mother's role is to support the father in meeting family needs. This includes providing emotional, physical, and financial support to the family. This does not exclude other roles like ensuring good neighbourliness or helping the less privileged, but the primary role is to support the family.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>16", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "The human right that is application to human beings without reference to their nationality is the right to", "images": [], "options": {"A": "life and dignity of human persons", "B": "vote", "C": "acquire asset and landed property", "D": "work"}, "answer": "A", "explanation": "The right to life and dignity of human persons is a fundamental human right that applies to all human beings regardless of their nationality. This right is enshrined in various international human rights instruments, including the Universal Declaration of Human Rights. The other options such as the right to vote, acquire asset and landed property, and work can be subject to certain restrictions based on nationality.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>17", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "All regulatory road signs can be categorized into", "images": [], "options": {"A": "mandatory and mediative", "B": "punitive and prohibitive", "C": "prohibitive and mandatory", "D": "persuasive and informative"}, "answer": "C", "explanation": "Regulatory road signs are typically categorized into prohibitive and mandatory signs. Prohibitive signs are used to prohibit certain types of maneuvers or some types of traffic. Mandatory signs are used to set the obligations of all traffic that uses a specific area of road. The other options such as punitive and mediative, and persuasive and informative are not standard categories of road signs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>18", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS", "question": "A healthy inter-communal relationship is not associated with", "images": [], "options": {"A": "political development", "B": "economic progress", "C": "state of violence", "D": "social security"}, "answer": "C", "explanation": "A healthy inter-communal relationship is associated with political development, economic progress, and social security. It promotes peace, unity, and cooperation among different communities, which in turn fosters development in various sectors. However, it is not associated with a state of violence. A state of violence is usually a result of a poor or unhealthy inter-communal relationship, characterized by conflicts, disputes, and misunderstandings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>19", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Cult activities are usually  characterized by", "images": [], "options": {"A": "terrorist activities", "B": "despotic tendencies", "C": "violent disposition", "D": "martial bravery"}, "answer": "A", "explanation": "Cult activities are usually characterized by terrorist activities. Cults are often associated with violence, intimidation, and other forms of harm to achieve their objectives. They often use terror as a tool to instill fear and exert control. While they may also exhibit despotic tendencies, violent disposition, and martial bravery, the most defining characteristic is their engagement in terrorist activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>20", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : MEANING OF DRUG ABUSE", "question": "Which of the following cannot be termed drug abuse?", "images": [], "options": {"A": "Using prescribed drugs the wrong way", "B": "Drinking alcohol in excess", "C": "Frequent intake of soft drinks", "D": "The use of self-medication"}, "answer": "C", "explanation": "Drug abuse refers to the misuse of substances, especially over-the-counter (OTC) medications, prescription drugs, alcohol, and illicit drugs for purposes other than those for which they are indicated or in a manner or in quantities other than directed. Frequent intake of soft drinks does not fall under this category as soft drinks are not classified as drugs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>21", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "An interventionist programme between two warring groups can best be made successful through", "images": [], "options": {"A": "conciliation", "B": "cooperation", "C": "mediation", "D": "counselling"}, "answer": "C", "explanation": "Mediation is a process where a neutral third party helps the disputing parties to reach a mutually acceptable solution. In the context of two warring groups, mediation is the most effective interventionist programme as it involves an unbiased mediator who facilitates communication, promotes understanding, assists the parties to identify their needs and interests, and uses creative problem solving techniques to enable the parties to reach their own agreement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>22", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW", "question": "Use the image in figure 1 to answer question below      The blindfold on the symbol of the woman in Figure 1 indicates that laws must be applied", "images": ["Civic Education/imgs/2020/sscecivil2020obj22.png"], "options": {"A": "with great caution", "B": "in favour of women", "C": "with mental mindset", "D": "by an anonymous judge"}, "answer": "A", "explanation": "The blindfold represents impartiality, the ideal that justice should be applied without regard to wealth,power or other status.", "marks": "1", "difficulty": "3"}, {"id": "objective>Civic Education>2020>23", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : CAUSES OF HIV/AIDS", "question": "Which of these cannot be responsible for the spread of Human Immune deficiency Virus? Acquired Immune Deficiency Syndrome (HIV/AIDS)?", "images": [], "options": {"A": "Unprotected sexual intercourse", "B": "Dinning and drinking with people living with HIV/AIDS", "C": "Using unscreened blood transfusion", "D": "Sharing of unsterilized piercing instruments"}, "answer": "B", "explanation": "HIV/AIDS cannot be spread through casual contact such as dining and drinking with people living with the virus. HIV is transmitted through direct contact with certain body fluids from a person with HIV. These body fluids include blood, semen, vaginal fluids, and breast milk. It is not transmitted through saliva, sweat, tears, urine, or feces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>24", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Studying hard in school is one of the preventive measures against", "images": [], "options": {"A": "unionism", "B": "cultism", "C": "bigotry", "D": "racism"}, "answer": "B", "explanation": "Studying hard in school can be seen as a preventive measure against cultism. Cultism often involves engaging in activities that are outside the normal academic curriculum. Therefore, focusing on academic work and studying hard can help prevent students from being lured into cult activities. Cultism refers to the practices and rituals followed by a cult, often involving violent or illegal activities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>25", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "Use the dialogue below to answer question below:  Zainab: Mum, i am afraid.  Mum: Afraid of what?  Zainab: Lucy,the girl with HIV/AIDS in my class hugged me in school today.  Mum: Dont worry dear, you can't contact HIV by mere hugging.Cheer up my daughter.    From the dialogue above, the problem of Zainab is that of", "images": [], "options": {"A": "stigmatization", "B": "ignorance", "C": "infection", "D": "pride"}, "answer": "B", "explanation": "From the dialogue, Zainab's problem is ignorance. She is afraid because she thinks she can contract HIV/AIDS from hugging someone who is infected. This shows a lack of knowledge or understanding about how the disease is transmitted. HIV/AIDS is not transmitted through casual contact such as hugging, shaking hands, or sharing personal objects, food or water. It is transmitted through certain body fluids—blood, semen, pre-seminal fluid, rectal fluids, vaginal fluids, and breast milk—from a person who has HIV.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>26", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC", "question": "A major challenge for civil societies in executing their mandate is", "images": [], "options": {"A": "poor funding of their programme", "B": "questionable reputable of their members", "C": "compostion of their leadership", "D": "their desire for political power"}, "answer": "A", "explanation": "Civil societies often face the challenge of poor funding of their programmes. This is because they rely on donations, grants, and contributions from members and well-wishers to fund their activities. When these sources of funds are not forthcoming, it becomes difficult for them to execute their mandate effectively. The other options do not directly affect the execution of their mandate as much as funding does.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>27", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "The National Agency for the prohibtion of Traffickig in Persons (NAPTIP) was established in the year", "images": [], "options": {"A": "2001", "B": "2002", "C": "2003", "D": "2004"}, "answer": "C", "explanation": "The National Agency for the Prohibition of Trafficking in Persons (NAPTIP) is a law enforcement agency in Nigeria. It was established by the Trafficking in Persons (Prohibition) Enforcement and Administration Act, 2003. The agency is charged with enforcing laws against human trafficking and similar human rights violations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>28", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "The Senator and House of Representative in Nigeria constitutue the", "images": [], "options": {"A": "Federal congress", "B": "National Parliament", "C": "Federal Legislature", "D": "National Assembly"}, "answer": "D", "explanation": "In Nigeria, the bicameral legislature consists of the House of Representatives and the Senate, and together they make up the National Assembly. The National Assembly is the highest legislative body in the country and has the power to make laws for the peace, order, and good governance of the Federation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>29", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "A primary ambition of individuals involved in human trafficking that cannot be achieved is", "images": [], "options": {"A": "unwanted pregnancy", "B": "physical and actual abuse", "C": "functional freedom", "D": "depression and suicidal thought"}, "answer": "C", "explanation": "Human trafficking involves the use of force, fraud, or coercion to obtain some type of labor or commercial sex act. The primary ambition of individuals involved in human trafficking is to exploit others for personal or financial gain. Functional freedom, which refers to the ability to make decisions and act independently, cannot be achieved by those involved in human trafficking because their actions are illegal and infringe upon the rights and freedoms of others.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>30", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "The approval of the government budget is the responsibility of the", "images": [], "options": {"A": "judiciary", "B": "legislature", "C": "ministers", "D": "executive"}, "answer": "B", "explanation": "The approval of the government budget is the responsibility of the legislature. In a democratic system of government, the legislature is the branch of government that has the power to make laws, and also has the responsibility of approving the government's budget. This is to ensure checks and balances, and to prevent misuse of public funds by the executive branch.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>31", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "Use the dialogue below to answer question below:  Bayo: Wao! Shola, how did you manage to purchase a new tricycle?  Shola: I did not buy it, it was the Councillor from my town that distributed tricycles to unemployed youths. I am lucky to be one of them.  Bayo: Congratulation! That's a good gesture. I wish the Councillor from my town would do same.    The step taken by the Councillor in the dialogue above is best described as", "images": [], "options": {"A": "empowerment", "B": "selflessness", "C": "development", "D": "patriotism"}, "answer": "A", "explanation": "The Councillor's action of distributing tricycles to unemployed youths is a form of empowerment. Empowerment in this context refers to the process of increasing the capacity of individuals or groups to make choices and to transform those choices into desired actions and outcomes. By providing tricycles, the Councillor is enabling the youths to have a means of livelihood, thus empowering them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>32", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Use the dialogue below to answer question below:  Bayo: Wao! Shola, how did you manage to purchase a new tricycle?  Shola: I did not buy it, it was the Councillor from my town that distributed tricycles to unemployed youths. I am lucky to be one of them.  Bayo: Congratulation! That's a good gesture. I wish the Councillor from my town would do same.  Shola in the dialogue above will likely end up being", "images": [], "options": {"A": "patriotic", "B": "hard working", "C": "contended", "D": "self-reliant"}, "answer": "D", "explanation": "Given that Shola has received a tricycle, he now has a means to earn a living and thus, he is likely to become self-reliant. Self-reliance is the ability to depend on oneself for the things one needs. In this case, Shola can use the tricycle for transportation services and earn income, reducing his dependence on others.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>33", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : DIFFERENT CULT GROUPS IN NIGERIA AND THEIR SYMBOLS", "question": "Which of the following is a known as cult group in Nigeria?", "images": [], "options": {"A": "Rangers", "B": "Pirates", "C": "Flamingoes", "D": "Illuminatis"}, "answer": "B", "explanation": "A cult group is a social group that is defined by its unusual religious, spiritual, or philosophical beliefs, or by its common interest in a particular personality, object, or goal. In Nigeria, the Pirates is a known cult group. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>34", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "The body in charge of controlling trafficking of drugs in Nigeria is the", "images": [], "options": {"A": "Federal Road Safety Corps (FRSC)", "B": "National Agency For Food and Drug Administration and Control (NAFDAC)", "C": "National Drug Law Enforcement Agency (NDLEA)", "D": "Nigerian Institute Of Medical Research (NIMR)"}, "answer": "C", "explanation": "The National Drug Law Enforcement Agency (NDLEA) is a Federal agency in Nigeria charged with eliminating the growing, processing, manufacturing, selling, exporting, and trafficking of hard drugs. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>35", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "Which of the following makes the votes of the poor and the rich equal?", "images": [], "options": {"A": "Compulsory voting", "B": "Right to vote", "C": "Popular participation", "D": "Free and fair election"}, "answer": "D", "explanation": "The votes of the poor and the rich are made equal through a free and fair election. This is because in a free and fair election, every vote counts equally regardless of the voter's social or economic status. The concept of a free and fair election is a fundamental aspect of democracy, where each citizen has the right to vote and their vote has equal weight.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>36", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "The act of recruiting and trading of persons for the purpose of commercial exploitation is known as", "images": [], "options": {"A": "slave trade", "B": "human trafficking", "C": "human rights abuse", "D": "amnesty violations"}, "answer": "B", "explanation": "Human trafficking is the act of recruiting and trading of persons for the purpose of commercial exploitation. This involves the use of force, fraud, or coercion to obtain some type of labor or commercial sex act. It is a serious crime and a grave violation of human rights.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2020>37", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF RULE OF LAW", "question": "Which of these is an disadvantage to the application of the rule of law in a democratic society?", "images": [], "options": {"A": "Existence of free and fair election", "B": "Granting of immunity to public office holders", "C": "Ensuring equal protection of citizen's rights", "D": "Promoting popular participation in politics"}, "answer": "B", "explanation": "The rule of law is a principle that ensures that all individuals, including public office holders, are subject to the law and can be held accountable for their actions. However, when public office holders are granted immunity, they are protected from legal proceedings for actions taken in their official capacity. This can be seen as a disadvantage to the application of the rule of law in a democratic society, as it can potentially allow for abuse of power and corruption without fear of legal repercussions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>38", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW", "question": "Use the features of democracy below to answer question below:    I.   Rule of law  II. Judicial independence  III. Press Freedom  IV. Official opposition  V. Free,fair and periodic election  VI. Universal adult suffrage    The protection of citizens' right can be best guaranteed when there is", "images": [], "options": {"A": "II and V", "B": "III and VI", "C": "I and II", "D": "IV and V"}, "answer": "C", "explanation": "The protection of citizens' rights can be best guaranteed when there is Rule of Law (I) and Judicial Independence (II). The rule of law ensures that all citizens are treated equally under the law, and judicial independence ensures that the judiciary can make decisions free from influence or pressure from other branches of government. This combination helps to ensure that citizens' rights are protected and that justice is served fairly and impartially.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>39", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Use the features of democracy below to answer question below:    I.   Rule of law  II. Judicial independence  III. Press Freedom  IV. Official opposition  V. Free,fair and periodic election  VI. Universal adult suffrage  Constructive criticism of government policies and action in a democratic state is best promoted by", "images": [], "options": {"A": "I and V", "B": "IV and VI", "C": "III and IV", "D": "V and VI"}, "answer": "C", "explanation": "Constructive criticism of government policies and action in a democratic state is best promoted by Press Freedom and Official opposition. Press Freedom allows the media to report and critique government actions without fear of retribution, promoting transparency and accountability. Official opposition provides a platform for alternative viewpoints and policies, encouraging debate and scrutiny of government actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>40", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Use the features of democracy below to answer question below:    I.   Rule of law  II. Judicial independence  III. Press Freedom  IV. Official opposition  V. Free,fair and periodic election  VI. Universal adult suffrage  Smooth transition of government in a democratic state is ensured when there is", "images": [], "options": {"A": "I and III", "B": "III and VI", "C": "III and IV", "D": "V and VI"}, "answer": "D", "explanation": "Smooth transition of government in a democratic state is ensured when there is Free, fair and periodic election and Universal adult suffrage. Free, fair and periodic elections ensure that power is transferred peacefully from one government to another. Universal adult suffrage guarantees that all adult citizens have the right to vote, ensuring that the transition of power is based on the will of the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>41", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The 1999 constitution could be described as rigid mainly because", "images": [], "options": {"A": "its amendment requires two-third majority votes of the National Assembly", "B": "its implementation requires the regular services of experienced constitutional lawyers", "C": "adherence to its provision is very difficult", "D": "it requires the presidential proclamation and judicial decision"}, "answer": "A", "explanation": "The 1999 constitution of Nigeria is described as rigid because its amendment requires a two-third majority vote of the National Assembly. This means that for any change to be made to the constitution, it must be approved by a significant majority of the legislative body, making it difficult to alter. This is a characteristic of a rigid constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>42", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "One major factor that hinders women from participating actively in politics is", "images": [], "options": {"A": "their educational background", "B": "lack of fund and financial power", "C": "societal discrimination and belief system", "D": "their religious background"}, "answer": "C", "explanation": "Societal discrimination and belief system is a major factor that hinders women from participating actively in politics. In many societies, women are seen as inferior and are not given equal opportunities as men in many areas including politics. This societal belief and discrimination limit their participation in politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>43", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Under the 1999 Nigerian constitution, the judiciary exercises the greatest power of checks and balances over the", "images": [], "options": {"A": "Executive and Legislature", "B": "House of Representative and Senate", "C": "Local Government Councils and The State Houses of Assembly", "D": "States legislature and National Assembly"}, "answer": "A", "explanation": "The judiciary in Nigeria, as per the 1999 constitution, exercises the greatest power of checks and balances over the Executive and Legislature. This is because the judiciary has the power to interpret the constitution and the laws of the land. It can declare actions of the executive and laws of the legislature unconstitutional if they violate any part of the constitution. This power of judicial review gives the judiciary a significant role in checking and balancing the other two arms of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>44", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "The activities of Economic and Financial Crime Commission (EFCC) can help in promoting the following except", "images": [], "options": {"A": "development", "B": "democracy", "C": "justice", "D": "dictatorship"}, "answer": "D", "explanation": "The Economic and Financial Crime Commission (EFCC) is a Nigerian law enforcement agency that investigates financial crimes such as advance fee fraud and money laundering. The activities of EFCC promote development, democracy, and justice by ensuring that economic and financial crimes are investigated and prosecuted. However, these activities do not promote dictatorship. Dictatorship is a form of government where a single person or a small group possesses absolute power without effective constitutional limitations. EFCC's activities are aimed at promoting transparency and accountability, which are contrary to the principles of a dictatorship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>45", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Use the cartoon in Figure 2 to answer questions below      Based on the cartoon in Figure 2, it is evident that fuel scarcity is associated with the following except", "images": ["Civic Education/imgs/2020/sscecivil2020obj45.png"], "options": {"A": "corruption in public corporation driven oil sector", "B": "the inability of fuel marketers to supply fuel", "C": "corruption in private corporation driven oil sector", "D": "adequate importation of petrol by licensed marketers"}, "answer": "D", "explanation": "Fuel scarcity is associated with corruption in public corporation driven oil sector, the inability of fuel marketers to supply fuel, corruption in private corporation driven oil sector.", "marks": "1", "difficulty": "3"}, {"id": "objective>Civic Education>2020>46", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION", "question": "Use the cartoon in Figure 2 to answer questions below    In Figure 2, the statement  \"government has started the war on corruption\" is an indication that", "images": ["Civic Education/imgs/2020/sscecivil2020obj45.png"], "options": {"A": "taxi drivers are not happy with the new fuel price", "B": "the patronage of taxi has reduced", "C": "government is now tackling a major civic problem", "D": "corruption has been eradicated in the oil sector"}, "answer": "C", "explanation": "The statement indicates that government is now tackling a major civic problem.", "marks": "1", "difficulty": "3"}, {"id": "objective>Civic Education>2020>47", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "The feeling of indifference people have towards participating in issues relating to governance is termed", "images": [], "options": {"A": "political discontentment", "B": "apathy", "C": "bad leadership", "D": "selfishness"}, "answer": "B", "explanation": "Apathy is the term used to describe a state of indifference, or the suppression of emotions such as concern, excitement, motivation, or passion. In the context of governance, political apathy refers to the indifference towards political activities such as elections, civil rights, and freedom of speech. It can manifest as a lack of interest in participating in politics, or a lack of belief in the importance of one's vote.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>48", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC", "question": "Which of the following is a negative way of engaging in popular participation in a state?", "images": [], "options": {"A": "Engaging in  rallies and demonstration", "B": "Joining political party of your choice", "C": "Taking part in  general elections", "D": "Snatching of ballot box during election"}, "answer": "D", "explanation": "Snatching of ballot box during election is a negative way of engaging in popular participation in a state. It is an act of electoral fraud and is illegal. It undermines the democratic process by preventing the votes from being counted accurately. The other options listed such as engaging in rallies and demonstrations, joining a political party of your choice, and taking part in general elections are all legitimate and positive ways of participating in the political process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>49", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "Representative democracy thrives on", "images": [], "options": {"A": "educated electorates", "B": "formation of political parties", "C": "free and fair elections", "D": "equal gender representation"}, "answer": "C", "explanation": "Representative democracy thrives on free and fair elections. This is because in a representative democracy, citizens elect representatives to make laws and policies on their behalf. For this system to work effectively, elections must be free and fair to ensure that the elected representatives truly reflect the will of the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2020>50", "subject": "Civic Education", "year": "2020", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "Which of the the following is a major limitation to the operational effectiveness in the public service?", "images": [], "options": {"A": "Change of government", "B": "Corruption", "C": "Nepotism", "D": "Bureaucratic red-tapism"}, "answer": "D", "explanation": "Bureaucratic red-tapism is a major limitation to the operational effectiveness in the public service. Bureaucratic red-tapism refers to excessive regulation or rigid conformity to formal rules that is considered redundant or bureaucratic and hinders or prevents action or decision-making. This can lead to inefficiencies and delays in the public service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>1", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "The deliberate effort to avoid behaving abnormally when faced with pressure can be termed", "images": [], "options": {"A": "self esteem", "B": "self control", "C": "integrity", "D": "determination"}, "answer": "B", "explanation": "The deliberate effort to avoid behaving abnormally when faced with pressure can be termed as 'self control'. Self control is the ability to control oneself, in particular one's emotions and desires or the expression of them in one's behavior, especially in difficult situations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>2", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "The categories of Nigerian citizens that cannot be declared as non-citizens under any circumstances are citizens by", "images": [], "options": {"A": "parentage and naturalization", "B": "registration and birth", "C": "birth and parentage", "D": "registration and naturalization"}, "answer": "C", "explanation": "The categories of Nigerian citizens that cannot be declared as non-citizens under any circumstances are citizens by 'birth and parentage'. This is because citizenship by birth and parentage is irrevocable, unlike citizenship by registration and naturalization which can be revoked under certain circumstances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>3", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "An importance of effective parenting is that it ensures", "images": [], "options": {"A": "adequate formal education of the citizen", "B": "provision of secondary needs for the family", "C": "family members know how to socialize", "D": "morally upright wards are bred for the society"}, "answer": "D", "explanation": "Effective parenting ensures that children are raised in a manner that they become morally upright citizens. This is because parents are the first moral compass for children and their actions and teachings greatly influence the child's character and behavior. Therefore, the correct answer is 'morally upright wards are bred for the society'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>4", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "A ban on public lectures and symposiums is against the right to freedom of", "images": [], "options": {"A": "movement and right to speech", "B": "worship and fair hearing", "C": "electronic and print media", "D": "peaceful assembly and association"}, "answer": "D", "explanation": "A ban on public lectures and symposiums is against the right to freedom of peaceful assembly and association. This is because these activities are forms of peaceful assembly where people come together to discuss, learn, and share ideas. Therefore, the correct answer is 'peaceful assembly and association'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>5", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "All these can be a cause of accident on the road except", "images": [], "options": {"A": "praying while driving", "B": "eating while driving", "C": "being conscious of road signs", "D": "taking alcohol before driving"}, "answer": "C", "explanation": "Being conscious of road signs is not a cause of accidents on the road. On the contrary, it is a safety measure that helps to prevent accidents. The other options, such as praying while driving, eating while driving, and taking alcohol before driving, can cause distractions or impair the driver's ability to operate the vehicle safely, thereby leading to accidents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>6", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "Use the quotation below to answer question below  'Being truthful to oneself;   being truthful to others;   being someone others can trust;   doing what is right regardless   of the circumstances.\"   The above quotation is apt for describing", "images": [], "options": {"A": "selflessness", "B": "diligence", "C": "discipline", "D": "integrity"}, "answer": "D", "explanation": "The quotation describes the concept of integrity. Integrity involves being truthful to oneself and others, being trustworthy, and doing what is right regardless of the circumstances. The other options, such as selflessness, diligence, and discipline, do not fully capture the essence of the quotation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>7", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "National consciousness, unity and integrity are promoted through all the following ways except", "images": [], "options": {"A": "obedience to rules and regulations", "B": "National Youth Service Corps", "C": "compromise of the rule of law", "D": "teaching of Civic Education in schools"}, "answer": "C", "explanation": "National consciousness, unity and integrity are promoted through obedience to rules and regulations, National Youth Service Corps, and teaching of Civic Education in schools. However, the compromise of the rule of law does not promote national consciousness, unity, and integrity. The rule of law is a principle that ensures all individuals, including the government, are subject to law that is fairly applied and enforced. Compromising it would lead to injustice and inequality, which are against national consciousness, unity, and integrity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>8", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : MEANING AND ORIGIN OF CULTISM", "question": "Membership of an organization associated with secrecy of operations in the society is an indication of", "images": [], "options": {"A": "activism", "B": "cultism", "C": "radicalism", "D": "spiritism"}, "answer": "B", "explanation": "Membership of an organization associated with secrecy of operations in the society is an indication of cultism. Cultism involves activities of secret cults or societies that are kept secret from non-members. These groups often have secret signs, symbols, or codes and may be involved in illegal activities. Activism, radicalism, and spiritism do not necessarily involve secrecy of operations in the society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>9", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL RELATIONSHIPS", "question": "Associations, connections and affiliations between two or more group is what type of relationship?", "images": [], "options": {"A": "Intra-group", "B": "Inter-communal", "C": "Interpersonal", "D": "Intra-communal"}, "answer": "B", "explanation": "The question is asking about the type of relationship between two or more groups. The correct answer is 'Inter-communal'. 'Inter-' is a prefix meaning 'between', 'among', or 'mutually', so 'inter-communal' refers to relationships or interactions between different communities or groups. 'Intra-' on the other hand, is a prefix meaning 'within' or 'inside', so 'intra-group' and 'intra-communal' refer to relationships within a single group or community. 'Interpersonal' refers to relationships or interactions between individuals, not groups.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>10", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "Orderliness in society is best guaranteed when all citizens", "images": [], "options": {"A": "obey rules and regulations", "B": "respect and humble themselves", "C": "are proud to be associated with the society", "D": "know the sanctions for violations of laws"}, "answer": "A", "explanation": "The question is asking about what guarantees orderliness in society. The correct answer is 'obey rules and regulations'. This is because rules and regulations are established to maintain order and harmony in a society. When all citizens obey these rules and regulations, it ensures that everyone's actions are predictable and consistent, which in turn promotes orderliness. The other options, while they may contribute to a harmonious society, do not directly guarantee orderliness.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>11", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Use the images in the diagram to answer question below            The traffic sign in the images in the diagram is to caution road drivers that", "images": ["Civic Education/imgs/2021/civic2021q11.png"], "options": {"A": "pedestrians crossing is in progress therefore, all cars should wait patiently for them", "B": "a designed bus-stop is ahead where school children can be picked and dropped", "C": "pedestrians are to hold hands together so as to support one another when crossing", "D": "they need to move fast because of the presence of a school zone"}, "answer": "A", "explanation": "Pedestrian crossing signs are posted near crosswalks and intersections and posted in school zones. Both signs use yellow-green fluorescent reflective sheeting that enhances its visibility on the roads.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>12", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "Paying our taxes and assisting the government in the fight against crime are examples of", "images": [], "options": {"A": "civil obligations", "B": "social obligations", "C": "economic obligations", "D": "cultural obligations"}, "answer": "A", "explanation": "Paying taxes and assisting the government in the fight against crime are examples of civil obligations. Civil obligations refer to the duties that citizens are expected to perform in their society. These duties include obeying the law, paying taxes, and assisting in the fight against crime.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>13", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "Creating an enabling environment for someone to have control over his financial situation is known as", "images": [], "options": {"A": "reinforcement", "B": "endowment", "C": "empowerment", "D": "enhancement"}, "answer": "C", "explanation": "Creating an enabling environment for someone to have control over his financial situation is known as empowerment. Empowerment refers to the process of becoming stronger and more confident, especially in controlling one's life and claiming one's rights. In this context, it refers to financial empowerment, which involves giving an individual the ability to manage and control their financial situation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>14", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "The following are steps towards sustaining national unity except", "images": [], "options": {"A": "emphasis on factors that unite a nation", "B": "respecting the national symbols", "C": "discouraging inter-religious marriages", "D": "working towards achieving national objectives"}, "answer": "C", "explanation": "National unity is sustained by emphasizing factors that unite a nation, respecting national symbols, and working towards achieving national objectives. However, discouraging inter-religious marriages does not contribute to national unity. Instead, it promotes division and discrimination among different religious groups. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>15", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS", "question": "A major reason that fosters healthy interpersonal relationship is", "images": [], "options": {"A": "pursuit of money", "B": "party politics", "C": "common goals", "D": "culture"}, "answer": "C", "explanation": "Healthy interpersonal relationships are fostered by common goals. When individuals or groups share common goals, they are more likely to work together, communicate effectively, and resolve conflicts in a manner that strengthens their relationship. The pursuit of money and party politics can often lead to conflicts and unhealthy competition, while culture can sometimes be a source of division. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>16", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "People Living with HIV/AIDS (PLWHA) are stigmatized by", "images": [], "options": {"A": "refusal of privileges", "B": "exploitation by care givers", "C": "refusal to be voted for in election", "D": "refusing to respect their authority"}, "answer": "A", "explanation": "People Living with HIV/AIDS (PLWHA) are often stigmatized by society in various ways. One of these ways is through the refusal of privileges. This can include being denied access to certain services, opportunities, or rights due to their health status. This form of discrimination contributes to the marginalization and stigmatization of PLWHA.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>17", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS", "question": "A child who is forced to engage in hawking all day must have been denied the right to", "images": [], "options": {"A": "fair hearing", "B": "expression", "C": "education", "D": "life"}, "answer": "C", "explanation": "A child who is forced to engage in hawking all day is being denied the right to education. The United Nations Convention on the Rights of the Child, to which most countries are signatories, stipulates that every child has the right to education. Forcing a child to hawk all day prevents the child from going to school and receiving an education, thereby denying them this fundamental right.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>18", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "The sole aim of youth empowerment is to", "images": [], "options": {"A": "encourage students to take on a vacation job", "B": "learn to earn money and also how to manage it", "C": "learn how to behave in a work related environment", "D": "give youths financial independence and self reliance"}, "answer": "D", "explanation": "Youth empowerment is a process where young people are encouraged to take charge of their lives. They do this by addressing their situation and then take action in order to improve their access to resources and transform their consciousness through their beliefs, values, and attitudes. The ultimate goal of youth empowerment is to improve the socio-economic status of the youth, which includes financial independence and self-reliance. Therefore, the correct answer is 'give youths financial independence and self reliance'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>19", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "Use the passage below to answer questions below    One day she met some friends who capitalized on her situation and advised her to leave home if she wanted to live good life and she obliged; she was introduced to a trafficking agent who took her abroad where she was compelled to engage in prostitution. Five years later, Chalyn was deported after she had contracted the deadly HIV/AIDS.    - From the above passage, it could be inferred that Chalyn is majorly a victim of", "images": [], "options": {"A": "human trafficking", "B": "inconsiderate government", "C": "lack of family planning", "D": "non-payment of salaries"}, "answer": "A", "explanation": "From the passage, it is clear that Chalyn was introduced to a trafficking agent who took her abroad where she was compelled to engage in prostitution. This is a clear case of human trafficking, which is the action or practice of illegally transporting people from one country or area to another, typically for the purposes of forced labour or commercial sexual exploitation. Therefore, the correct answer is 'human trafficking'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>20", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING", "question": "Use the passage below to answer questions below    One day she met some friends who capitalized on her situation and advised her to leave home if she wanted to live good life and she obliged; she was introduced to a trafficking agent who took her abroad where she was compelled to engage in prostitution. Five years later, Chalyn was deported after she had contracted the deadly HIV/AIDS.   Which of the following would have likely saved Chalyn from falling into the hands of traffickers?", "images": [], "options": {"A": "Adequate remunerations for civil servants", "B": "An established family business", "C": "Moral upbringing and solid parental care", "D": "Adequate family planning"}, "answer": "C", "explanation": "From the passage, it can be inferred that Chalyn was vulnerable due to her situation and was easily influenced by her friends to leave home. If she had received moral upbringing and solid parental care, she might have been able to make better decisions and not fall into the hands of traffickers. Moral upbringing refers to the process of teaching a child the difference between right and wrong, and solid parental care refers to the provision of a safe, nurturing environment by parents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>21", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "Use the passage below to answer questions below    One day she met some friends who capitalized on her situation and advised her to leave home if she wanted to live good life and she obliged; she was introduced to a trafficking agent who took her abroad where she was compelled to engage in prostitution. Five years later, Chalyn was deported after she had contracted the deadly HIV/AIDS.   Chalyn's ordeal would have been likely prevented through all the following means except", "images": [], "options": {"A": "poverty alleviation programme", "B": "effective family planning", "C": "qualitative higher education", "D": "skill acquisition courses"}, "answer": "B", "explanation": "The passage suggests that Chalyn's ordeal was a result of her being trafficked and forced into prostitution. While poverty alleviation, qualitative higher education, and skill acquisition courses could potentially prevent such a situation by providing alternative means of livelihood, effective family planning is not directly related to preventing human trafficking. Family planning generally refers to the practice of controlling the number of children in a family and the intervals between their births, which doesn't directly impact the likelihood of being trafficked.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>22", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Which of the following agents is not saddled with the responsibility of maintaining traffic regulation in Nigeria?", "images": [], "options": {"A": "Vehicle Inspection Officer", "B": "Nigerian Customs Officer", "C": "Police Traffic Warden", "D": "Corps Marshal"}, "answer": "B", "explanation": "The Nigerian Customs Officer is not responsible for maintaining traffic regulation in Nigeria. Their primary role is to manage the import and export of goods, collect customs revenue and prevent smuggling. The Vehicle Inspection Officer, Police Traffic Warden, and Corps Marshal are all involved in maintaining traffic regulation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>23", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : CAUSES OF HIV/AIDS", "question": "A society that is free from HIV/AIDS infected persons will likely experience", "images": [], "options": {"A": "increase in level of poverty", "B": "increase in productivity", "C": "loss of man power", "D": "high deah rate"}, "answer": "B", "explanation": "A society that is free from HIV/AIDS infected persons will likely experience an increase in productivity. This is because the absence of the disease means that more people are healthy and able to contribute to the workforce, leading to increased productivity. The other options such as increase in level of poverty, loss of man power, and high death rate are more likely to be associated with a society that has a high prevalence of HIV/AIDS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>24", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Major behavioural manifestations of drug addicts include the following except", "images": [], "options": {"A": "mental disorder", "B": "isolation and withdrawal", "C": "depression and regrets", "D": "humility and boldness"}, "answer": "D", "explanation": "Drug addiction often leads to various behavioral changes such as mental disorders, isolation and withdrawal, and depression and regrets. However, humility and boldness are not typically associated with drug addiction. In fact, drug addicts often exhibit the opposite behaviors, such as arrogance and fearfulness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>25", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The lowest court in Nigeria is the", "images": [], "options": {"A": "Magistrate/District Court", "B": "Court of Appeal", "C": "Sharia Court of Appeal", "D": "State High Court"}, "answer": "A", "explanation": "In the Nigerian judicial system, the Magistrate/District Court is considered the lowest court. It is the first point of call for most civil and criminal cases. The Court of Appeal, Sharia Court of Appeal, and State High Court are higher courts in the hierarchy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>26", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "Which of the following has the power to impeach the president in Nigeria?", "images": [], "options": {"A": "Executive", "B": "Judiciary", "C": "Legislature", "D": "Supreme court"}, "answer": "C", "explanation": "In Nigeria, the power to impeach the president lies with the Legislature. The process begins in the House of Representatives and if a resolution is passed by two-thirds majority of all its members, it is sent to the Senate for further deliberation and investigation. If the Senate also passes the resolution by two-thirds majority, the president is successfully impeached.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>27", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS", "question": "The phrase no man is an island............means that", "images": [], "options": {"A": "mankind needs other plants and animals to survive", "B": "citizens cannot operate without help of a government", "C": "individuals need the cooperation of others to progress", "D": "humans need to marry and have life partners"}, "answer": "C", "explanation": "The phrase 'no man is an island' is a proverb that emphasizes the interdependence of humans. It means that humans do not thrive when isolated from others and need to be part of a community in order to survive. It implies that individuals need the cooperation of others to progress in life.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>28", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Use the image in the diagram to answer questions below         The people depicted in the image in the diagram are engaged in", "images": ["Civic Education/imgs/2021/civic2021q28.png"], "options": {"A": "community service", "B": "personal development", "C": "empowerment scheme", "D": "fashion design competition"}, "answer": "C", "explanation": "Empowerment is the degree of autonomy and self determination in people and communities. This enables them to represent their interest in a responsible and self-determined way, acting on their own authority. It is a key concept in the discourse on promoting civic engagement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>29", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Use the image in the diagram to answer questions below         The aim of those engaged in the activity captured in the image in Figure 2 is to", "images": ["Civic Education/imgs/2021/civic2021q28.png"], "options": {"A": "obtain relevant skills", "B": "acquire formal knowledge", "C": "source for extra income", "D": "develop interpersonal skills"}, "answer": "A", "explanation": "Empowerment is letting the power out. It encourages people to gain the skills and knowledge that will allow them to overcome obstacles in life or work environment and ultimately, help them develop within themselves or in the society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>30", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Use the image in the diagram to answer questions below         Which type of skill is dominant in the image in figure 2?", "images": ["Civic Education/imgs/2021/civic2021q28.png"], "options": {"A": "Manipulative Skill", "B": "Intellectual Skill", "C": "Negotiation Skill", "D": "Communicative Skill"}, "answer": "A", "explanation": "Manipulative skill is the ability to manipulate a thing or an object with the help of the body or a body part e.g kicking, throwing, bouncing etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>31", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION", "question": "Citizenship education ensures that citizens become aware of", "images": [], "options": {"A": "tenets of the laws of the society", "B": "attributes required to become a leader", "C": "how to restore peace during conflict", "D": "justice and injustice during litigation"}, "answer": "A", "explanation": "Citizenship education is a type of education that prepares citizens to become informed, thoughtful, and active citizens of their communities. It is designed to instill good civic virtues and habits in the citizens, making them aware of the tenets of the laws of the society. This includes understanding the rights, responsibilities, and privileges of citizenship, as well as how to exercise these rights and responsibilities in a variety of contexts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>32", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Cultism is usually not associated with", "images": [], "options": {"A": "rustication", "B": "academic excellence", "C": "stigmatization", "D": "spiritual problems"}, "answer": "B", "explanation": "Cultism is a social vice that is associated with negative outcomes such as rustication, stigmatization, and spiritual problems. However, it is not associated with academic excellence. In fact, involvement in cultism often leads to poor academic performance due to the time and energy that cult activities demand, as well as the potential for disciplinary actions such as suspension or expulsion from school.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>33", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The programmes political parties intend to implement if they are voted into power are known as political", "images": [], "options": {"A": "campaigns", "B": "manifestoes", "C": "agenda", "D": "propaganda"}, "answer": "B", "explanation": "The programmes political parties intend to implement if they are voted into power are known as political manifestoes. A political manifesto is a public declaration of policies and aims, especially one issued before an election by a political party or candidate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>34", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "Use the dialogue below to answer questions below  Mr. Ganaba: Mr Katoun, where are you   going with the hoe and cutlass   on a day that has been set aside for the rescheduled   gubernatorial election in our state?   Mr. Katoun: I am going to the farm   to harvest some tubers of   yam for the next market   day. I don't need to remind   you that we have been   made our own governemt.   Therefore, the sale of   this product is much more   beneficial to me and my   family than whoever   becomes the next governor.    From the dialogue above, Mr Katoun has demonstrated", "images": [], "options": {"A": "survival mode", "B": "intolerance", "C": "apathy", "D": "hard work"}, "answer": "C", "explanation": "From the dialogue, Mr Katoun has demonstrated apathy. Apathy is a lack of interest, enthusiasm, or concern. In this context, Mr Katoun shows a lack of interest in the gubernatorial election, choosing instead to focus on his farming activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>35", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "Use the dialogue below to answer questions below  Mr. Ganaba: Mr Katoun, where are you   going with the hoe and cutlass   on a day that has been set aside for the rescheduled   gubernatorial election in our state?   Mr. Katoun: I am going to the farm   to harvest some tubers of   yam for the next market   day. I don't need to remind   you that we have been   made our own governemt.   Therefore, the sale of   this product is much more   beneficial to me and my   family than whoever   becomes the next governor.   As seen in the dialogue above, Mr. Ganabe is involved in an essential community service as", "images": [], "options": {"A": "a social mobilizer", "B": "a political analyst", "C": "an election observer", "D": "a party official"}, "answer": "A", "explanation": "From the dialogue, Mr. Ganaba is seen questioning Mr. Katoun about his decision to go to the farm on an election day. This shows that he is trying to mobilize Mr. Katoun to participate in the election, hence he is acting as a social mobilizer. A social mobilizer is someone who motivates others to take part in a particular activity or cause.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>36", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY", "question": "Use the dialogue below to answer questions below  Mr. Ganaba: Mr Katoun, where are you   going with the hoe and cutlass   on a day that has been set aside for the rescheduled   gubernatorial election in our state?   Mr. Katoun: I am going to the farm   to harvest some tubers of   yam for the next market   day. I don't need to remind   you that we have been   made our own governemt.   Therefore, the sale of   this product is much more   beneficial to me and my   family than whoever   becomes the next governor.   The behaviour of Mr.Katoun in the dialogue above can be traced to the following factors except", "images": [], "options": {"A": "inadequate security at polling booths", "B": "poor technology", "C": "unfulfilled manifestoes", "D": "existence of endemic corruption"}, "answer": "B", "explanation": "From the dialogue, Mr. Katoun's decision to go to the farm instead of participating in the election is not directly linked to any of the provided options. His decision seems to be more influenced by his personal belief that his farming activities are more beneficial to him and his family than the outcome of the election. Therefore, none of the options provided correctly explains Mr. Katoun's behavior.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>37", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The constitution of the Federal Republic of Nigeria from 1979 to 1999 have all been", "images": [], "options": {"A": "written and rigid", "B": "written and flexible", "C": "unwritten and rigid", "D": "unwritten and flexible"}, "answer": "A", "explanation": "The constitutions of the Federal Republic of Nigeria from 1979 to 1999 have all been written and rigid. A written constitution is a formal document defining the nature of the constitutional settlement, the rules that govern the political system and the rights of citizens and governments in a codified form. A rigid constitution is one that requires a special procedure for its amendment or revision, usually involving a higher degree of difficulty than for ordinary laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>38", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "An established way Labour Unions protect the interest of workers is", "images": [], "options": {"A": "police action", "B": "hunger strike", "C": "industrial action", "D": "mass resignation"}, "answer": "C", "explanation": "Labour Unions protect the interest of workers through industrial action. Industrial action is taken by employees or workers when there is a dispute that cannot be resolved by negotiation. It involves activities undertaken by unionized workers to express their dissatisfaction, including strikes, work-to-rule, go-slow, or other actions designed to reduce productivity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>39", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS", "question": "The right to vie for public office falls under", "images": [], "options": {"A": "economic rights", "B": "political rights", "C": "social rights", "D": "religious right"}, "answer": "B", "explanation": "The right to vie for public office falls under political rights. Political rights are rights that allow individuals to freely participate in the political process, including the right to vote, the right to free speech, and the right to vie for public office. These rights are fundamental to a functioning democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>40", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "The system of government where the ultimate power resides in the people is", "images": [], "options": {"A": "plutocracy", "B": "aristocracy", "C": "theocracy", "D": "democracy"}, "answer": "D", "explanation": "The system of government where the ultimate power resides in the people is democracy. In a democracy, citizens have the power to elect their leaders and influence the policies of their government. This is in contrast to other forms of government like plutocracy (rule by the wealthy), aristocracy (rule by a privileged class), and theocracy (rule by religious leaders).", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2021>41", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "Politically enlightened people may still feel discouraged in the political affairs of their society because of political", "images": [], "options": {"A": "selflessness", "B": "contentment", "C": "participation", "D": "marginalization"}, "answer": "D", "explanation": "Political marginalization refers to the process where certain individuals or groups are pushed to the edge of society by not allowing them an active voice, identity, or place in it. This can lead to them feeling discouraged in the political affairs of their society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>42", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "Supervisory Councilors at the local government level are part of the", "images": [], "options": {"A": "civil servants", "B": "executive organ", "C": "legislature organ", "D": "judicial organ"}, "answer": "B", "explanation": "Supervisory Councilors at the local government level are part of the executive organ. The executive organ is the part of government that has sole authority and responsibility for the daily administration of the state. It executes, or enforces the law. The division of power into separate branches of government is central to the idea of the separation of powers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>43", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "Constitutional provisions cannot be derived from", "images": [], "options": {"A": "statutory sources", "B": "customary sources", "C": "judicial precedents", "D": "colonial policies"}, "answer": "D", "explanation": "Constitutional provisions are the laws and guidelines as stated in a country's constitution. They can be derived from statutory sources, customary sources, and judicial precedents. Statutory sources refer to laws enacted by the legislative arm of government. Customary sources refer to the customs and traditions of the people which have been accepted over time. Judicial precedents refer to previous court decisions that are used as a guide in similar future cases. However, colonial policies cannot be a source of constitutional provisions because they are the policies imposed by colonial masters during the colonial era and may not reflect the values, customs, and traditions of the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>44", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "Political participation is facilitated by the following reasons except", "images": [], "options": {"A": "engaging in moral upliftment", "B": "fostering of political stability", "C": "enhancement of dividends of democracy", "D": "influencing the direction of government policies"}, "answer": "A", "explanation": "Political participation refers to the activities that citizens engage in, to influence the selection of political leaders and the policies they make. These activities include voting, campaigning, lobbying, etc. While political participation can foster political stability, enhance the dividends of democracy, and influence the direction of government policies, engaging in moral upliftment is not a direct way of facilitating political participation. Moral upliftment refers to the improvement of one's moral standards and it's more of a personal development activity rather than a political one.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>45", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY", "question": "Which of these societal values is most expected of every public office holder?", "images": [], "options": {"A": "Excellence", "B": "Accountability", "C": "Hospitality", "D": "Diplomacy"}, "answer": "B", "explanation": "Accountability is the most expected societal value of every public office holder. This is because public office holders are entrusted with public resources and power, and they are expected to use these resources and power responsibly, transparently, and in the best interest of the public. Accountability ensures that public office holders are answerable for their actions and decisions, and can be held responsible if they misuse their power or resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>46", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "Constitutional democracy is also known as", "images": [], "options": {"A": "limited government", "B": "communalism", "C": "communism", "D": "absolute government"}, "answer": "A", "explanation": "Constitutional democracy is also known as limited government. In a constitutional democracy, the power of the government is limited by the constitution, which protects the rights and freedoms of the citizens. This is in contrast to an absolute government, where the government has unlimited power and can do whatever it wants without any checks or balances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2021>47", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "Use the cartoon in the diagram to answer questions below         The phrase the music has changed refers to the fact that", "images": ["Civic Education/imgs/2021/civic2021q47.png"], "options": {"A": "checks and balances are no longer effective", "B": "public servants are to show partisanship", "C": "there was corruption in the public service sector", "D": "the activities of the judiciary should be checkmated"}, "answer": "C", "explanation": "The phrase the music has changed refers to the fact that there was corruption in the public service sector.", "marks": "1", "difficulty": "3"}, {"id": "objective>Civic Education>2021>48", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "Use the cartoon in the diagram to answer questions below         The first statement in the cartoon affirms that the speaker was", "images": ["Civic Education/imgs/2021/civic2021q47.png"], "options": {"A": "supportive of constituted authority", "B": "jealous of Chief Jeunkoku's wealth", "C": "aiding and abetting corruption", "D": "discouraging injustice in the land"}, "answer": "C", "explanation": "The first statement indicate \" aiding and abetting corruption\"", "marks": "1", "difficulty": "3"}, {"id": "objective>Civic Education>2021>49", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF RULE OF LAW", "question": "Use the cartoon in the diagram to answer questions below         A way Chief Jeunkoku can evade sanction is if there is", "images": ["Civic Education/imgs/2021/civic2021q47.png"], "options": {"A": "presence of checks and balances", "B": "operational principle of rule of law", "C": "supremacy of the constitution", "D": "a weak and comprised judiciary"}, "answer": "D", "explanation": "Chief Jeunkoku can evade sanction is if there is a weak and comprised judiciary.", "marks": "1", "difficulty": "3"}, {"id": "objective>Civic Education>2021>50", "subject": "Civic Education", "year": "2021", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Which of the following is not a feature of civil society?", "images": [], "options": {"A": "Protection of the interest of society", "B": "Voluntary membership and participation", "C": "Respect for constituted authority", "D": "Soliciting for political patronage"}, "answer": "D", "explanation": "Civil society is characterized by voluntary membership and participation, protection of the interest of society, and respect for constituted authority. However, soliciting for political patronage is not a feature of civil society. Civil society organizations are typically independent of government and do not seek political patronage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>1", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "A prerequisite for orderliness is", "images": [], "options": {"A": "humility", "B": "morality", "C": "hardwork", "D": "politeness"}, "answer": "B", "explanation": "Orderliness is a prerequisite for morality. Morality involves understanding and adhering to the rules and standards set by society, which promotes orderliness. Humility, hardwork, and politeness are virtues that can contribute to orderliness, but they are not prerequisites.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>2", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "National symbols are also referred to a symbols of national", "images": [], "options": {"A": "co-operation", "B": "identity", "C": "unity", "D": "development"}, "answer": "B", "explanation": "National symbols are referred to as symbols of national identity. They represent the values, history, and cultural heritage of a nation, thereby creating a sense of identity among its citizens. Examples of national symbols include the national flag, national anthem, national bird, etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>3", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "Law of libel and defamation of character violates right to freedom of", "images": [], "options": {"A": "fair hearing", "B": "religion", "C": "expression", "D": "association"}, "answer": "C", "explanation": "The law of libel and defamation of character violates the right to freedom of expression. Freedom of expression is a fundamental human right that allows individuals to freely express their thoughts, ideas, and opinions. However, this right is not absolute and can be limited to protect the reputation and rights of others. Libel and defamation are legal terms for false statements that harm the reputation of an individual or entity, and making such statements can be considered a violation of their right to freedom of expression.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>4", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "Who among the following is not a foremost Nigerian nationalist?", "images": [], "options": {"A": "Sir Abubakar Tafawa Balewa", "B": "Dr. Nnamdi Azikwe", "C": "General Yakubu Gowon", "D": "Chief Obafemi Awolowo"}, "answer": "C", "explanation": "General Yakubu Gowon is not considered a foremost Nigerian nationalist. The term 'nationalist' refers to a person who advocates for political independence for a country. While Gowon played a significant role in Nigeria's history as the head of state during the Nigerian Civil War, he is not typically categorized as a nationalist. The other individuals listed, Sir Abubakar Tafawa Balewa, Dr. Nnamdi Azikwe, and Chief Obafemi Awolowo, are well-known nationalists who played key roles in Nigeria's struggle for independence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>5", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : TRAFFIC REGULATION AND ITS IMPORTANCE IN THE SOCIETY", "question": "The major reason for the enactment of traffic regulations is to", "images": [], "options": {"A": "make sure people travel for business purpose.", "B": "arrest traffic offenders and violators.", "C": "ensure safety and allow easy flow of traffic", "D": "ensure the sustenance and longevity of the roads."}, "answer": "C", "explanation": "The major reason for the enactment of traffic regulations is to ensure safety and allow easy flow of traffic. Traffic regulations are rules or guidelines created by traffic authorities to guide the behavior of road users. This is done to ensure safety on the roads and to prevent accidents and traffic jams. While arresting traffic offenders and ensuring the longevity of roads may be secondary benefits, they are not the primary reason for traffic regulations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>6", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "The basic responsibility of parents is", "images": [], "options": {"A": "providing necessities of life for the children.", "B": "buying expensive gifts for the children.", "C": "sending the children abroad for quality education.", "D": "visiting site of attraction with the children."}, "answer": "A", "explanation": "The basic responsibility of parents is to provide the necessities of life for their children. This includes providing food, shelter, clothing, education, and healthcare. While the other options may be things that parents can do for their children, they are not considered basic responsibilities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>7", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS", "question": "The attitude that prevents peaceful resolution of inter-communal conflict is", "images": [], "options": {"A": "conciliation", "B": "resentment", "C": "dialogue", "D": "mediation"}, "answer": "B", "explanation": "Resentment is an attitude that can prevent the peaceful resolution of inter-communal conflict. Resentment is a feeling of anger or displeasure about someone or something unfair. It can lead to unwillingness to forgive or forget past wrongs, which can hinder dialogue, mediation, and conciliation efforts. The other options - conciliation, dialogue, and mediation are actually methods used to resolve conflicts, not attitudes that prevent resolution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>8", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Use the passage below to answer the question.    It is a common practice for the youths of Upe village to meet every last Saturday of the month to build a proposed structure. Through this practice, they have successfully built a monumental market complex which attracts people from neighboring villages.    The zeal shown by the youths of Upe village is a manifestation of", "images": [], "options": {"A": "community service", "B": "political participation", "C": "national development", "D": "town planning"}, "answer": "A", "explanation": "The zeal shown by the youths of Upe village is a manifestation of community service. Community service is a voluntary work intended to help people in a particular area. In this case, the youths of Upe village are voluntarily coming together to build a proposed structure which benefits their community.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>9", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Use the passage below to answer the question.    It is a common practice for the youths of Upe village to meet every last Saturday of the month to build a proposed structure. Through this practice, they have successfully built a monumental market complex which attracts people from neighboring villages.  The youth who took part in the various building projects in Upe village are said to be", "images": [], "options": {"A": "reliable", "B": "self-reliant", "C": "hardworking", "D": "selfless"}, "answer": "D", "explanation": "The youth who took part in the various building projects in Upe village are said to be selfless. Selflessness is the quality of caring more about other people's needs and interests than about your own. In this case, the youths of Upe village are putting the needs of their community before their own by voluntarily participating in the building projects.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>10", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Which of the following sets of agencies are responsible for checking road worthiness of vehicles?", "images": [], "options": {"A": "The Federal Road Safety Corps and Vehicle Inspection Office", "B": "The Police and National Security and Civil Defence Corps", "C": "Federal Road Safety Corps and the Nigerian Army", "D": "The Nigerian Army and Vehicle Inspection Office"}, "answer": "A", "explanation": "The Federal Road Safety Corps (FRSC) and Vehicle Inspection Office (VIO) are the agencies responsible for checking the roadworthiness of vehicles in Nigeria. The FRSC is the Government Agency with statutory responsibilities for road safety administration in Nigeria. It is responsible for ensuring that vehicles on the road are safe to drive. The VIO, on the other hand, is a service in all states of Nigeria for road traffic administration and control. They are responsible for issuing vehicle licenses and ensuring that vehicles are roadworthy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>11", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "Which of the following may not be vested with a constitution authority?", "images": [], "options": {"A": "A family", "B": "A mob", "C": "A school", "D": "The state"}, "answer": "B", "explanation": "A mob is not vested with constitutional authority. A mob is a large crowd of people, especially one that is disorderly and intent on causing trouble or violence. They are not organized or recognized by the constitution as a body with authority. On the other hand, a family, a school, and the state are all recognized by the constitution and have certain authorities vested in them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>12", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "An individual who finds it difficult to do without in-take of prohibited substances is", "images": [], "options": {"A": "a human trafficker", "B": "an armed robber", "C": "a drug addict", "D": "a kidnapper"}, "answer": "C", "explanation": "The question is about an individual who finds it difficult to do without in-take of prohibited substances. This is a clear description of a drug addict. A drug addict is a person who is unable to stop using a drug, despite harmful consequences to their health and personal life. The other options (human trafficker, armed robber, kidnapper) do not fit this description.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>13", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING", "question": "Which of the following is not a method of recruiting victims for human trafficking?", "images": [], "options": {"A": "Deceit", "B": "Threat", "C": "Application", "D": "Abduction"}, "answer": "C", "explanation": "The question asks for a method that is not used for recruiting victims for human trafficking. The options provided are Deceit, Threat, Application, and Abduction. The correct answer is 'Application'. Human trafficking involves the use of force, fraud, or coercion to obtain some type of labor or commercial sex act. While deceit, threat, and abduction are common methods used by traffickers, 'application' is not a recognized method of recruitment in human trafficking. It implies a formal, voluntary process, which is not characteristic of human trafficking.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>14", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW", "question": "The law protecting certain individuals from being prosecuted is called", "images": [], "options": {"A": "penal code.", "B": "constitutional protection.", "C": "immunity clause.", "D": "legal rights."}, "answer": "C", "explanation": "The law protecting certain individuals from being prosecuted is called the immunity clause. This is a provision in the constitution that grants certain public officials, especially high-ranking executives, immunity from legal suits and prosecution for actions conducted in their official capacity. It is designed to allow such officials to perform their duties without fear of constant litigation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>15", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD", "question": "Use the image to answer the question.        We can conclude that the mother of the boy putting on a face cap in the cartoon in the image  is a", "images": ["Civic Education/imgs/2022/civic2022q15.png"], "options": {"A": "religious mother", "B": "responsible parent", "C": "wealthy person", "D": "child activist"}, "answer": "B", "explanation": "We can conclude that the mother of the boy putting on face cap is a responsible mother as she taught him good morals and abided by it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>16", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION", "question": "Use the image to answer the question.        The effect of the interaction as captured in the cartoon, in the Fig. in relation to Civic Education is", "images": ["Civic Education/imgs/2022/civic2022q15.png"], "options": {"A": "mass mobilization", "B": "pressure group", "C": "peer pressure", "D": "popular participation"}, "answer": "C", "explanation": "Peer pressure is the direct or indirect influence on peers, i.e., members of social groups with similar interests, experiences, or social statuses. Members of a peer group are more likely to influence a person's beliefs, values, and behaviour.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>17", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "Use the image to answer the question.        We can make inference from the response of the boy wearing short pants in the cartoon, in the image that he", "images": ["Civic Education/imgs/2022/civic2022q15.png"], "options": {"A": "needs the knowledge of Civic Education.", "B": "became industrious through empowerment.", "C": "gets financial support from his family.", "D": "lacks moral care of a responsible parent."}, "answer": "D", "explanation": "Self-explanatory as this is the most appropriate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>18", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD", "question": "Use the image to answer the question.        Which of the following is not  an advisable way through which the orientation of the boy wearing short pants in the cartoon, in the image can be corrected?", "images": ["Civic Education/imgs/2022/civic2022q15.png"], "options": {"A": "Subjecting him to harsh punitive measures.", "B": "Impacting an effective Civic Education in him.", "C": "He needs morally upright and responsible parenting.", "D": "An effective guidance and counselling section."}, "answer": "C", "explanation": "Moral  upbringing is a basic responsibility of the parent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>19", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS", "question": "Limitation to the right of life can be found in the case of", "images": [], "options": {"A": "an imprisoned person", "B": "a kidnapped person", "C": "a condemned person", "D": "a trafficked person"}, "answer": "C", "explanation": "Limitation to the right of life can be found in the case of a condemned person. This refers to a person who has been sentenced to death by a competent court of law for committing a capital offence. In such cases, the right to life is legally limited as a form of punishment for the crime committed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>20", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS", "question": "In which of the following do citizens have equal rights? Right to", "images": [], "options": {"A": "freedom of movement", "B": "freedom from discrimination", "C": "free education", "D": "form or join any political party"}, "answer": "B", "explanation": "In the context of citizen's rights, the 'freedom from discrimination' implies that all citizens have equal rights regardless of their race, religion, sex, age, and other personal characteristics. This means that every citizen is treated equally under the law and has equal access to social goods and services. The other options, while they are rights, do not inherently imply equality among citizens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>21", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION", "question": "Interest and willingness to participate in the affairs of a nation are forms of", "images": [], "options": {"A": "Popular Participation", "B": "National Consciousness", "C": "Political Apathy", "D": "Citizenship Education"}, "answer": "A", "explanation": "Interest and willingness to participate in the affairs of a nation are forms of 'Popular Participation'. This refers to the involvement of citizens in decision-making processes, implementation, and evaluation of policies and projects. 'National Consciousness' refers to the awareness of being part of a nation and having a sense of belonging. 'Political Apathy' refers to indifference towards political activities and 'Citizenship Education' is about educating citizens about their rights, responsibilities, and the workings of the government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>22", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "The societal norms that represents the overall attitude of the people in a society is called", "images": [], "options": {"A": "group values.", "B": "general  values.", "C": "religious values.", "D": "personal values."}, "answer": "B", "explanation": "The societal norms that represent the overall attitude of the people in a society are referred to as general values. These are the values that are widely accepted and followed by the majority of people in a society. They are not specific to any group, religion, or individual, hence the term 'general'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>23", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "My stiffest earthly assignment is ended and major life's work is done. My country is now free...        -  Dr. Nnamdi Azikiwe     The speaker quoted above must have fought hard for national", "images": [], "options": {"A": "prosperity", "B": "recognition", "C": "development", "D": "independence"}, "answer": "D", "explanation": "The quote is from Dr. Nnamdi Azikiwe, who was one of the leading figures in Nigeria's struggle for independence from British rule. The phrase 'My country is now free' indicates that the speaker was involved in a struggle for national independence, not prosperity, recognition, or development. Therefore, the correct answer is 'independence'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>24", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "Irresponsible parenting has the tendency of", "images": [], "options": {"A": "encouraging egoistic tendencies", "B": "preserving of culture", "C": "promoting of positive values", "D": "promoting peaceful co-existence"}, "answer": "A", "explanation": "Irresponsible parenting can lead to children developing egoistic tendencies. This is because when parents do not fulfill their responsibilities, children may grow up thinking only about their own needs and wants, without considering the needs and wants of others. This is what is referred to as egoistic tendencies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>25", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY", "question": "Which of the following is a cause of political apathy in Nigeria?", "images": [], "options": {"A": "Adequate citizenship education", "B": "A free and fair election", "C": "Biased electoral umpires", "D": "Adequate political awareness"}, "answer": "C", "explanation": "Biased electoral umpires can cause political apathy in Nigeria. Political apathy refers to a lack of interest in political activities, such as voting in elections. When electoral umpires are biased, they may not conduct free and fair elections, which can lead to citizens losing faith in the electoral process and becoming apathetic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>26", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "Representation of Nigerians in the senate is", "images": [], "options": {"A": "Proportional", "B": "collegial", "C": "equal", "D": "unequal"}, "answer": "C", "explanation": "Representation of Nigerians in the Senate is equal. This is because each state, regardless of its size or population, is represented by three senators. This ensures that all states have an equal voice in the Senate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>27", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS", "question": "Identify the odd one from the list below in relation to citizenship obligations", "images": [], "options": {"A": "Payment of tax", "B": "Right to personal liberty", "C": "Protection of public utilities", "D": "Obedience to the Law"}, "answer": "B", "explanation": "The odd one from the list in relation to citizenship obligations is 'Right to personal liberty'. This is because it is a fundamental human right, not an obligation. The other options - 'Payment of tax', 'Protection of public utilities', and 'Obedience to the Law' - are all obligations of a citizen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>28", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "According to the 1999 constitution as amended, sovereignty belongs to the", "images": [], "options": {"A": "president who is also the Commander-in-Chief of the Armed Forces.", "B": "people from whom government derives its power and authority.", "C": "National Assembly which has power to make laws and amend the constitution.", "D": "judiciary which interprets the laws of the state"}, "answer": "B", "explanation": "According to the 1999 constitution as amended, sovereignty belongs to the people from whom government derives its power and authority. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. In this case, the people are the source of power and authority for the government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>29", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "Article 1 of the Universal Declaration of Human Rights (UDHR) states that all human beings", "images": [], "options": {"A": "have freedom of movement", "B": "are born free and equal", "C": "should be free from torture", "D": "have the right to recognition"}, "answer": "B", "explanation": "Article 1 of the Universal Declaration of Human Rights (UDHR) states that all human beings are born free and equal in dignity and rights. They are endowed with reason and conscience and should act towards one another in a spirit of brotherhood. This means that every person is entitled to certain fundamental rights, simply by the fact of being human. These rights are not granted by any state. These universal rights are inherent to us all, regardless of nationality, sex, national or ethnic origin, color, religion, language, or any other status.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>30", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Use the quotation below to answer the question.     If you cannot beat them, join them.     The statement is an indication of a society that is", "images": [], "options": {"A": "ethically upright", "B": "morally degenerated", "C": "politically disintegrated", "D": "socially regenerated"}, "answer": "B", "explanation": "The statement 'If you cannot beat them, join them' is often used to express a form of surrender or compromise, especially when one is unable to overcome a particular challenge or situation. It suggests a form of moral degeneration as it implies giving up on one's principles or values to conform to the majority or the status quo, even if it's wrong or unethical. Therefore, the statement is an indication of a society that is morally degenerated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>31", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Use the quotation below to answer the question.     If you cannot beat them, join them.   Through which of the following means can the effect of the above quotation on the society be rectified?", "images": [], "options": {"A": "Compulsory communal service", "B": "Strengthening of the constitution", "C": "Reorientation of values", "D": "Distribution of relief materials during emergency"}, "answer": "C", "explanation": "The effect of the quotation 'If you cannot beat them, join them' on the society can be rectified through the reorientation of values. This means educating the members of the society about the importance of upholding their principles and values, even when faced with challenges or opposition. It involves teaching them to stand for what is right, even if it means standing alone, rather than conforming to the majority or the status quo, especially when it's wrong or unethical. Therefore, the reorientation of values is the means through which the effect of the above quotation on the society can be rectified.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>32", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS", "question": "Interpersonal relationship is promoted through the following ways except", "images": [], "options": {"A": "confrontation", "B": "healthy competition", "C": "co-operation", "D": "communal living"}, "answer": "A", "explanation": "Interpersonal relationship is promoted through healthy competition, co-operation, and communal living. These are all ways that encourage positive interaction, mutual understanding, and respect among individuals. However, confrontation does not promote interpersonal relationships. Confrontation often leads to conflicts, disagreements, and can strain relationships.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>33", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM", "question": "An activity meant to promote and protect the interest of a country is", "images": [], "options": {"A": "unitarianism", "B": "communism", "C": "communalism", "D": "nationalism"}, "answer": "D", "explanation": "Nationalism is an activity meant to promote and protect the interest of a country. It involves the actions and policies that are aimed at achieving and maintaining the unity, integrity, and identity of a nation. Unitarianism, communism, and communalism are forms of political ideologies or systems, but they do not inherently promote and protect the interest of a country in the way that nationalism does.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>34", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY", "question": "Democracy is important because it", "images": [], "options": {"A": "accommodates popular participation.", "B": "accommodates political apathy.", "C": "encourages operational bureaucracy.", "D": "breeds ethnic competition and rivalry."}, "answer": "A", "explanation": "Democracy is a system of government where citizens exercise power by voting. It is important because it accommodates popular participation. This means that in a democratic system, every citizen has the right to participate in the decision-making process, either directly or through elected representatives. This is not the case with political apathy, operational bureaucracy, or ethnic competition and rivalry, which are not inherent characteristics of democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>35", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Which of the following criminal act is most commonly perpetrated by cult members?", "images": [], "options": {"A": "Prostitution", "B": "Money Laundering", "C": "Corruption", "D": "Violence"}, "answer": "D", "explanation": "Cultism is often associated with violence. Cult members are known to engage in violent activities such as fights, murders, and other forms of physical aggression. While cult members may also engage in other criminal activities such as prostitution, money laundering, and corruption, violence is the most common act perpetrated by them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>36", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : SYMPTOMS AND EFFECTS OF HIV/AIDS", "question": "Use the dialogue below to answer the question.    Tim: Jim, let's go to the hospital and confirm our  HIV  status.  Jim: Really? Does my face resemble that of someone with  HIV ?  After all, I am too poor to engage in illicit sex, drug abuse nor keep numerous partners like you do.  Tim: It is more than what you think, Jim. You suffer other noticeable symptoms which makes me suspicious of your status.  Jim:  Okay, just to satisfy your curiosity, let's go.    From the above dialogue, noticeable symptoms Tim must have observed about Jim include the following except", "images": [], "options": {"A": "profuse night sweats.", "B": "persistent diarrhoea.", "C": "increase in appetite", "D": "usual fatigue"}, "answer": "C", "explanation": "The dialogue does not provide any specific symptoms that Tim observed in Jim. However, the options provided are common symptoms of HIV. Among these symptoms, an increase in appetite is not typically associated with HIV. HIV often causes loss of appetite. Therefore, the correct answer is 'increase in appetite'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>37", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "Use the dialogue below to answer the question.    Tim: Jim, let's go to the hospital and confirm our  HIV  status.  Jim: Really? Does my face resemble that of someone with  HIV ?  After all, I am too poor to engage in illicit sex, drug abuse nor keep numerous partners like you do.  Tim: It is more than what you think, Jim. You suffer other noticeable symptoms which makes me suspicious of your status.  Jim:  Okay, just to satisfy your curiosity, let's go.    Individual like Jim in the story above who believe HIV carriers are selective, can get enlightenment through", "images": [], "options": {"A": "effective fasting and prayer.", "B": "youth empowerment programme.", "C": "sex and civic education.", "D": "popular participation."}, "answer": "C", "explanation": "The dialogue suggests that Jim has misconceptions about how HIV is transmitted. He believes that only certain types of people (those who engage in illicit sex, drug abuse, or have numerous partners) can contract HIV. This is a misunderstanding. HIV can affect anyone, regardless of their lifestyle. Therefore, the best way for Jim to correct his misconceptions is through education, specifically sex and civic education, which would provide accurate information about HIV transmission and prevention.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>38", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "Which of the following is not a function of the judicial arm of government?", "images": [], "options": {"A": "Interpretation of the law", "B": "Judicial review", "C": "Checking of arbitrariness", "D": "Initiation of bills"}, "answer": "D", "explanation": "The judicial arm of government is responsible for interpreting the law, conducting judicial reviews, and checking arbitrariness. However, the initiation of bills is not a function of the judiciary but rather the legislature. The legislature is responsible for making laws, which includes the initiation of bills.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>39", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The officials of the administrative agency of the state that are most active in governance belongs to the", "images": [], "options": {"A": "Legislative organ", "B": "Judicial organ", "C": "Executive organ", "D": "Civil societies"}, "answer": "C", "explanation": "The officials of the administrative agency of the state that are most active in governance belong to the executive organ. The executive branch of government is responsible for implementing and enforcing laws, which includes the administration of public policy. This makes them the most active in governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>40", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : REASONS FOR CULTISM", "question": "One major reason some Nigerian youths join cult groups is", "images": [], "options": {"A": "inadequate religious and moral instruction", "B": "poor welfare programme for students.", "C": "inadequate support from guardians and parents.", "D": "prevalence of corruption among political elites"}, "answer": "A", "explanation": "The major reason some Nigerian youths join cult groups is due to inadequate religious and moral instruction. This is because a strong moral and religious foundation can help guide a person's actions and decisions, and prevent them from engaging in harmful activities such as joining a cult. The other options, while they may contribute to the problem, are not the main reason.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>41", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS", "question": "All the following are aims of youth empowerment scheme except", "images": [], "options": {"A": "Reduction of youth delinquency", "B": "Promotion of self-reliance", "C": "Maximization of profit", "D": "Building of self-esteem"}, "answer": "C", "explanation": "The aim of youth empowerment schemes is not to maximize profit. Youth empowerment schemes are designed to equip young people with the skills, knowledge, and opportunities they need to be productive members of society. This includes reducing youth delinquency, promoting self-reliance, and building self-esteem. Maximizing profit is typically a goal of businesses, not empowerment programs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>42", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "A situation where only 35% of 80 million registered voters participated in a general election, is an indication of political", "images": [], "options": {"A": "instability", "B": "exclusiveness", "C": "apathy", "D": "socialization"}, "answer": "C", "explanation": "Political apathy refers to the indifference on the part of any citizen of any country with regard to their attitude towards political activities. A low voter turnout, such as 35% of 80 million registered voters participating in a general election, is a clear indication of political apathy. This is because a significant number of registered voters did not participate in the election, showing a lack of interest or concern in the political process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>43", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "The organizations working against dictatorship and mounting of campaigns for effective civil rule are called", "images": [], "options": {"A": "professional bodies.", "B": "religious institutions.", "C": "civil societies", "D": "political parties"}, "answer": "C", "explanation": "Civil societies are organizations or groups that work in the interest of the citizens but operate outside of the government. They include non-governmental organizations (NGOs), community groups, women's organizations, faith-based organizations, professional associations, trade unions, self-help groups, social movements, business associations, coalitions and advocacy groups. They often work against dictatorship and mount campaigns for effective civil rule, advocating for human rights, social or political change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>44", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Use the diagram below to answer the question        In the democratic government structure, the portion marked x in the diagram is occupied by the", "images": ["Civic Education/imgs/2022/civic2022q44.png"], "options": {"A": "press", "B": "judiciary", "C": "civil societies", "D": "political parties"}, "answer": "B", "explanation": "The judiciary is the third arm of government. The presidency represents the executive arm while the national assembly represents the legislative arm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>45", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Use the diagram below to answer the question      The major function of the activity of the occupiers of the marked x in the diagram is to", "images": ["Civic Education/imgs/2022/civic2022q44.png"], "options": {"A": "interpret laws.", "B": "execute policies.", "C": "make bye laws", "D": "formulate policies"}, "answer": "A", "explanation": "The major function of the judiciary is to interpret the law. The executive is charged with executing policies while the legislature formulates policies. Bye laws are made by local governments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>46", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC", "question": "Which of the following is not is not a problem of civil society?", "images": [], "options": {"A": "Leadership struggle", "B": "Poor funding", "C": "Planning to capture political power", "D": "Embezzlement of funds"}, "answer": "C", "explanation": "Civil societies are typically non-governmental organizations that are involved in the public sphere, expressing the interests and will of their members. They are not involved in capturing political power, which is the domain of political parties. Therefore, planning to capture political power is not a problem of civil society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>47", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "One of the major complaint against the public service is", "images": [], "options": {"A": "Inefficiency", "B": "Victimization", "C": "Discrimination", "D": "Election rigging"}, "answer": "A", "explanation": "Public service refers to services provided by government to its citizens, either directly or by financing provision of services. One of the major complaints against the public service is inefficiency. This could be due to bureaucracy, lack of resources, or poor management. Inefficiency in public service can lead to delays, poor quality of service, and dissatisfaction among the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>48", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "From which of the following sources are constitutional provisions not derived?", "images": [], "options": {"A": "Statutory sources", "B": "Customary sources", "C": "Judicial Precedence", "D": "Story book"}, "answer": "D", "explanation": "Constitutional provisions are derived from statutory sources, customary sources, and judicial precedence. These are all legal sources that contribute to the formation and interpretation of a constitution. Statutory sources refer to laws enacted by a legislative body. Customary sources refer to long-standing practices and traditions that have been recognized by the courts and have the force of law. Judicial precedence refers to the principle that the decision of a higher court should serve as a guide or precedent for the decision of a lower court in similar cases. However, a story book is not a source of constitutional provisions. It's a book containing a collection of stories, usually for children, and has no legal bearing or contribution to constitutional provisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2022>49", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "The head of the judicial arm of government in Nigeria is the", "images": [], "options": {"A": "Chief justice", "B": "Supreme leader", "C": "Chief of staff", "D": "Chief Magistrate"}, "answer": "A", "explanation": "The head of the judicial arm of government in Nigeria is the Chief Justice. The Chief Justice is the highest-ranking judge who presides over the Supreme Court in Nigeria. The Supreme Leader is a title more commonly used in countries with a theocratic government structure and is not applicable to Nigeria's democratic system. The Chief of Staff is an administrative position, often in the executive branch of government, and does not head the judiciary. The Chief Magistrate is a judicial officer but does not head the judiciary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2022>50", "subject": "Civic Education", "year": "2022", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "The composition of National Assembly of the Federal Republic of Nigeria could be termed", "images": [], "options": {"A": "unicameral", "B": "collegial", "C": "bicameral", "D": "hierarchical"}, "answer": "C", "explanation": "The composition of the National Assembly of the Federal Republic of Nigeria is bicameral because it consists of two houses: the Senate and the House of Representatives. The term 'bicameral' refers to a legislative body that has two branches or chambers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>1", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS", "question": "Which of the following is important for sustainable human relation in a society?", "images": [], "options": {"A": "Tolerance", "B": "Birth registration", "C": "Cultural affinity", "D": "Rehabilitation"}, "answer": "A", "explanation": "Tolerance is important for sustainable human relations in a society. It allows people to live together peacefully, understand and accept the differences among them. It promotes peace, understanding, cooperation and unity in a society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>2", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The machinery through which the will of the state is driven is described as", "images": [], "options": {"A": "administration", "B": "rule of law", "C": "government", "D": "custom and tradition"}, "answer": "C", "explanation": "The machinery through which the will of the state is driven is described as the government. The government is the institution through which a society makes and enforces its public policies. It is composed of lawmakers, administrators, and arbitrators. Government maintains order, provides public services, and enforces decisions that are binding on all people living within the state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>3", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "A major attribute an individual will likely exhibit if not contended is", "images": [], "options": {"A": "jealousy", "B": "irresponbility", "C": "greediness", "D": "dishonesty"}, "answer": "C", "explanation": "A major attribute an individual will likely exhibit if not contented is greediness. Greediness is the excessive desire to acquire or possess more than what one needs or deserves, especially with respect to material wealth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>4", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "Standards, rule and criteria that determine  acceptable norms that influence a cordial relationship in the society are referred to as", "images": [], "options": {"A": "values", "B": "attitudes", "C": "conventions", "D": "regulations"}, "answer": "A", "explanation": "Standards, rules, and criteria that determine acceptable norms that influence a cordial relationship in the society are referred to as values. Values are the principles or standards of behavior; one's judgment of what is important in life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>5", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "Under the Nigeria 1999 constitution as amended, the right to secede is", "images": [], "options": {"A": "allowed to any state in the federation", "B": "denied to all states in the federation", "C": "resident in local government in federation", "D": "given to the federal government"}, "answer": "B", "explanation": "Under the Nigeria 1999 constitution as amended, the right to secede is denied all states in the federation. The constitution does not provide any provision for any state or part of the country to secede or separate from the federation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>6", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The Nigerian Tribune newspaper was established by", "images": [], "options": {"A": "Herbert Macauley", "B": "Obafemi Awolowo", "C": "Anthony Enahoro", "D": "Ahmadiu Bello"}, "answer": "B", "explanation": "The Nigerian Tribune newspaper was established by Chief Obafemi Awolowo in November 1949. It is one of the oldest surviving private newspapers in Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>7", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "A person born in Ghana by Nigerian parents and resides in Ghana is a citizen of", "images": [], "options": {"A": "Ghana by naturalization", "B": "Nigeria by birth", "C": "Nigerian by registration", "D": "Ghana by birth"}, "answer": "D", "explanation": "The person acquires the citizenship by birth. This is the most appropriate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>8", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "The payment of residential utility bills is a duty of the", "images": [], "options": {"A": "federal government", "B": "state government", "C": "local government", "D": "citizens"}, "answer": "D", "explanation": "The payment of residential utility bills such as electricity, water, and waste disposal is a responsibility of the citizens. These bills are used to fund the provision of these services by the government or private companies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>9", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "An inalienable right enjoyed by citizens of a state but denied all non - citizens is the right to", "images": [], "options": {"A": "fair hearing", "B": "freedom of speech", "C": "be voted for", "D": "sue and be sued"}, "answer": "C", "explanation": "The right to be voted for, also known as the right to hold public office, is an inalienable right that is typically reserved for citizens of a state. Non-citizens, even if they are permanent residents, are usually not allowed to run for public office.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>10", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS", "question": "Right to ownership of property falls under the category of", "images": [], "options": {"A": "civil right", "B": "social right", "C": "politcal right", "D": "economic right"}, "answer": "A", "explanation": "The right to ownership of property is a civil right. Civil rights are a class of rights that protect individuals' freedom from infringement by governments, social organizations, and private individuals. They ensure one's ability to participate in the civil and political life of the society and state without discrimination or repression.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>11", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS", "question": "The right to freedom of expression can be limited by", "images": [], "options": {"A": "the legislature", "B": "the police", "C": "slander", "D": "insecurity"}, "answer": "C", "explanation": "The right to freedom of expression can be limited by slander. Slander refers to the act of making false spoken statements that damage a person's reputation. If a person's expression involves slander, it can be limited or restricted to protect the rights and reputation of others.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>12", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : ROLES OF INDIVIDUALS, GROUPS AND GOVERNMENT IN UDHR", "question": "Human rights abuse can be prevented with the existence of", "images": [], "options": {"A": "independence judiciary", "B": "well-equipped police force", "C": "strong armed force", "D": "strong intergovernmental relation"}, "answer": "A", "explanation": "Human rights abuse can be prevented with the existence of an independent judiciary. An independent judiciary ensures that laws are interpreted and enforced fairly and impartially. It can protect individuals from human rights abuses by holding those responsible accountable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>13", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "To enhance national development, parenthood which is the nucleus of every society must be", "images": [], "options": {"A": "regulated by religious clerics", "B": "relaxed in their responsibilities", "C": "supported by leader in government", "D": "a civil and morally responsible one"}, "answer": "D", "explanation": "To enhance national development, parenthood, which is the nucleus of every society, must be a civil and morally responsible one. Responsible parenthood involves raising children to be responsible, productive, and ethical members of society, which contributes to national development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>14", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "The beam of yellow colour on a traffic light is an indication to drivers to", "images": [], "options": {"A": "move", "B": "get ready to move", "C": "stop", "D": "watch out for cars"}, "answer": "B", "explanation": "The beam of yellow colour on a traffic light is an indication to drivers to get ready to move. It is the transition signal between green (go) and red (stop), preparing drivers for the change.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>15", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Road signs are usually", "images": [], "options": {"A": "regulatory and informative", "B": "persuasive and regulatory", "C": "informative and persuasive", "D": "punitive and informative"}, "answer": "A", "explanation": "Road signs are usually regulatory and informative. Regulatory signs instruct road users on what they must or must not do under certain circumstances. Informative signs provide information about the road conditions, route directions, and points of geographical or historical interest.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>16", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : TRAFFIC REGULATION AND ITS IMPORTANCE IN THE SOCIETY", "question": "Use the write up below to answer the question    Driving on the highways entails being very watchful, observant and attentive to one's surrounding, else you many run into an object or someone. Most accidents are caused by human factors.    From the above statement, it is clear that accidents can be", "images": [], "options": {"A": "discouraged", "B": "managed", "C": "eliminated", "D": "prevented"}, "answer": "D", "explanation": "The passage implies that by being watchful, observant, and attentive, accidents can be prevented. Therefore, the correct answer is 'prevented'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>17", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Traffic regulations are law that mainly", "images": [], "options": {"A": "guide all road users on safety practices", "B": "establish agencies for control of traffic", "C": "ensure the teaching of road safety in school", "D": "instruct drivers on the use of traffic signs only"}, "answer": "A", "explanation": "Traffic regulations are laws that guide all road users on safety practices to prevent accidents and ensure smooth flow of traffic. They do not primarily establish agencies for control of traffic, ensure the teaching of road safety in school, or instruct drivers on the use of traffic signs only.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>18", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS", "question": "Positive interpersonal relationship mainly promotes", "images": [], "options": {"A": "competition with one another", "B": "peaceful co-existence", "C": "existence of healthy rivalry", "D": "acquisition of business ideas"}, "answer": "B", "explanation": "Positive interpersonal relationships mainly promote peaceful co-existence. They allow individuals to work together harmoniously, which can lead to peace and stability in a community or society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>19", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS", "question": "A social affiliation between two or more people in the society is known as", "images": [], "options": {"A": "intercommunal relations", "B": "inter-ethnic relations", "C": "interpersonal relations", "D": "inter societal relations"}, "answer": "C", "explanation": "A social affiliation between two or more people in the society is known as interpersonal relations. Interpersonal relations refer to social associations, connections, or affiliations between two or more people. They can vary from brief acquaintances to close, personal relationships.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>20", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS", "question": "A major achievement that can be attributed to good intercommunal relationship in Nigeria is", "images": [], "options": {"A": "curtailing rural-urban migration", "B": "promoting national cultural festivals", "C": "encouraging competition among individuals in the society", "D": "promoting peace, mutual understanding and development"}, "answer": "D", "explanation": "A major achievement that can be attributed to good intercommunal relationship in Nigeria is promoting peace, mutual understanding and development. Good intercommunal relationships can lead to peace and mutual understanding, which in turn can foster development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>21", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Activities of secret cults are not likely to be prominent in", "images": [], "options": {"A": "educational campuses", "B": "motor parks", "C": "market squares", "D": "religious gatherings"}, "answer": "D", "explanation": "Secret cults are more likely to be prominent in places where there are large gatherings of people, especially young people, such as educational campuses. They are less likely to be prominent in religious gatherings because these are usually supervised by adults and have a moral and spiritual focus that is incompatible with the activities of secret cults.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>22", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY", "question": "Which of the following factors have made political apathy in Nigeria more pronounced?", "images": [], "options": {"A": "Long period of dictatorship and election rigging", "B": "Poverty, ethnicity and religious fanaticism", "C": "Indiscriminate registration of parties and illiteracy", "D": "Use of card readers and complexity of voting procedure"}, "answer": "A", "explanation": "Political apathy, or lack of interest in politics, can be caused by a variety of factors. In the context of Nigeria, a long period of dictatorship and election rigging can lead to a sense of disillusionment and cynicism about the political process, making people less likely to participate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>23", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "Combating human trafficking requires the efforts of", "images": [], "options": {"A": "government, educational bodies, religious organisations excluding civil services", "B": "government and non-governmental agencies excluding the students", "C": "international bodie, pressure groups and other non-governmental agencies only", "D": "individuals, government, non-governmental agencies including international bodies"}, "answer": "D", "explanation": "Combating human trafficking requires the efforts of everyone, including individuals, government, non-governmental agencies, and international bodies. Human trafficking is a global problem that requires a coordinated, international response.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>24", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY", "question": "When voters exercise their right to vote based on monetary or material inducements, the elected candidates mau suffer", "images": [], "options": {"A": "eroded legitimacy during elected term", "B": "loss of voters support in the next election", "C": "loss of party support for anothet term", "D": "erosion of dividends of democracy"}, "answer": "A", "explanation": "When voters are induced to vote for a candidate based on monetary or material inducements, it undermines the legitimacy of the elected candidate. This is because the election is not based on the candidate's policies or qualifications, but on their ability to provide inducements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>25", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : WAYS OF DISCOURAGING POLITICAL APATHY", "question": "Political apathy can be addressed by", "images": [], "options": {"A": "selling of votes to the highest bidders", "B": "criticizing the policies of elected officials", "C": "boycotting election campaigns and rallies", "D": "public enlightenment and campaigns"}, "answer": "D", "explanation": "Political apathy can be addressed by public enlightenment and campaigns. These can educate people about the importance of participating in the political process and the impact of their vote. They can also provide information about the candidates and their policies, helping people to make an informed decision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>26", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "Legislative arm of government can check the executive by", "images": [], "options": {"A": "withholding the salaries of ministers", "B": "delaying the posting of ambassadors", "C": "demanding the review of any act of the executive", "D": "reporting them to the supreme court"}, "answer": "C", "explanation": "The legislative arm of government can check the executive by demanding the review of any act of the executive. This is part of the checks and balances system in a democratic government, where each branch of government has some measure of influence over the other branches and may choose to block procedures of the other branches.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>27", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "The Nigerian federation is divided into how may geopolitical zones?", "images": [], "options": {"A": "774", "B": "36", "C": "6", "D": "4"}, "answer": "C", "explanation": "The Nigerian federation is divided into 6 geopolitical zones. These zones are North Central, North East, North West, South East, South South, and South West.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>28", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "The executive, legislative and judiciary constitute the", "images": [], "options": {"A": "arms of government", "B": "systems of government", "C": "tiers of government", "D": "forms of government"}, "answer": "A", "explanation": "The executive, legislative and judiciary constitute the arms of government. These are the three branches of government in a democratic system, each with separate and independent powers and areas of responsibility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>29", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Civil societies act mainly as a link between", "images": [], "options": {"A": "government and international bodies", "B": "different opposing communities", "C": "individuals of divergent interests", "D": "government and the populace"}, "answer": "D", "explanation": "Civil societies act mainly as a link between government and the populace. They play a crucial role in raising awareness of social issues, advocating for change, and facilitating communication between the public and the government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>30", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "When power is concentrated in one central government, the constitution is said to be", "images": [], "options": {"A": "federal", "B": "unitary", "C": "republican", "D": "semi-federal"}, "answer": "B", "explanation": "When power is concentrated in one central government, the constitution is said to be unitary. In a unitary system, the central government has total power, as opposed to a federal system where power is divided between central and regional governments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>31", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "Legislations on issues affecting policies on money, policing and international relations are within the scope of", "images": [], "options": {"A": "exclusive legislative matter", "B": "concurrent and residual list", "C": "residual legislative matter", "D": "concurrent and exclusive list"}, "answer": "A", "explanation": "Legislations on issues affecting policies on money, policing and international relations are within the scope of exclusive legislative matter. Exclusive legislative matters are those areas of law that only the federal or central government can make laws on. They are usually matters of national or international importance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>32", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : WHY LEADERS FAIL TO PROTECT THE INTERESTS OF THEIR FOLLOWERS", "question": "God-fatherism in a democratic system of government can led to", "images": [], "options": {"A": "neglect of followers", "B": "citizen's participation", "C": "loss of employment", "D": "economic development"}, "answer": "A", "explanation": "God-fatherism in a democratic system of government can lead to neglect of followers. This is because the godfather, who is usually a powerful and influential person, may use his influence to favor his godson or goddaughter, thereby neglecting the needs and interests of the followers or citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>33", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY", "question": "One significance of democracy in Nigeria is that it promotes", "images": [], "options": {"A": "secularism", "B": "sectionalism", "C": "regionalism", "D": "constitutionalism"}, "answer": "D", "explanation": "One significance of democracy in Nigeria is that it promotes constitutionalism. Constitutionalism is the adherence to a system of constitutional government, which is a key feature of democracy. It ensures that government power is limited and that the rights and freedoms of citizens are protected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>34", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "Execution and implementation of government policies are parts of the functions of the", "images": [], "options": {"A": "military", "B": "civil society", "C": "legislature", "D": "public service"}, "answer": "D", "explanation": "Execution and implementation of government policies are parts of the functions of the public service. The public service, also known as the civil service, is responsible for implementing government policies and delivering public services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>35", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS", "question": "One of the political responsibilities of a citizen is", "images": [], "options": {"A": "exercising the right of franchise", "B": "participation in social gatherings", "C": "engaging in cultural debates", "D": "joining town hall meetings"}, "answer": "A", "explanation": "One of the political responsibilities of a citizen is exercising the right of franchise. The right of franchise, also known as the right to vote, is a fundamental political responsibility of every eligible citizen in a democracy. It allows citizens to participate in the electoral process and choose their representatives in government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>36", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "Local government administration promotes", "images": [], "options": {"A": "consensus building in governance", "B": "responsible government", "C": "democracy at the gross roots", "D": "responsive government"}, "answer": "C", "explanation": "Local government administration promotes democracy at the grassroots. This is because local government is the level of government closest to the people and it provides a platform for citizens to participate in governance at the local level, thereby promoting democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>37", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "The traffic sign indicated in Figure 1 means", "images": ["Civic Education/imgs/2023/fone.png"], "options": {"A": "no waiting", "B": "no stopping", "C": "no crossing", "D": "no overtaking"}, "answer": "A", "explanation": "A 'no waiting' or 'no parking' sign lets a driver stop temporarily, maybe to let out a passenger or unload some goods, but you can't linger there.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>38", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Where you will likely not find the sign in Figure 1 in Nigeria is", "images": ["Civic Education/imgs/2023/fone.png"], "options": {"A": "court areas", "B": "military zones", "C": "presidential villa", "D": "shopping malls"}, "answer": "D", "explanation": "This allows customer to pick up and drop off. This is the most appropriate answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>39", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "The major aim of youth empowerment programmes it to", "images": [], "options": {"A": "tackle the problem of insecurity and lawlessnes", "B": "provide vocational skills to the youths", "C": "provide attitudinal reorientation to the youths", "D": "help the youths become good decision makers"}, "answer": "B", "explanation": "The major aim of youth empowerment programs is to provide vocational skills to the youths. This is because by equipping youths with vocational skills, they become self-reliant and can contribute positively to the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>40", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "Human trafficking can be described as", "images": [], "options": {"A": "desperate desire by youths to travel abroad for greener pasture", "B": "exploitation of humans in ways their rights are deprived in the course of movement", "C": "exploration and adventuries in foreign countries", "D": "recruitment of youths as casual workers in distant places"}, "answer": "B", "explanation": "Human trafficking can be described as exploitation of humans in ways their rights are deprived in the course of movement. This is because human trafficking involves the illegal trade of people for exploitation or commercial gain, which is a gross violation of human rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>41", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Traffic regulations are mainly meant for all", "images": [], "options": {"A": "pedestrians", "B": "road users", "C": "truck drivers", "D": "private drivers"}, "answer": "B", "explanation": "Traffic regulations are mainly meant for all road users. This includes pedestrians, cyclists, motorists, and passengers. The purpose of traffic regulations is to ensure safety and smooth movement for all who use the road.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>42", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS", "question": "When opposing communities come together, to discuss a way out of a pending feud, the action is best described as", "images": [], "options": {"A": "co-operation", "B": "dialogue", "C": "arbitration", "D": "peackeeping"}, "answer": "B", "explanation": "When opposing communities come together, to discuss a way out of a pending feud, the action is best described as dialogue. Dialogue involves a discussion between two or more people or groups, especially one directed towards exploration of a particular subject or resolution of a conflict.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>43", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : MEANING OF CONSTITUTED AUTHORITY", "question": "Authority that is recognised by the law of the land is called", "images": [], "options": {"A": "religious authority", "B": "consultative authority", "C": "constituted authority", "D": "charismatic authority"}, "answer": "C", "explanation": "Constituted authority refers to the power or authority that is recognized by the law of the land. It is the power given to individuals or groups by the constitution of a country. This authority is legally recognized and has the power to make, interpret, enforce, or change laws.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>44", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Which of the following values will likely, cause harm to the society?", "images": [], "options": {"A": "Tolerance", "B": "Indiscipline", "C": "Politeness", "D": "Fair play"}, "answer": "B", "explanation": "Indiscipline is likely to cause harm to the society. Indiscipline refers to a lack of control in the behavior of a group of people, often resulting in chaos and disorder. This can lead to a breakdown of law and order in the society, hence causing harm.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2023>45", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS~~NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "Carefully study the following list of civic education terms I and VII below and use them to answer the questions    I. HIV/AIDS  II. Law and order  III. Political apathy  IV. Human trafficking  V. Popular participation  VI. Responsible parenting  VII. Fundamental human rights    The major reasons some countries are termed developing resulted from", "images": [], "options": {"A": "III and VI", "B": "IV and V", "C": "II and VII", "D": "V and VI"}, "answer": "A", "explanation": "The major reasons some countries are termed developing resulted from Political apathy (III) and Responsible parenting (VI). Political apathy refers to the indifference towards political activities, which can hinder the development of a country. Responsible parenting, on the other hand, is crucial for the upbringing of responsible citizens who contribute to the development of the country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>46", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : MEANING OF HIV/AIDS~~NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER~~GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY~~EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING~~GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION~~NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD~~NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "Carefully study the following list of civic education terms I and VII below and use them to answer the questions    I. HIV/AIDS  II. Law and order  III. Political apathy  IV. Human trafficking  V. Popular participation  VI. Responsible parenting  VII. Fundamental human rights    Non-negotiable entitlements of every individual on earth are", "images": [], "options": {"A": "II and V", "B": "II and VIII", "C": "VI and VII", "D": "III and VI"}, "answer": "C", "explanation": "Non-negotiable entitlements of every individual on earth are Fundamental human rights (VII) and Responsible parenting (VI). Fundamental human rights are the basic rights and freedoms to which all individuals are entitled, regardless of nationality, sex, national or ethnic origin, race, religion, language, or other status. Responsible parenting is also a non-negotiable entitlement as it ensures the well-being and development of children.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>47", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : MEANING OF HIV/AIDS~~NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS~~EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "Carefully study the following list of civic education terms I and VII below and use them to answer the questions    I. HIV/AIDS  II. Law and order  III. Political apathy  IV. Human trafficking  V. Popular participation  VI. Responsible parenting  VII. Fundamental human rights    From the list above, the two experiences of individuals that require counselling are", "images": [], "options": {"A": "III and V", "B": "I and VII", "C": "II and III", "D": "I and IV"}, "answer": "D", "explanation": "From the list above, the two experiences of individuals that require counselling are HIV/AIDS (I) and Human trafficking (IV). Individuals affected by HIV/AIDS often require counselling to cope with the physical and emotional challenges associated with the disease. Similarly, victims of human trafficking require counselling to help them recover from the traumatic experience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>48", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : MEANING OF HIV/AIDS~~NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER~~GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY~~GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION", "question": "Carefully study the following list of civic education terms I and VII below and use them to answer the questions    I. HIV/AIDS  II. Law and order  III. Political apathy  IV. Human trafficking  V. Popular participation  VI. Responsible parenting  VII. Fundamental human rights    The major reasons for citizens' reorientation in civic education are", "images": [], "options": {"A": "II and V", "B": "III and V", "C": "VI and VIII", "D": "I and II"}, "answer": "B", "explanation": "The major reasons for citizens' reorientation in civic education are political apathy and popular participation. Political apathy refers to the indifference on the part of any citizen of any country with regard to their attitude towards political activities. Popular participation refers to the involvement of citizens in the decision-making process, especially those decisions that affect their lives. Therefore, reorientation in civic education is needed to address political apathy and encourage popular participation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>49", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "The search of a citizen's residence by the police without a warrant or court order amounts to a breach of his/her right to", "images": [], "options": {"A": "privacy", "B": "freedom of conscience", "C": "freedom of expression", "D": "life"}, "answer": "A", "explanation": "The right to privacy is a fundamental human right. It protects individuals from unwarranted intrusions into their personal life. Therefore, a search of a citizen's residence by the police without a warrant or court order amounts to a breach of his/her right to privacy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2023>50", "subject": "Civic Education", "year": "2023", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "The unpleasant attitudes towards people Living With HIV/AIDS is termed", "images": [], "options": {"A": "playing safe", "B": "civic neglect", "C": "human right abuse", "D": "stigmatization"}, "answer": "D", "explanation": "The unpleasant attitudes towards people Living With HIV/AIDS is termed stigmatization. Stigmatization refers to the situation where people are set apart from others and viewed in a negative light because of perceived differences, often related to health conditions, such as HIV/AIDS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>1", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW", "question": "Democratic societies are run and governed by", "images": [], "options": {"A": "laws", "B": "monarchs", "C": "passion", "D": "charisma"}, "answer": "A", "explanation": "Democratic societies are run and governed by laws. In a democratic society, the rule of law is fundamental, and all individuals, including government officials, are subject to the law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>2", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "To guarantee the rights and freedom of citizens, the powers of the organs of government must be", "images": [], "options": {"A": "rotated", "B": "separated", "C": "fused", "D": "incorporated"}, "answer": "B", "explanation": "To guarantee the rights and freedom of citizens, the powers of the organs of government must be separated. This principle is known as the separation of powers, where the legislative, executive, and judicial branches of government are distinct and independent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>3", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "Which of the following is an example of inalienable right?", "images": [], "options": {"A": "Right to life", "B": "Right to vote", "C": "Right to social security", "D": "Right to adequate wages"}, "answer": "A", "explanation": "Inalienable rights are rights that are considered inherent to all individuals and cannot be taken away or transferred.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>4", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "Citizenship can be acquired through", "images": [], "options": {"A": "nationalization", "B": "registration", "C": "negotiation", "D": "decree"}, "answer": "B", "explanation": "Citizenship can be acquired through registration. Registration is a common method for individuals to acquire citizenship in many countries by fulfilling certain criteria and submitting necessary documentation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>5", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "Which of the following rights cannot be enjoyed by an Italian citizen that is residing a West African country?", "images": [], "options": {"A": "Freedom of expression", "B": "Ownership of properties", "C": "Right to worship", "D": "Right to vote"}, "answer": "D", "explanation": "All the rights listed can generally be enjoyed by citizens regardless of their location except the right to vote.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>6", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "One of the outstanding features of citizenship by birth is that", "images": [], "options": {"A": "it can be withdrawn", "B": "it can never be forfeited", "C": "special requirements are attached", "D": "it can be reverted to alien status"}, "answer": "B", "explanation": "Citizenship by birth is a fundamental right that is typically considered irrevocable. Once a person is granted citizenship by birth, it cannot be forfeited under normal circumstances. Therefore, the correct option is 'it can never be forfeited'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>7", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "In order to reduce over-reliance on foreign grants, civil society organizations need to", "images": [], "options": {"A": "create revenue generation activities", "B": "become more national in their spread and membership", "C": "engage in more pragmatic methods like lobbying", "D": "engage the state for funding"}, "answer": "A", "explanation": "To reduce over-reliance on foreign grants, civil society organizations should create revenue generation activities. By generating their own revenue, they can become more self-sustainable and less dependent on external funding sources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>8", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;~~GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF DEMOCRACY", "question": "The major constraint to national development is", "images": [], "options": {"A": "improper assessment of policies", "B": "overdependence on natural resources", "C": "high level of nepotism", "D": "absence of modern technology"}, "answer": "C", "explanation": "Nepotism, which refers to favoritism shown to family or friends, is a major constraint to national development. When individuals are appointed based on connections rather than merit, it can hinder progress and lead to inefficiencies in governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>9", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "The conduct of an election in a democracy is the responsibility of", "images": [], "options": {"A": "electoral commission", "B": "security agencies.", "C": "election stakeholders", "D": "civil society"}, "answer": "A", "explanation": "The conduct of an election in a democracy is primarily the responsibility of the electoral commission. The electoral commission is tasked with organizing and overseeing the electoral process to ensure fairness, transparency, and credibility in elections.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>10", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "Accepting other people's opinions and preferences, even when they live in a way one does not agree with defines", "images": [], "options": {"A": "honesty", "B": "tolerance", "C": "cooperation", "D": "courage"}, "answer": "B", "explanation": "Accepting other people's opinions and preferences, even when they differ from one's own, is a key aspect of tolerance. Tolerance involves respecting and acknowledging diverse viewpoints and lifestyles, even if one may not personally agree with them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>11", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "Civil society organizations fight poverty by", "images": [], "options": {"A": "checking the emergence of dictatorship", "B": "strengthening good governance", "C": "providing arena for the expression of diverse interest", "D": "supporting the ruling political party"}, "answer": "C", "explanation": "Civil society organizations fight poverty by providing an arena for the expression of diverse interests. This allows them to advocate for policies and programs that address poverty issues and promote social welfare.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>12", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "The constitution is important because it", "images": [], "options": {"A": "allows government institutions to act anyhow", "B": "enables a particular ethnic group to control the government", "C": "is applicable to the president only", "D": "regulates all citizens"}, "answer": "D", "explanation": "The constitution is important because it establishes the fundamental principles, structures, and processes of a government, ensuring the rule of law and protecting the rights of citizens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>13", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "Which of the following does a civil society advocate for?", "images": [], "options": {"A": "Subjective criticism of government policies and programmes", "B": "Emergence of dictatorship and political extremism", "C": "Violent demonstrations to express views or positions", "D": "Objectivity and respect for opposing views"}, "answer": "D", "explanation": "A civil society advocates for objectivity and respect for opposing views. This is essential for promoting dialogue, inclusivity, and democratic values within a society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>14", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "A responsible citizen can show loyalty and devotion to his country by", "images": [], "options": {"A": "involving in jungle justice", "B": "reporting any act of sabotage", "C": "prosecuting criminals", "D": "arresting criminals"}, "answer": "B", "explanation": "A responsible citizen can show loyalty and devotion to his country by reporting any act of sabotage. This action contributes to maintaining law and order, and upholding the values of justice and security within the society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>15", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS", "question": "Violations of traffic codes are often dealt with by", "images": [], "options": {"A": "loss of driving privileges", "B": "criminal court", "C": "payment of damages", "D": "forfeiting a fine"}, "answer": "A", "explanation": "Violations of traffic codes are often dealt with by loss of driving privileges. This serves as a deterrent to ensure compliance with traffic regulations and promotes road safety.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>16", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "Civil society is regarded as an important organ of the society because it", "images": [], "options": {"A": "involves the operation of government", "B": "takes position on important policy questions.", "C": "represents the interests of powerful groups", "D": "improves the generality of citizens' well being"}, "answer": "D", "explanation": "Civil society is regarded as an important organ of the society because it improves the generality of citizens' well-being. Civil society organizations play a crucial role in advocating for the rights and welfare of citizens, promoting social justice, and holding governments accountable for their actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>17", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "Building national values and ethical cultures can be hindered by", "images": [], "options": {"A": "celebrating right people by media or society", "B": "punishing influential individuals for misdeeds", "C": "poor citizenship or followership", "D": "strengthening societal worth or morals"}, "answer": "C", "explanation": "Building national values and ethical cultures can be hindered by poor citizenship or followership. The behavior and actions of citizens play a significant role in shaping the values and ethics of a nation. When citizens exhibit poor citizenship or followership, it can impede the development of positive national values.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>18", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Establishment, maintenance and regulation of slaughterhouses and slabs is the statutory role of", "images": [], "options": {"A": "federal government", "B": "state government", "C": "regional government", "D": "local government"}, "answer": "D", "explanation": "Establishment, maintenance, and regulation of slaughterhouses and slabs is the statutory role of the local government. Local governments are typically responsible for issues related to public health and sanitation within their jurisdictions, which includes overseeing the operation of slaughterhouses and ensuring compliance with regulations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>19", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "Public servants are directly responsible for the poor quality of service delivery due to", "images": [], "options": {"A": "poor working mindsets", "B": "misallocation of resources", "C": "poor condition of service", "D": "overbearing external influence"}, "answer": "A", "explanation": "Public servants are directly responsible for the poor quality of service delivery due to poor working mindsets. The mindset and attitude of public servants towards their work can significantly impact the quality of service delivery. Issues such as lack of motivation, inefficiency, and corruption can stem from poor working mindsets among public servants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>20", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "Which of the following defines a legal member of a state?", "images": [], "options": {"A": "Follower", "B": "Alien", "C": "Citizen", "D": "Leader"}, "answer": "C", "explanation": "A legal member of a state is defined as a Citizen. Citizenship confers certain rights and responsibilities on individuals within a state, including the right to vote, access public services, and participate in the democratic process. Being a citizen signifies legal membership in a particular state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>21", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS", "question": "Constant appreciation of children by parents", "images": [], "options": {"A": "makes children to be arrogant", "B": "promotes withdrawal syndrome in children", "C": "makes children secretive", "D": "builds strong and confident children"}, "answer": "D", "explanation": "Constant appreciation of children by parents builds strong and confident children. When parents consistently appreciate their children, it boosts their self-esteem and confidence, leading to strong and confident individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>22", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : SYMPTOMS OF DRUG ABUSE", "question": "An individual who abuses drugs will experience the following except", "images": [], "options": {"A": "healthy immune system", "B": "withdrawal", "C": "depression", "D": "traces of insanity"}, "answer": "A", "explanation": "An individual who abuses drugs will not have a healthy immune system. Drug abuse weakens the immune system, making the individual more susceptible to illnesses and infections.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>23", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "The right to rule based on the recognition of personal qualities is known as", "images": [], "options": {"A": "traditional authority", "B": "charismatic authority", "C": "legal authority", "D": "rational authority"}, "answer": "B", "explanation": "The right to rule based on the recognition of personal qualities is known as charismatic authority. Charismatic authority is based on the personal qualities and charisma of the leader, rather than traditional, legal, or rational factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>24", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR", "question": "The Universal Declaration of Human Rights (UDHR) was proclaimed by the United Nation's", "images": [], "options": {"A": "Security Council", "B": "General Assembly", "C": "International Court of Justice", "D": "Economic and Social Council"}, "answer": "B", "explanation": "The Universal Declaration of Human Rights (UDHR) was proclaimed by the United Nations General Assembly. The General Assembly is the main deliberative, policymaking, and representative organ of the UN, making it the correct option in this context.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>25", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "Dependency on foreign donors by civil society organizations primarily", "images": [], "options": {"A": "promotes a long term strategy of chasing funds", "B": "distracts the organizations from their missions", "C": "promotes sustainability", "D": "increase scope of activities"}, "answer": "B", "explanation": "Dependency on foreign donors can have various impacts, including financial stability, resource availability, and influence on organizational priorities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>26", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS", "question": "The right to work in any part of the country can be regarded as", "images": [], "options": {"A": "natural rights", "B": "civic rights", "C": "economic rights", "D": "social rights"}, "answer": "C", "explanation": "The right to work in any part of the country is an economic right because it pertains to the ability of individuals to engage in economic activities across different regions within the country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>27", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "Political participation can be limited by", "images": [], "options": {"A": "wealth", "B": "gender", "C": "age", "D": "religion"}, "answer": "C", "explanation": "Political participation can be limited by age as states usually restrict minors from voting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>28", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "One of the roles of the police as an important pillar of democracy is", "images": [], "options": {"A": "subjecting citizens to the wishes of leaders", "B": "guarding and protecting sensitive election materials", "C": "suppressing opposition to the government", "D": "helping the incumbent government to continue in office"}, "answer": "B", "explanation": "One of the roles of the police as an important pillar of democracy is guarding and protecting sensitive election materials to ensure free and fair elections, which is crucial for democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>29", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "Which of the following institutions was set up to address the unfair treatments of citizens by public servants?", "images": [], "options": {"A": "Independent Corrupt Practices Commission", "B": "Economic and Financial Crimes Commission", "C": "Public Complaint Commission/ Ombudsman", "D": "International Labour Organization"}, "answer": "C", "explanation": "The Public Complaint Commission/Ombudsman was set up to address the unfair treatments of citizens by public servants by providing a platform for citizens to lodge complaints against such actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>30", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "Some Civil Society Organizations do not get the needed attention from the government because of", "images": [], "options": {"A": "awareness of their activities", "B": "confrontation in some sensitive issues", "C": "overbearing external influence", "D": "open nature of the organization"}, "answer": "C", "explanation": "Some Civil Society Organizations do not get the needed attention from the government because of overbearing external influence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>31", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR", "question": "The reason the seven core freedoms of the Universal Declaration of Human Rights (UDHR) are so important is because", "images": [], "options": {"A": "they concern individuals directly and influence their peaceful existence as human beings", "B": "the violation of one right often leads to violation of another right", "C": "they embody key values and rights of human beings", "D": "they enable individuals to speak up and challenge poor treatment from a public authority"}, "answer": "C", "explanation": "The correct answer is they embody key values and rights of human beings. The seven core freedoms of the Universal Declaration of Human Rights (UDHR) are important because they embody fundamental values and rights that are essential for the dignity and well-being of all individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>32", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR", "question": "The role of individuals in the Universal Declaration of Human Rights (UDHR) includes", "images": [], "options": {"A": "incorporation of UDHR into the national constitution", "B": "enacting laws that promote the objectives of UDHR", "C": "tolerance of other people's opinions, beliefs etc", "D": "carrying out advocacy programmes through the mass media"}, "answer": "C", "explanation": "The correct answer is  tolerance of other people's opinions, beliefs etc. The role of individuals in the Universal Declaration of Human Rights (UDHR) includes promoting tolerance towards diverse opinions, beliefs, and cultures, which is a key aspect of upholding human rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>33", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "Bureaucracy in public service simply means", "images": [], "options": {"A": "favouritism", "B": "nepotism", "C": "red-tapism", "D": "patriotism"}, "answer": "C", "explanation": "Bureaucracy refers to the system of government in which most of the important decisions are made by state officials rather than by elected representatives.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>34", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "Constant changes in public service has led", "images": [], "options": {"A": "overdependence on crude oil", "B": "abandonment of many projects", "C": "large scale unemployment", "D": "poor standard of living"}, "answer": "B", "explanation": "Constant changes can have various effects and that includes abandonment of many projects.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>35", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS", "question": "The rule of law requires that", "images": [], "options": {"A": "government should be subject to the law", "B": "the law should be subject to the government", "C": "law should be made in respect of an individual", "D": "the law should be subject to traditional rulers"}, "answer": "A", "explanation": "The correct answer is  government should be subject to the law. The rule of law requires that the government and its officials are bound by and accountable under the law. This ensures that the exercise of governmental power is constrained by legal principles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>36", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Youth empowerment programmes are aimed at giving the youth the opportunity to", "images": [], "options": {"A": "become exceedingly wealthy", "B": "be self sufficient", "C": "be physically strong", "D": "have all their wants met"}, "answer": "B", "explanation": "Youth empowerment programmes are aimed at making the youth self-sufficient by providing them with skills, resources, and opportunities to succeed on their own. This option aligns with the primary goal of such programs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>37", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "To end the compulsive behaviour of drug addiction, drug addicts", "images": [], "options": {"A": "can quit by themselves", "B": "need support and treatment", "C": "can relocate to a new environment", "D": "should take a lesser dosage of drugs"}, "answer": "B", "explanation": "To end the compulsive behavior of drug addiction, drug addicts need support and treatment. Addiction is a complex condition that requires professional help and support to overcome.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>38", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "One can support a person with substance abuse problem by", "images": [], "options": {"A": "counselling and rehabilitation", "B": "hiding or throwing out drugs", "C": "taking over the drug abusers' responsibilities", "D": "covering up or making excuses for the drug abuser"}, "answer": "A", "explanation": "One can support a person with substance abuse problems by providing counseling and rehabilitation. This approach helps the individual address the root causes of their addiction and learn coping mechanisms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>39", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING", "question": "Trafficked persons are mainly lured with a promise of", "images": [], "options": {"A": "schooling", "B": "love", "C": "employment", "D": "protection"}, "answer": "C", "explanation": "Trafficked persons are mainly lured with false promises of a better life, which may include employment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>40", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "A major source of funds to local government authorities is", "images": [], "options": {"A": "donations", "B": "import duties", "C": "taxes on goods", "D": "utility bills"}, "answer": "C", "explanation": "A major source of funds to local government authorities is taxes on goods. Taxes play a crucial role in generating revenue for local governments to fund public services and infrastructure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>41", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTERPERSONAL RELATIONSHIPS", "question": "Which of the following is the key factor in fostering cooperation among members of the society?", "images": [], "options": {"A": "Discipline", "B": "Empathy", "C": "Maturity", "D": "Understanding"}, "answer": "D", "explanation": "The key factor in fostering cooperation among members of the society is 'Understanding'. When individuals have a deep understanding of each other's perspectives, beliefs, and values, they are more likely to cooperate and work together effectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>42", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "Which of the immune system cells does HIV target or attack?", "images": [], "options": {"A": "B-Cells", "B": "T-Cells", "C": "NK Cells", "D": "Red blood cells"}, "answer": "B", "explanation": "HIV primarily targets or attacks T-Cells in the immune system. T-Cells are a type of white blood cell that plays a crucial role in the body's immune response. HIV specifically infects and destroys these cells, weakening the immune system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2024>43", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "Values are what we", "images": [], "options": {"A": "can see, feel and touch", "B": "believe in and imbibe", "C": "avoid like a plague", "D": "know as agents of civic education"}, "answer": "B", "explanation": "Values are what we 'believe in and imbibe'. Values are deeply held beliefs and principles that guide our behavior and decision-making. They are not physical entities that can be seen, felt, or touched.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>44", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "One of the citizenship values inculcated by parents into their children includes", "images": [], "options": {"A": "tax evasion", "B": "arrest of criminals", "C": "fairness to all", "D": "no action"}, "answer": "C", "explanation": "\"Fairness to all\" refers to the principle of treating everyone equally and justly, without favoritism or discrimination.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>45", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS", "question": "The boldness to be honest in persecution is a manifestation of", "images": [], "options": {"A": "humility", "B": "obedience", "C": "strength", "D": "courage"}, "answer": "D", "explanation": "The boldness to be honest in persecution is a manifestation of 'courage'. Courage is the ability to confront fear, pain, danger, uncertainty, or intimidation with confidence and bravery. It involves standing up for what is right even in challenging situations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>46", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS", "question": "Civic education is also called", "images": [], "options": {"A": "Civic socialism", "B": "Citizenship education", "C": "Citizenship socialism", "D": "Cultural education"}, "answer": "B", "explanation": "Civic education is also called Citizenship education. It is a type of education that aims to prepare individuals to be responsible and active citizens in their society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>47", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM", "question": "Which of the following is not an agent of Civic education?", "images": [], "options": {"A": "Familv", "B": "Print and electronic media", "C": "Pressure group", "D": "Ministry of Labour and Productivity"}, "answer": "D", "explanation": "The Ministry of Labour and Productivity is not an agent of Civic education. The other options like Family, Print and electronic media, and Pressure groups play a role in promoting civic education.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>48", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : ROLES OF INDIVIDUALS, GROUPS AND GOVERNMENT IN UDHR", "question": "The fundamental agent in children guidance, training and education is", "images": [], "options": {"A": "peers", "B": "parents", "C": "society", "D": "school"}, "answer": "B", "explanation": "The fundamental agent in children guidance, training, and education is parents. Parents have a significant influence on the upbringing and education of children.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>49", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP", "question": "The most common method of acquiring the citizenship of a country is by", "images": [], "options": {"A": "registration", "B": "birth", "C": "marriage", "D": "naturalization"}, "answer": "B", "explanation": "The most common method of acquiring the citizenship of a country is by birth. Citizenship by birth is automatic for individuals born in a particular country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2024>50", "subject": "Civic Education", "year": "2024", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY", "question": "The qualities of being fair and reasonable in the way that people are treated is known as", "images": [], "options": {"A": "integrity", "B": "love", "C": "justice", "D": "honesty"}, "answer": "C", "explanation": "The qualities of being fair and reasonable in the way that people are treated is known as justice. Justice is a fundamental principle in civic education and society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>1", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION", "question": "The training of oneself in subjection to self-rules and self-control is achieved as a result of", "images": [], "options": {"A": "Integrity", "B": "Discipline", "C": "Contentment", "D": "Commitment"}, "answer": "B", "explanation": "Discipline refers to the ability to train oneself to follow rules and control impulses. It involves self-regulation and adherence to set standards.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>2", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "A situation where people are encouraged to define their own values and respect other people's values is known as value", "images": [], "options": {"A": "Mobilization", "B": "Clarification", "C": "Classification", "D": "Orientation"}, "answer": "B", "explanation": "Value clarification is the process through which individuals identify, examine, and develop their own values and learn to respect others'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>3", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "A Gambian who wishes to become a Nigerian citizen by naturalisation must be", "images": [], "options": {"A": "18 years old and above and have spent at least 15 years in Nigeria", "B": "18 years old and above and have spent at least 25 years in Nigeria", "C": "21 years and above and have spent at least 10 years in Nigeria", "D": "21 years old and above and have spent at least 15 years in Nigeria"}, "answer": "D", "explanation": "According to the Nigerian Constitution, a person seeking citizenship by naturalisation must be at least 21 years old and must have resided in Nigeria for 15 years continuously.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>4", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTERPERSONAL RELATIONSHIPS", "question": "The major reason for studying Civic Education is that it", "images": [], "options": {"A": "Encourages the struggle for political power in the state", "B": "Inculcates the spirit of nationalism and patriotism in the citizens of a state", "C": "Helps students and citizens to study and understand their physical environment", "D": "Enables students and citizens to identify problems in their society without offering functional solutions"}, "answer": "B", "explanation": "Civic Education develops informed, responsible, and patriotic citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>5", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS", "question": "Which of the following is not a national symbol?", "images": [], "options": {"A": "National flag", "B": "Voter's card", "C": "National currency", "D": "Coat of arms"}, "answer": "B", "explanation": "National symbols are official representations of a country's identity and sovereignty, such as the flag, currency, and coat of arms. A voter's card is an electoral document, not a symbol.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>6", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY", "question": "The newspapers established by the nationalists helped in", "images": [], "options": {"A": "Revealing the weaknesses of the colonial powers", "B": "Fighting racial discrimination in the country", "C": "Protecting the rights of traditional rulers", "D": "Promoting the image of the nationalists"}, "answer": "A", "explanation": "Nationalist newspapers, like West African Pilot, exposed the injustices and shortcomings of colonial rule, helping to build consciousness among Nigerians.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>7", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM", "question": "The main significance of nationalism to the development of a country is to", "images": [], "options": {"A": "Foster a sense of selflessness towards the nation", "B": "Create a sense of allegiance to the nation", "C": "Promote the awareness of fundamental human rights", "D": "Create a sense of political awareness"}, "answer": "B", "explanation": "Nationalism promotes loyalty and devotion to one's country, encouraging citizens to act in the national interest, which strengthens unity and development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>8", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR", "question": "How many articles are contained in the Universal Declaration of Human Rights (UDHR) of 1948?", "images": [], "options": {"A": "30", "B": "33", "C": "48", "D": "50"}, "answer": "A", "explanation": "The Universal Declaration of Human Rights (UDHR), adopted in 1948 by the United Nations, contains 30 articles, each outlining fundamental human rights and freedoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>9", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "A person who is found guilty of an offence and sentenced to prison by a competent court of law would forfeit his/her", "images": [], "options": {"A": "Freedom of expression and right to fair hearing", "B": "Right to life and right to personal liberty", "C": "Right to movement and association", "D": "Right to fair hearing and right to movement"}, "answer": "C", "explanation": "A convicted person loses freedom of movement and association while in prison but retains rights like fair hearing unless legally removed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>10", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR", "question": "A person who writes false statements on social media that harms another person's reputation will be found guilty of", "images": [], "options": {"A": "Blackmail", "B": "Sedition", "C": "Slander", "D": "Libel"}, "answer": "D", "explanation": "Libel is a written or published false statement damaging to a person's reputation. Slander is spoken. Blackmail involves threats, and sedition is inciting resistance against authority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>11", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY", "question": "The notion that the law should apply to everyone irrespective of their status implies", "images": [], "options": {"A": "Supremacy of the law", "B": "Fair hearing", "C": "Equality before the law", "D": "Right to appeal"}, "answer": "C", "explanation": "This principle ensures that every individual, regardless of class, rank, or status, is subject to the same laws and legal processes. It reinforces fairness and justice in a democratic society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>12", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY", "question": "Constituted authority is necessary in a society because it", "images": [], "options": {"A": "Promotes international relations", "B": "Ensures security of life and property", "C": "Serves as an agent of socialization", "D": "Provides scholarship for higher education"}, "answer": "B", "explanation": "Constituted authorities like the police and government ensure peace, law, and order. Their main purpose is to protect citizens and property, creating a safe environment for development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>13", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Responsible parenthood is important to national development because it", "images": [], "options": {"A": "Promotes political participation", "B": "Ensures upbringing of strict leaders", "C": "Emphasizes equality in the society", "D": "Helps in reduction of social vices"}, "answer": "D", "explanation": "Responsible parents instill moral values and discipline, thereby reducing criminality, drug abuse, and other vices among children, which contributes to national progress.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>14", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "Traffic regulations mean", "images": [], "options": {"A": "Rules of traffic jam", "B": "Rules guiding pedestrians", "C": "Codes and ethics of traffic", "D": "Driving on express roads"}, "answer": "C", "explanation": "Traffic regulations are established rules to guide both motorists and pedestrians for safe and orderly use of roads.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>15", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "Traffic wardens assist in", "images": [], "options": {"A": "Presentation of traffic legislation", "B": "Mounting of traffic signs", "C": "Control of traffic flow", "D": "Formulation of rules and regulations"}, "answer": "C", "explanation": "Traffic wardens are responsible for directing vehicles and pedestrians to avoid congestion and ensure road safety.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>16", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS", "question": "Conflict resolution mechanisms in inter-communal relationships include", "images": [], "options": {"A": "Reorientation", "B": "Compromise", "C": "Commendation", "D": "Diligence"}, "answer": "B", "explanation": "Compromise involves mutual concessions, which is a peaceful approach to resolving disputes between communities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>17", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS", "question": "The phrase \"no man is an island\" means that", "images": [], "options": {"A": "Mankind needs plants and animals to survive", "B": "Citizens cannot operate without help of the government", "C": "Individuals need the cooperation of others to progress", "D": "Humans are made to marry and have life partners"}, "answer": "C", "explanation": "The phrase emphasizes interdependence and the need for teamwork in human society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>18", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : DRUGS THAT CAN BE ABUSED", "question": "Which of the following cannot be identified as drug abuse?", "images": [], "options": {"A": "Consumption of the right dosage of prescribed drugs", "B": "Trafficking of hard substances", "C": "Consumption of high dosage of legal drugs", "D": "Taking drugs without authorization"}, "answer": "A", "explanation": "When drugs are taken as prescribed, it is not abuse. Drug abuse involves misuse or illegal use of substances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>19", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "An aspect of human trafficking involves", "images": [], "options": {"A": "Liberation of victims", "B": "Counseling of victims", "C": "Empowerment of victims", "D": "Recruitment of victims"}, "answer": "D", "explanation": "Trafficking starts with the recruitment and deception of victims for exploitation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>20", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "Women are trafficked mainly for", "images": [], "options": {"A": "Entrepreneurship", "B": "Sexual servitude", "C": "Debt bondage", "D": "Empowerment"}, "answer": "B", "explanation": "Many women are trafficked into prostitution, a major form of sexual exploitation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>21", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Human Immunodeficiency Virus (HIV) mainly leads to", "images": [], "options": {"A": "Immune repletion", "B": "Immune deficiency", "C": "Vines deficiency", "D": "Virus repletion"}, "answer": "B", "explanation": "HIV weakens the immune system, making the body vulnerable to infections and diseases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>22", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : MEANING OF DRUG ABUSE", "question": "The most common way for babies to contract Human Immunodeficiency Virus (HIV) is through", "images": [], "options": {"A": "Blood transfusion", "B": "Sharp object sharing", "C": "Breastfeeding", "D": "Sexual transmission"}, "answer": "C", "explanation": "An HIV-positive mother can transmit the virus to her baby through breast milk if preventive measures are not taken.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>23", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "Youth empowerment can be enhanced through", "images": [], "options": {"A": "Imposition of taxes", "B": "Political lobbying", "C": "Granting of bursaries", "D": "Provision of startup capital"}, "answer": "D", "explanation": "Startup funds help youth initiate businesses, reduce unemployment, and foster independence.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>24", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "One of the vital skills needed for youth empowerment is", "images": [], "options": {"A": "Transversal skills", "B": "Cross-curricular skills", "C": "Manipulative skills", "D": "Non-cognitive skills"}, "answer": "A", "explanation": "Transversal skills like communication, critical thinking, and adaptability are essential for success in various life contexts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>25", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Which of the following is not a youth empowerment skill?", "images": [], "options": {"A": "Leadership skills", "B": "Communication skills", "C": "Self-reliance skills", "D": "Investigation skills"}, "answer": "D", "explanation": "Investigation is a research or law enforcement skill, not typically classified as a core empowerment skill.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>26", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "The power to impeach the president of a country resides in the", "images": [], "options": {"A": "Executive", "B": "Judiciary", "C": "Legislature", "D": "Supreme Court"}, "answer": "C", "explanation": "The legislature has constitutional power to impeach the president after due process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>27", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER", "question": "Laws made by both federal and state governments are contained in the", "images": [], "options": {"A": "Residual list", "B": "Exclusive list", "C": "Concurrent list", "D": "Joint list"}, "answer": "C", "explanation": "The concurrent list allows both levels of government to legislate on shared matters like education and health.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>28", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "Which of the following government functions is reserved to the exclusive list?", "images": [], "options": {"A": "Provision of education", "B": "Defence of the nation", "C": "Provision of good roads", "D": "Establishment of industries"}, "answer": "B", "explanation": "National defence is the sole responsibility of the federal government and is on the exclusive list.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>29", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "What arm of government do ministers, commissioners, and supervisory councillors belong to?", "images": [], "options": {"A": "Executive", "B": "Legislature", "C": "Judiciary", "D": "Civil service"}, "answer": "A", "explanation": "These are political appointees who implement government policies - a key function of the executive arm.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>30", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "A local government administration supports", "images": [], "options": {"A": "Unitary government", "B": "Consensus politics", "C": "Grassroot government", "D": "Foreign culture"}, "answer": "C", "explanation": "Local governments bring governance closer to the people, especially at the community level.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>31", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "The adoption of a federal system of government is necessitated by", "images": [], "options": {"A": "Fear of ethnic domination", "B": "Inclusion of a secretive clause in the constitution", "C": "Availability of abundant natural resources", "D": "Adoption of a written constitution"}, "answer": "A", "explanation": "Nigeria and other multi-ethnic nations adopt federalism to ensure that no ethnic group dominates others and that all regions have autonomy and representation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>32", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT", "question": "One feature of representative government is", "images": [], "options": {"A": "Minority rule", "B": "Inter-regional cooperation", "C": "Centralization of power", "D": "Periodic election"}, "answer": "D", "explanation": "In representative democracy, citizens elect leaders at regular intervals to make decisions and represent their interests in governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>33", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Direct democracy implies that the governance of a country involves", "images": [], "options": {"A": "Only male citizens", "B": "Only adult male citizens", "C": "Citizens' representatives", "D": "All the citizens"}, "answer": "D", "explanation": "In direct democracy, all eligible citizens participate directly in decision-making without intermediaries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>34", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "Individual freedom in a democratic country can be enhanced by", "images": [], "options": {"A": "One-party system", "B": "Multi-party system", "C": "Autocratic system", "D": "Communal system"}, "answer": "B", "explanation": "A multi-party system allows for competition, diverse representation, and more choices for citizens, which strengthens democracy and individual freedom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>35", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER", "question": "Absence of one of the following pairs will spell doom for the society.", "images": [], "options": {"A": "I and III", "B": "IV and V", "C": "III and VI", "D": "II and VII"}, "answer": "D", "explanation": "Without law and order and the protection of fundamental human rights, society would collapse into chaos and tyranny.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>36", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS", "question": "The entitlements of every child in the society are", "images": [], "options": {"A": "II and V", "B": "V and VII", "C": "VI and VII", "D": "II and VI"}, "answer": "C", "explanation": "Children are entitled to proper upbringing (through responsible parenting) and the enjoyment of their rights under the law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>37", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION", "question": "Trade unions, market women associations, and student unions are examples of", "images": [], "options": {"A": "Professional associations", "B": "Pressure groups", "C": "Civil societies", "D": "Political parties"}, "answer": "C", "explanation": "Civil societies are non-governmental groups that advocate for public interests and democratic ideals, including trade unions and student groups.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>38", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER", "question": "Inept and irresponsible governance can best be checked by", "images": [], "options": {"A": "Criticism of government officials", "B": "Attacks on government officials", "C": "Revolt against such governments", "D": "Recourse to constitutional means"}, "answer": "D", "explanation": "Citizens should use legal methods like elections, petitions, and judicial redress to address bad governance", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>39", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "In order to avoid undue interference in the process of governance, there should be", "images": [], "options": {"A": "More roles for traditional rulers", "B": "Clear-cut separation of governmental powers", "C": "Proper fusion of government functions", "D": "Checks and balances"}, "answer": "B", "explanation": "Separating the powers of the executive, legislature, and judiciary ensures that no arm of government interferes unduly in the duties of another", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>40", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS", "question": "Which of the following is the implication of immunity clause?", "images": [], "options": {"A": "Some public officers cannot be sued", "B": "The president can grant pardon to any prisoner/criminal", "C": "Public officers are not accountable to the electorate", "D": "There is absence of arbitrary rule"}, "answer": "A", "explanation": "The immunity clause protects certain public officials (e.g. president, governors) from legal prosecution while in office, to allow them perform their duties without distraction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>41", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Neutrality of civil servants implies that they should", "images": [], "options": {"A": "Be appointed by a neutral body", "B": "Be recruited on the basis of federal character", "C": "Have security of tenure", "D": "Not be affiliated to any political party"}, "answer": "D", "explanation": "Civil servants must remain politically neutral to serve all governments faithfully, regardless of party in power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>42", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY", "question": "The following are forms of political apathy except", "images": [], "options": {"A": "Refusal to register for voting", "B": "Rigging of elections", "C": "Lack of interest", "D": "Refusal to give information"}, "answer": "B", "explanation": "Rigging is electoral malpractice, not political apathy. Political apathy refers to indifference or non-participation in politics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>43", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "Use the diagram  to answer the questions below.       What does letter X in the diagram stand for?", "images": ["Civic Education/imgs/2025/P4JXPF.jpg"], "options": {"A": "Separation of powers", "B": "Checks and balances", "C": "Democratic division", "D": "Rule of law"}, "answer": "A", "explanation": "The diagram illustrated the three arms of government. \"X\" represents the principle that each arm functions independently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>44", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "Use the diagram  to answer the questions below.          The letter X as illustrated in the diagram is an integral feature of", "images": ["Civic Education/imgs/2025/P4JXPF.jpg"], "options": {"A": "Limited government", "B": "Absolute monarchy", "C": "Constitutional democracy", "D": "Aristocratic government"}, "answer": "C", "explanation": "Separation of powers is essential in a constitutional democracy to prevent tyranny and promote accountability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>45", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "CIVILSOCIETY ORGANISATIONS", "question": "Inadequate funding may force Civil Society Organizations (CSOs) to", "images": [], "options": {"A": "Lobby for funds from the government", "B": "Contest for political power", "C": "Scale back activities", "D": "Stimulate debate and discussion"}, "answer": "C", "explanation": "Without adequate funding, CSOs may reduce their operations or shut down, limiting their impact on society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>46", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "CIVILSOCIETY ORGANISATIONS", "question": "Civil Society Organizations (CSOs) assist government in alleviating poverty by", "images": [], "options": {"A": "Influencing government decisions", "B": "Promoting youth empowerment", "C": "Criticizing malpractice", "D": "Exerting influence on legislation"}, "answer": "B", "explanation": "Many CSOs implement skills acquisition and empowerment programmes targeted at youths and vulnerable populations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>47", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "CIVILSOCIETY ORGANISATIONS", "question": "Which of the following is a major source of funding for civil societies?", "images": [], "options": {"A": "Government allocation", "B": "Membership dues", "C": "Foreign donations", "D": "Taxation and borrowing"}, "answer": "C", "explanation": "CSOs often rely on international funding from donor agencies to run projects and advocacy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Civic Education>2025>48", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "CIVILSOCIETY ORGANISATIONS", "question": "Civil Society Organizations (CSOs) are not characterized by", "images": [], "options": {"A": "Establishing new political parties", "B": "Advocating for benefits of democracy", "C": "Checkmating the excesses of government", "D": "Acting as training ground for future leaders"}, "answer": "A", "explanation": "CSOs are non-partisan. They advocate for rights and accountability but do not contest elections or form political parties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>49", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "An established way public servants protest to protect their interests is by", "images": [], "options": {"A": "Police action", "B": "Hunger strike", "C": "Industrial strike", "D": "Mass resignation"}, "answer": "C", "explanation": "When negotiation fails, civil/public servants may resort to strike action as a legal method to demand better working conditions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Civic Education>2025>50", "subject": "Civic Education", "year": "2025", "type": "Objective", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Anonymity of civil servants implies that civil servants are", "images": [], "options": {"A": "Not expected to take credit or blame in their duty", "B": "Expected to abstain from voting during elections", "C": "Expected to be fair and impartial in judgment", "D": "Not expected to be politically known in the society"}, "answer": "A", "explanation": "Anonymity means civil servants work behind the scenes. Ministers and politicians take responsibility for government policies, not the civil servants who implement them.", "marks": "1", "difficulty": "2"}];